 15→ * ValueTag — Type tag for Lisp values.
 16→ */
 17→enum ValueTag : char {
 18→    NIL,
 19→    INT,
 20→    STRING,         // String value
 21→    SYMBOL,
 22→    CONS,
 23→    CLOSURE,
