 28→    DOUBLE,         // Floating-point number
 29→    HASHMAP,        // Hash map (mutable dictionary)
 30→    FFI_HANDLE,     // FFI library handle (dlopen result)
 31→    ARRAY,          // Mutable array (dynamic array)
