 33→    INSTANCE,       // User-defined type instance
 34→    METHOD_TABLE,   // Dispatch table for multiple dispatch
 35→    MODULE,         // First-class module reference
 36→    ITERATOR,       // Lazy iterator (backed by closure thunk)
