231→ */
232→struct Closure {
233→    uint      refcount;       // Number of Value* sharing this Closure (RC lifecycle)
234→    main::ScopeRegion* env_scope; // Standalone scope holding env copy (null if root-scope closure)
235→    SymbolId  param;          // Parameter name (first/only param, or unused if param_count==0)
236→    SymbolId* params;         // All fixed params (including first), malloc'd
237→    usz       param_count;    // Number of fixed params
238→    bool      has_rest;       // True if variadic (.. rest)
239→    SymbolId  rest_param;     // Rest parameter name (if has_rest)
240→    Expr*     body;           // Body expression
241→    Env*      env;            // Captured environment
242→    bool      has_param;      // false for zero-arg lambdas: (lambda () body)
