300→/**

  1→/**
  2→ * =============================================================================
  3→ * SCOPE REGION — Lightweight bump-allocating scopes with reference counting
  4→ * =============================================================================
  5→ *
  6→ * Replaces the heavyweight Region system for Value/Env allocation with
  7→ * fine-grained scopes at let/loop/lambda boundaries.
  8→ *
  9→ * Key properties:
 10→ * - Bump allocation: ~3 instructions per alloc (load, add, compare)
 11→ * - Reference counting: scopes freed deterministically at known program points
 12→ * - No cycles: closures form a lexical tree (child→parent, never reverse)
 13→ * - Freelist recycling: ScopeRegion structs reused across scope lifetimes
 14→ * - Destructor list: heap-backed values (strings, arrays, etc.) cleaned up on scope death
 15→ *
 16→ * Memory layout:
 17→ *   ScopeRegion → ScopeChunk (linked list of bump chunks)
 18→ *                 ScopeDtor  (linked list of destructors, bump-allocated in chunks)
 19→ */
 20→module main;
 21→
 22→import std::io;
 23→
 24→// =============================================================================
 25→// Types
 26→// =============================================================================
 27→
 28→alias ScopeDestructorFn = fn void(void* ptr);
 29→
 30→// =============================================================================
 31→// Structs
 32→// =============================================================================
 33→
 34→/**
 35→ * ScopeChunk — A contiguous block of memory for bump allocation.
 36→ * Chunks form a singly-linked list (newest first). Data follows inline
 37→ * after the struct fields.
 38→ */
 39→struct ScopeChunk {
 40→    ScopeChunk* next;       // Previous chunk (linked list, newest→oldest)
 41→    usz         capacity;   // Usable bytes in this chunk (after header)
 42→}
 43→
 44→/**
 45→ * ScopeDtor — Destructor entry for heap-backed values.
 46→ * Allocated within the scope's own chunks (freed automatically).
 47→ */
 48→struct ScopeDtor {
 49→    ScopeDtor*       next;  // Linked list (LIFO — last registered runs first)
 50→    void*            ptr;   // Object to destroy
 51→    ScopeDestructorFn func; // Destructor function
 52→}
 53→
 54→/**
 55→ * ScopeRegion — A lightweight, bump-allocating memory scope.
 56→ *
 57→ * Typical size: ~80 bytes (vs hundreds for the old Region).
 58→ * Fast path allocation: load bump, add size, compare limit.
 59→ */
 60→struct ScopeRegion {
 61→    // Identity & lifetime
 62→    uint         generation;    // Incremented on recycle (for handle validation)
 63→    uint         refcount;      // +1 per external reference (owner + captures)
 64→
 65→    // Hierarchy
 66→    ScopeRegion* parent;        // Lexical parent scope (retained via RC)
 67→
 68→    // Bump allocator
 69→    char*        bump;          // Current allocation pointer
 70→    char*        limit;         // End of current chunk's data area
 71→    ScopeChunk*  chunks;        // Linked list of chunks (head = current)
 72→
 73→    // Cleanup
 74→    ScopeDtor*   dtors;         // Destructor list (LIFO)
 75→    usz          alloc_bytes;   // Total bytes allocated (for split decisions)
 76→    usz          alloc_count;   // Object count (for stats)
 77→
 78→    // Recycling
 79→    ScopeRegion* pool_next;     // Freelist link (only used when in freelist)
 80→}
 81→
 82→// =============================================================================
 83→// Constants
 84→// =============================================================================
 85→
 86→const usz SCOPE_CHUNK_INITIAL   = 512;      // First chunk size (bytes)
 87→const usz SCOPE_CHUNK_MAX       = 65536;    // Maximum chunk size (64KB)
 88→
 89→// =============================================================================
 90→// Global freelist
 91→// =============================================================================
 92→
 93→ScopeRegion* g_scope_freelist = null;
 94→usz g_scope_freelist_count = 0;
 95→const usz SCOPE_FREELIST_MAX = 64;  // Don't hoard too many recycled scopes
 96→
 97→// =============================================================================
 98→// Chunk allocation
 99→// =============================================================================
100→
101→/**
102→ * Allocate a new chunk with at least `min_bytes` of usable data space.
103→ * The chunk struct header is placed at the start; data follows inline.
104→ */
105→fn ScopeChunk* scope_chunk_alloc(usz min_bytes) {
106→    // Double from initial, capped at max
107→    usz capacity = SCOPE_CHUNK_INITIAL;
108→    while (capacity < min_bytes) {
109→        capacity *= 2;
110→        if (capacity > SCOPE_CHUNK_MAX) {
111→            capacity = min_bytes;  // Oversized allocation — exact fit
112→            break;
113→        }
114→    }
115→    usz total = ScopeChunk.sizeof + capacity;
116→    ScopeChunk* chunk = (ScopeChunk*)mem::malloc(total);
117→    chunk.next = null;
118→    chunk.capacity = capacity;
119→    return chunk;
120→}
121→
122→/**
123→ * Get the data start pointer for a chunk (immediately after the header).
124→ */
125→fn char* scope_chunk_data(ScopeChunk* chunk) @inline {
126→    return (char*)chunk + ScopeChunk.sizeof;
127→}
128→
129→// =============================================================================
130→// ScopeRegion lifecycle
131→// =============================================================================
132→
133→/**
134→ * Create a new ScopeRegion, optionally as a child of `parent`.
135→ * If parent is non-null, it is retained (RC incremented).
136→ * Returns a scope with refcount=1 (the caller owns it).
137→ */
138→fn ScopeRegion* scope_create(ScopeRegion* parent = null) {
139→    ScopeRegion* scope;
140→
141→    // Try freelist first
142→    if (g_scope_freelist != null) {
143→        scope = g_scope_freelist;
144→        g_scope_freelist = scope.pool_next;
145→        g_scope_freelist_count--;
146→    } else {
147→        scope = (ScopeRegion*)mem::malloc(ScopeRegion.sizeof);
148→        scope.generation = 0;
149→    }
150→
151→    // Allocate initial chunk
152→    ScopeChunk* chunk = scope_chunk_alloc(SCOPE_CHUNK_INITIAL);
153→    chunk.next = null;
154→
155→    // Initialize scope
156→    scope.refcount = 1;
157→    scope.parent = parent;
158→    scope.chunks = chunk;
159→    scope.bump = scope_chunk_data(chunk);
160→    scope.limit = scope.bump + chunk.capacity;
161→    scope.dtors = null;
162→    scope.alloc_bytes = 0;
163→    scope.alloc_count = 0;
164→    scope.pool_next = null;
165→
166→    // Retain parent
167→    if (parent != null) {
168→        scope_retain(parent);
169→    }
170→
171→    return scope;
172→}
173→
174→/**
175→ * Increment the reference count of a scope.
176→ */
177→fn void scope_retain(ScopeRegion* scope) @inline {
178→    if (scope != null) scope.refcount++;
179→}
180→
181→/**
182→ * Decrement the reference count. Destroys the scope when RC hits 0.
183→ */
184→fn void scope_release(ScopeRegion* scope) @inline {
185→    if (scope == null) return;
186→    if (--scope.refcount == 0) {
187→        scope_destroy(scope);
188→    }
189→}
190→
191→/**
192→ * Run all registered destructors in reverse order (LIFO).
193→ * Does NOT free chunks or the scope itself — use for scope reuse.
194→ */
195→fn void scope_run_dtors(ScopeRegion* scope) {
196→    ScopeDtor* d = scope.dtors;
197→    while (d != null) {
198→        d.func(d.ptr);
199→        d = d.next;
200→    }
201→}
202→
203→/**
204→ * Destroy a scope: run destructors, release parent, free chunks, recycle struct.
205→ * Called when refcount reaches 0. MUST NOT be called directly — use scope_release.
206→ */
207→fn void scope_destroy(ScopeRegion* scope) {
208→    // 1. Run destructors (reverse order — LIFO)
209→    scope_run_dtors(scope);
210→
211→    // 2. Release parent scope (may cascade)
212→    if (scope.parent != null) {
213→        scope_release(scope.parent);
214→        scope.parent = null;
215→    }
216→
217→    // 3. Free all chunks
218→    ScopeChunk* c = scope.chunks;
219→    while (c != null) {
220→        ScopeChunk* next = c.next;
221→        mem::free(c);
222→        c = next;
223→    }
224→    scope.chunks = null;
225→    scope.bump = null;
226→    scope.limit = null;
227→    scope.dtors = null;
228→
229→    // 4. Recycle ScopeRegion struct (increment generation, add to freelist)
230→    scope.generation++;
231→    if (g_scope_freelist_count < SCOPE_FREELIST_MAX) {
232→        scope.pool_next = g_scope_freelist;
233→        g_scope_freelist = scope;
234→        g_scope_freelist_count++;
235→    } else {
236→        mem::free(scope);
237→    }
238→}
239→
240→// =============================================================================
241→// Bump allocator
242→// =============================================================================
243→
244→/**
245→ * Slow path: allocate a new chunk when the current one is full.
246→ */
247→fn void* ScopeRegion.alloc_slow(ScopeRegion* self, usz aligned_size) {
248→    // Determine new chunk capacity: double the previous, or at least fit the request
249→    usz prev_cap = SCOPE_CHUNK_INITIAL;
250→    if (self.chunks != null) {
251→        prev_cap = self.chunks.capacity;
252→    }
253→    usz new_cap = prev_cap * 2;
254→    if (new_cap > SCOPE_CHUNK_MAX) new_cap = SCOPE_CHUNK_MAX;
255→    if (new_cap < aligned_size) new_cap = aligned_size;
256→
257→    ScopeChunk* chunk = scope_chunk_alloc(new_cap);
258→    chunk.next = self.chunks;
259→    self.chunks = chunk;
260→
261→    char* data = scope_chunk_data(chunk);
262→    self.bump = data + aligned_size;
263→    self.limit = data + chunk.capacity;
264→    self.alloc_bytes += aligned_size;
265→    self.alloc_count++;
266→    return (void*)data;
267→}
268→
269→/**
270→ * Bump-allocate `size` bytes from this scope. 8-byte aligned.
271→ * Fast path: ~3 instructions (load bump, add, compare).
272→ */
273→fn void* ScopeRegion.alloc(ScopeRegion* self, usz size) @inline {
274→    usz mask = 7;
275→    usz aligned = (size + mask) & ~mask;
276→    char* result = self.bump;
277→    char* new_bump = result + aligned;
278→    if (new_bump <= self.limit) {
279→        self.bump = new_bump;
280→        self.alloc_bytes += aligned;
281→        self.alloc_count++;
282→        return (void*)result;
283→    }
284→    return self.alloc_slow(aligned);
285→}
286→
287→// =============================================================================
288→// Destructor registration
289→// =============================================================================
290→
291→/**
292→ * Register a destructor to run when this scope is destroyed.
293→ * The ScopeDtor struct itself is bump-allocated in the scope's chunks.
294→ */
295→fn void scope_register_dtor(ScopeRegion* scope, void* ptr, ScopeDestructorFn func) {
296→    ScopeDtor* d = (ScopeDtor*)scope.alloc(ScopeDtor.sizeof);
297→    d.ptr = ptr;
298→    d.func = func;
299→    d.next = scope.dtors;
300→    scope.dtors = d;

