 10→/**
 11→ * Create a new empty StringVal with given initial capacity.
 12→ */
 13→fn StringVal* strval_new(usz initial_cap) {
 14→    if (initial_cap < 32) initial_cap = 32;
 15→    StringVal* sv = (StringVal*)mem::malloc(StringVal.sizeof);
 16→    sv.chars = (char*)mem::malloc(initial_cap);
 17→    sv.len = 0;
 18→    sv.capacity = initial_cap;
 19→    sv.chars[0] = 0;
 20→    return sv;
 21→}
 22→
 23→/**
 24→ * Ensure StringVal has room for at least `needed` more bytes.
 25→ */
 26→fn void strval_ensure(StringVal* sv, usz needed) {
 27→    if (sv.len + needed + 1 > sv.capacity) {
 28→        usz new_cap = sv.capacity * 2;
 29→        while (new_cap < sv.len + needed + 1) new_cap *= 2;
 30→        char* new_chars = (char*)mem::malloc(new_cap);
 31→        for (usz i = 0; i < sv.len; i++) new_chars[i] = sv.chars[i];
 32→        mem::free(sv.chars);
 33→        sv.chars = new_chars;
 34→        sv.capacity = new_cap;
 35→    }
 36→}
 37→
 38→/**
 39→ * Append a single char to a StringVal.
 40→ */
 41→fn void strval_push(StringVal* sv, char c) {
 42→    strval_ensure(sv, 1);
 43→    sv.chars[sv.len++] = c;
 44→}
