 46→fn Value* prim_add(Value*[] args, Env* env, Interp* interp) {
 47→    if (args.len < 1) return raise_error(interp, "+: expected at least 1 argument");
 48→
 49→    if (args.len == 1) {
 50→        if (!is_number(args[0])) return raise_error(interp, "+: expected number argument");
 51→        return args[0];
 52→    }
 53→
 54→    if (!is_number(args[0])) return raise_error(interp, "+: expected number argument");
 55→    if (!is_number(args[1])) return raise_error(interp, "+: expected number argument");
 56→    if (is_double(args[0]) || is_double(args[1])) {
