177→/**
178→ * (length lst) -> int
179→ * Returns the number of elements in a list
180→ */
181→fn Value* prim_length(Value*[] args, Env* env, Interp* interp) {
182→    if (args.len < 1) return raise_error(interp, "length: expected 1 argument");
183→
184→    // nil has length 0
185→    if (is_nil(args[0])) {
186→        return make_int(interp, 0);
187→    }
188→
189→    // String length
190→    if (is_string(args[0])) {
191→        return make_int(interp, (long)args[0].str_val.len);
192→    }
193→
194→    // Array length
195→    if (is_array(args[0])) {
196→        return make_int(interp, (long)args[0].array_val.length);
197→    }
198→
199→    // Dict count
200→    if (args[0].tag == HASHMAP) {
201→        return make_int(interp, (long)args[0].hashmap_val.count);
202→    }
203→
204→    // Count cons cells
205→    if (!is_cons(args[0])) {
206→        return raise_error(interp, "length: expected list, array, dict, or string");
207→    }
208→
209→    long count = 0;
210→    Value* current = args[0];
211→    while (is_cons(current)) {
212→        count++;
213→        current = current.cons_val.cdr;
214→    }
215→    return make_int(interp, count);
216→}
