600→
601→        case E_PERFORM:
602→            self.find_free_vars(expr.perform.arg, bound_vars, free_vars, enclosing_scope);
603→
604→        case E_RESOLVE:
605→            self.find_free_vars(expr.resolve.value, bound_vars, free_vars, enclosing_scope);
606→
607→        case E_HANDLE:
608→            self.find_free_vars(expr.handle.body, bound_vars, free_vars, enclosing_scope);
609→            for (usz i = 0; i < expr.handle.clause_count; i++) {
610→                // k_name and arg_name are bound in handler body
611→                List{SymbolId} handle_bound;
612→                foreach (b : *bound_vars) {
613→                    handle_bound.push(b);
614→                }
615→                handle_bound.push(expr.handle.clauses[i].k_name);
616→                handle_bound.push(expr.handle.clauses[i].arg_name);
617→                self.find_free_vars(expr.handle.clauses[i].handler_body, &handle_bound, free_vars, enclosing_scope);
618→                handle_bound.free();
619→            }
620→
621→        case E_BEGIN:
622→            for (usz i = 0; i < expr.begin.expr_count; i++) {
623→                self.find_free_vars(expr.begin.exprs[i], bound_vars, free_vars, enclosing_scope);
624→            }
625→
626→        case E_QUASIQUOTE:
627→            // Only look for free vars inside unquote nodes — the rest is quoted (literal symbols)
628→            self.find_free_vars_in_qq(expr.quasiquote.body, bound_vars, free_vars, enclosing_scope);
629→
630→        case E_UNQUOTE:
631→            self.find_free_vars(expr.unquote.body, bound_vars, free_vars, enclosing_scope);
632→
633→        case E_UNQUOTE_SPLICING:
634→            self.find_free_vars(expr.unquote_splicing.body, bound_vars, free_vars, enclosing_scope);
635→
636→        case E_DEFMACRO:
637→            // Macro templates may reference free vars at expansion time
638→            // Conservative: treat as having no free vars (macros expand at compile time)
639→            return;
640→
641→        case E_MODULE:
642→            for (usz i = 0; i < expr.module_expr.body_count; i++) {
643→                self.find_free_vars(expr.module_expr.body[i], bound_vars, free_vars, enclosing_scope);
644→            }
645→
646→        case E_IMPORT:
647→        case E_EXPORT_FROM:
648→            // No free variables
649→            return;
650→
651→        case E_SET:
652→            // The variable being set might be free
653→            SymbolId set_name = expr.set_expr.name;
654→            foreach (b : *bound_vars) {
655→                if ((uint)b == (uint)set_name) {
656→                    // Bound locally, just analyze the value
657→                    self.find_free_vars(expr.set_expr.value, bound_vars, free_vars, enclosing_scope);
658→                    return;
659→                }
660→            }
661→            // Check enclosing scope before is_primitive (enclosing var shadows global)
662→            if (enclosing_scope != null) {
663→                foreach (e : *enclosing_scope) {
664→                    if ((uint)e == (uint)set_name) {
665→                        bool set_enc_free = false;
666→                        foreach (f : *free_vars) {
667→                            if ((uint)f == (uint)set_name) { set_enc_free = true; break; }
668→                        }
669→                        if (!set_enc_free) {
670→                            free_vars.push(set_name);
671→                        }
672→                        self.find_free_vars(expr.set_expr.value, bound_vars, free_vars, enclosing_scope);
673→                        return;
674→                    }
675→                }
676→            }
677→            if (self.is_primitive(set_name)) {
678→                self.find_free_vars(expr.set_expr.value, bound_vars, free_vars, enclosing_scope);
679→                return;
680→            }
681→            // Check if already in free vars
682→            bool set_already_free = false;
683→            foreach (f : *free_vars) {
684→                if ((uint)f == (uint)set_name) { set_already_free = true; break; }
685→            }
686→            if (!set_already_free) {
687→                free_vars.push(set_name);
688→            }
689→            self.find_free_vars(expr.set_expr.value, bound_vars, free_vars, enclosing_scope);
690→
691→        default:
692→            // Handle other expression types conservatively
693→            return;
694→    }
695→}
