697→/**
698→ * Traverse quasiquote body, only descending into unquote/unquote-splicing for free vars.
699→ * In quasiquote, bare symbols are literals — only unquoted expressions reference variables.
700→ */
701→fn void Compiler.find_free_vars_in_qq(Compiler* self, Expr* expr, List{SymbolId}* bound_vars, List{SymbolId}* free_vars, List{SymbolId}* enclosing_scope) {
702→    if (expr == null) return;
703→    switch (expr.tag) {
704→        case E_UNQUOTE:
705→            // Unquoted expression — evaluate normally, so scan for free vars
706→            self.find_free_vars(expr.unquote.body, bound_vars, free_vars, enclosing_scope);
707→        case E_UNQUOTE_SPLICING:
708→            self.find_free_vars(expr.unquote_splicing.body, bound_vars, free_vars, enclosing_scope);
709→        case E_CALL:
710→            // Lists in qq template are parsed as E_CALL — traverse to find unquotes
711→            self.find_free_vars_in_qq(expr.call.func, bound_vars, free_vars, enclosing_scope);
712→            for (usz i = 0; i < expr.call.arg_count; i++) {
713→                self.find_free_vars_in_qq(expr.call.args[i], bound_vars, free_vars, enclosing_scope);
714→            }
715→        case E_APP:
716→            self.find_free_vars_in_qq(expr.app.func, bound_vars, free_vars, enclosing_scope);
717→            self.find_free_vars_in_qq(expr.app.arg, bound_vars, free_vars, enclosing_scope);
718→        case E_QUASIQUOTE:
719→            // Nested quasiquote — still only scan for unquotes
720→            self.find_free_vars_in_qq(expr.quasiquote.body, bound_vars, free_vars, enclosing_scope);
721→        default:
722→            // E_VAR, E_LIT, etc. in qq context are literal — no free vars
723→            return;
724→    }
725→}
