727→fn void Compiler.collect_pattern_bindings(Compiler* self, Pattern* pat, List{SymbolId}* bindings) {
728→    if (pat == null) return;
729→
730→    switch (pat.tag) {
731→        case PAT_VAR:
732→            bindings.push(pat.var_name);
733→
734→        case PAT_CONS:
735→            self.collect_pattern_bindings(pat.car_pat, bindings);
736→            self.collect_pattern_bindings(pat.cdr_pat, bindings);
737→
738→        case PAT_SEQ:
739→            for (usz i = 0; i < pat.elem_count; i++) {
740→                self.collect_pattern_bindings(pat.elements[i], bindings);
741→            }
742→            if (pat.rest_pos == REST_MIDDLE) {
743→                bindings.push(pat.rest_binding);
744→            }
745→
746→        case PAT_GUARD:
747→            if (pat.guard_sub != null) {
748→                self.collect_pattern_bindings(pat.guard_sub, bindings);
749→            }
750→
751→        default:
752→            return;
753→    }
754→}
