758→
759→    // Check known primitives
760→    char[][*] primitives = {
761→        "+", "-", "*", "/", "%",
762→        "=", "<", ">", "<=", ">=",
763→        "cons", "car", "cdr", "null?", "pair?",
764→        "list", "length", "not",
765→        "print", "println", "newline", "display",
766→        "string-append", "string-join", "substring",
767→        "string-split", "string-length", "string->list",
768→        "list->string", "string-upcase", "string-downcase",
769→        "string-trim", "string?", "int?", "symbol?",
770→        "closure?", "continuation?", "double?", "list?",
771→        "boolean?", "number?",
772→        "string->number", "number->string",
773→        "gensym", "load", "apply", "equal?",
774→        "dict", "dict-set!", "dict?",
775→        "ref", "push!", "keys", "values", "has?", "remove!",
776→        "read-file", "write-file", "file-exists?", "read-lines",
777→        "type-of",
778→        "abs", "min", "max", "floor", "ceiling", "round",
779→        "truncate", "sqrt", "even?", "odd?", "zero?",
780→        "positive?", "negative?", "gcd",
781→        "bitwise-and", "bitwise-or", "bitwise-xor",
782→        "bitwise-not", "lshift", "rshift",
783→        "true", "false", "nil"
784→    };
785→
786→    foreach (prim : primitives) {
787→        if (self.str_eq(name, prim)) return true;
788→    }
789→
790→    // Check if it's a defined global
791→    foreach (g : self.defined_globals) {
792→        if ((uint)g == (uint)sym) return true;
793→    }
794→
795→    return false;
796→}
