816→
817→/**
818→ * Pre-scan the entire expression tree to identify all mutable-captured variables.
819→ * Must be called before scan_lambdas so that lambda scanning can exclude
820→ * mutable-captured variables from closure struct captures.
821→ */
822→fn void Compiler.prescan_mutable_captures(Compiler* self, Expr* expr) {
823→    if (expr == null) return;
824→    switch (expr.tag) {
825→        case E_LET:
826→            // Check if this let-bound variable is mutable-captured
827→            if (self.is_mutable_capture(expr.let_expr.name, expr.let_expr.body)) {
828→                // Add to mutable captures if not already present
829→                bool already = false;
830→                foreach (mc : self.mutable_captures) {
831→                    if ((uint)mc == (uint)expr.let_expr.name) { already = true; break; }
832→                }
833→                if (!already) {
834→                    self.mutable_captures.push(expr.let_expr.name);
835→                }
836→            }
837→            self.prescan_mutable_captures(expr.let_expr.init);
838→            self.prescan_mutable_captures(expr.let_expr.body);
839→        case E_LAMBDA:
840→            self.prescan_mutable_captures(expr.lambda.body);
841→        case E_APP:
842→            self.prescan_mutable_captures(expr.app.func);
843→            self.prescan_mutable_captures(expr.app.arg);
844→        case E_IF:
845→            self.prescan_mutable_captures(expr.if_expr.test);
846→            self.prescan_mutable_captures(expr.if_expr.then_branch);
847→            self.prescan_mutable_captures(expr.if_expr.else_branch);
848→        case E_DEFINE:
849→            self.prescan_mutable_captures(expr.define.value);
850→        case E_BEGIN:
851→            for (usz i = 0; i < expr.begin.expr_count; i++) {
852→                self.prescan_mutable_captures(expr.begin.exprs[i]);
853→            }
854→        case E_CALL:
855→            self.prescan_mutable_captures(expr.call.func);
856→            for (usz i = 0; i < expr.call.arg_count; i++) {
857→                self.prescan_mutable_captures(expr.call.args[i]);
858→            }
859→        case E_AND:
860→            self.prescan_mutable_captures(expr.and_expr.left);
861→            self.prescan_mutable_captures(expr.and_expr.right);
862→        case E_OR:
863→            self.prescan_mutable_captures(expr.or_expr.left);
864→            self.prescan_mutable_captures(expr.or_expr.right);
865→        case E_MATCH:
866→            self.prescan_mutable_captures(expr.match.scrutinee);
867→            for (usz i = 0; i < expr.match.clause_count; i++) {
868→                self.prescan_mutable_captures(expr.match.clauses[i].result);
869→            }
870→        case E_SET:
871→            self.prescan_mutable_captures(expr.set_expr.value);
872→        case E_RESET:
873→            self.prescan_mutable_captures(expr.reset.body);
874→        case E_SHIFT:
875→            self.prescan_mutable_captures(expr.shift.body);
876→        case E_HANDLE:
877→            self.prescan_mutable_captures(expr.handle.body);
878→            for (usz i = 0; i < expr.handle.clause_count; i++) {
879→                self.prescan_mutable_captures(expr.handle.clauses[i].handler_body);
880→            }
881→        case E_PERFORM:
882→            self.prescan_mutable_captures(expr.perform.arg);
883→        case E_RESOLVE:
884→            self.prescan_mutable_captures(expr.resolve.value);
885→        default:
886→            return;
887→    }
888→}
