892→// =============================================================================
893→
894→/**
895→ * Check if a variable is both captured by a nested lambda AND mutated with set!.
896→ * This is done by scanning the expression tree for (set! name ...) where name
897→ * is a free variable of some nested lambda.
898→ *
899→ * We detect: is `name` set! inside any sub-expression that also contains

 900→ * a lambda that captures `name`?
 901→ */
 902→fn bool Compiler.is_mutable_capture(Compiler* self, SymbolId name, Expr* body) {
 903→    // Check if name is set! anywhere AND captured by any nested lambda
 904→    bool has_set = self.has_set_on(name, body);
 905→    bool has_capture = self.is_captured_by_nested_lambda(name, body);
 906→    return has_set && has_capture;
 907→}
 908→
 909→fn bool Compiler.has_set_on(Compiler* self, SymbolId name, Expr* expr) {
 910→    if (expr == null) return false;
 911→    switch (expr.tag) {
 912→        case E_SET:
 913→            if ((uint)expr.set_expr.name == (uint)name) return true;
 914→            return self.has_set_on(name, expr.set_expr.value);
 915→        case E_APP:
 916→            return self.has_set_on(name, expr.app.func) || self.has_set_on(name, expr.app.arg);
 917→        case E_IF:
 918→            return self.has_set_on(name, expr.if_expr.test) ||
 919→                   self.has_set_on(name, expr.if_expr.then_branch) ||
 920→                   self.has_set_on(name, expr.if_expr.else_branch);
 921→        case E_LET:
 922→            return self.has_set_on(name, expr.let_expr.init) || self.has_set_on(name, expr.let_expr.body);
 923→        case E_LAMBDA:
 924→            return self.has_set_on(name, expr.lambda.body);
 925→        case E_BEGIN:
 926→            for (usz i = 0; i < expr.begin.expr_count; i++) {
 927→                if (self.has_set_on(name, expr.begin.exprs[i])) return true;
 928→            }
 929→            return false;
 930→        case E_CALL:
 931→            if (self.has_set_on(name, expr.call.func)) return true;
 932→            for (usz i = 0; i < expr.call.arg_count; i++) {
 933→                if (self.has_set_on(name, expr.call.args[i])) return true;
 934→            }
 935→            return false;
 936→        case E_AND:
 937→            return self.has_set_on(name, expr.and_expr.left) || self.has_set_on(name, expr.and_expr.right);
 938→        case E_OR:
 939→            return self.has_set_on(name, expr.or_expr.left) || self.has_set_on(name, expr.or_expr.right);
 940→        case E_MATCH:
 941→            if (self.has_set_on(name, expr.match.scrutinee)) return true;
 942→            for (usz i = 0; i < expr.match.clause_count; i++) {
 943→                if (self.has_set_on(name, expr.match.clauses[i].result)) return true;
 944→            }
 945→            return false;
 946→        default:
 947→            return false;
 948→    }
 949→}
 950→
 951→fn bool Compiler.is_captured_by_nested_lambda(Compiler* self, SymbolId name, Expr* expr) {
 952→    if (expr == null) return false;
 953→    switch (expr.tag) {
 954→        case E_LAMBDA:
 955→            // Check if this lambda captures name as a free variable
 956→            List{SymbolId} bound;
 957→            if ((uint)expr.lambda.param != 0xFFFFFFFF) {
 958→                bound.push(expr.lambda.param);
 959→            }
 960→            List{SymbolId} free;
 961→            self.find_free_vars(expr.lambda.body, &bound, &free, null);
 962→            bool captured = false;
 963→            foreach (f : free) {
 964→                if ((uint)f == (uint)name) { captured = true; break; }
 965→            }
 966→            bound.free();
 967→            free.free();
 968→            if (captured) return true;
 969→            // Also check deeper nesting
 970→            return self.is_captured_by_nested_lambda(name, expr.lambda.body);
 971→        case E_APP:
 972→            return self.is_captured_by_nested_lambda(name, expr.app.func) ||
 973→                   self.is_captured_by_nested_lambda(name, expr.app.arg);
 974→        case E_IF:
 975→            return self.is_captured_by_nested_lambda(name, expr.if_expr.test) ||
 976→                   self.is_captured_by_nested_lambda(name, expr.if_expr.then_branch) ||
 977→                   self.is_captured_by_nested_lambda(name, expr.if_expr.else_branch);
 978→        case E_LET:
 979→            return self.is_captured_by_nested_lambda(name, expr.let_expr.init) ||
 980→                   self.is_captured_by_nested_lambda(name, expr.let_expr.body);
 981→        case E_BEGIN:
 982→            for (usz i = 0; i < expr.begin.expr_count; i++) {
 983→                if (self.is_captured_by_nested_lambda(name, expr.begin.exprs[i])) return true;
 984→            }
 985→            return false;
 986→        case E_CALL:
 987→            if (self.is_captured_by_nested_lambda(name, expr.call.func)) return true;
 988→            for (usz i = 0; i < expr.call.arg_count; i++) {
 989→                if (self.is_captured_by_nested_lambda(name, expr.call.args[i])) return true;
 990→            }
 991→            return false;
 992→        case E_AND:
 993→            return self.is_captured_by_nested_lambda(name, expr.and_expr.left) ||
 994→                   self.is_captured_by_nested_lambda(name, expr.and_expr.right);
 995→        case E_OR:
 996→            return self.is_captured_by_nested_lambda(name, expr.or_expr.left) ||
 997→                   self.is_captured_by_nested_lambda(name, expr.or_expr.right);
 998→        case E_MATCH:
 999→            if (self.is_captured_by_nested_lambda(name, expr.match.scrutinee)) return true;
1000→            for (usz i = 0; i < expr.match.clause_count; i++) {
1001→                if (self.is_captured_by_nested_lambda(name, expr.match.clauses[i].result)) return true;
1002→            }
1003→            return false;
1004→        case E_SET:
1005→            return self.is_captured_by_nested_lambda(name, expr.set_expr.value);
1006→        default:
1007→            return false;
1008→    }
1009→}
