1026→/**
1027→ * Serialize an Expr* back to Pika source text.
1028→ * This is used to convert continuation forms (reset/shift/handle/perform)
1029→ * into source strings that can be evaluated by the interpreter at runtime.
1030→ *
1031→ * The serialized output is appended to the compiler's output buffer temporarily
1032→ * via a separate List{char} buffer.
1033→ */
1034→fn void Compiler.serialize_expr_to_buf(Compiler* self, Expr* expr, List{char}* buf) {
1035→    if (expr == null) {
1036→        self.buf_append(buf, "nil");
1037→        return;
1038→    }
1039→
1040→    switch (expr.tag) {
1041→        case E_LIT:
1042→            self.serialize_value_to_buf(expr.lit.value, buf);
1043→
1044→        case E_VAR:
1045→            char[] name = self.interp.symbols.get_name(expr.var_expr.name);
1046→            self.buf_append(buf, name);
1047→
1048→        case E_LAMBDA:
1049→            self.buf_append(buf, "(lambda (");
1050→            // Check for zero-arg lambda
1051→            if ((uint)expr.lambda.param == 0xFFFFFFFF) {
1052→                // zero-arg
1053→            } else {
1054→                char[] pname = self.interp.symbols.get_name(expr.lambda.param);
1055→                self.buf_append(buf, pname);
1056→            }
1057→            self.buf_append(buf, ") ");
1058→            self.serialize_expr_to_buf(expr.lambda.body, buf);
1059→            buf.push(')');
1060→
1061→        case E_APP:
1062→            buf.push('(');
1063→            self.serialize_expr_to_buf(expr.app.func, buf);
1064→            buf.push(' ');
1065→            self.serialize_expr_to_buf(expr.app.arg, buf);
1066→            buf.push(')');
1067→
1068→        case E_IF:
1069→            self.buf_append(buf, "(if ");
1070→            self.serialize_expr_to_buf(expr.if_expr.test, buf);
1071→            buf.push(' ');
1072→            self.serialize_expr_to_buf(expr.if_expr.then_branch, buf);
1073→            buf.push(' ');
1074→            self.serialize_expr_to_buf(expr.if_expr.else_branch, buf);
1075→            buf.push(')');
1076→
1077→        case E_LET:
1078→            if (expr.let_expr.is_recursive) {
1079→                self.buf_append(buf, "(let ^rec (");
1080→            } else {
1081→                self.buf_append(buf, "(let (");
1082→            }
1083→            char[] let_name = self.interp.symbols.get_name(expr.let_expr.name);
1084→            self.buf_append(buf, let_name);
1085→            buf.push(' ');
1086→            self.serialize_expr_to_buf(expr.let_expr.init, buf);
1087→            self.buf_append(buf, ") ");
1088→            self.serialize_expr_to_buf(expr.let_expr.body, buf);
1089→            buf.push(')');
1090→
1091→        case E_DEFINE:
1092→            self.buf_append(buf, "(define ");
1093→            char[] def_name = self.interp.symbols.get_name(expr.define.name);
1094→            self.buf_append(buf, def_name);
1095→            buf.push(' ');
1096→            self.serialize_expr_to_buf(expr.define.value, buf);
1097→            buf.push(')');
1098→
1099→        case E_QUOTE:
1100→            buf.push('\'');
1101→            self.serialize_value_to_buf(expr.quote.datum, buf);
1102→
1103→        case E_RESET:
1104→            self.buf_append(buf, "(reset ");
1105→            self.serialize_expr_to_buf(expr.reset.body, buf);
1106→            buf.push(')');
1107→
1108→        case E_SHIFT:
1109→            self.buf_append(buf, "(shift ");
1110→            char[] k_name = self.interp.symbols.get_name(expr.shift.k_name);
1111→            self.buf_append(buf, k_name);
1112→            buf.push(' ');
1113→            self.serialize_expr_to_buf(expr.shift.body, buf);
1114→            buf.push(')');
1115→
1116→        case E_PERFORM:
1117→            self.buf_append(buf, "(perform ");
1118→            char[] tag_name = self.interp.symbols.get_name(expr.perform.tag);
1119→            self.buf_append(buf, tag_name);
1120→            buf.push(' ');
1121→            self.serialize_expr_to_buf(expr.perform.arg, buf);
1122→            buf.push(')');
1123→
1124→        case E_RESOLVE:
1125→            self.buf_append(buf, "(resolve ");
1126→            self.serialize_expr_to_buf(expr.resolve.value, buf);
1127→            buf.push(')');
1128→
1129→        case E_HANDLE:
1130→            self.buf_append(buf, "(handle ");
1131→            self.serialize_expr_to_buf(expr.handle.body, buf);
1132→            for (usz i = 0; i < expr.handle.clause_count; i++) {
1133→                self.buf_append(buf, " ((");
1134→                char[] etag = self.interp.symbols.get_name(expr.handle.clauses[i].effect_tag);
1135→                self.buf_append(buf, etag);
1136→                buf.push(' ');
1137→                char[] ek = self.interp.symbols.get_name(expr.handle.clauses[i].k_name);
1138→                self.buf_append(buf, ek);
1139→                buf.push(' ');
1140→                char[] ea = self.interp.symbols.get_name(expr.handle.clauses[i].arg_name);
1141→                self.buf_append(buf, ea);
1142→                self.buf_append(buf, ") ");
1143→                self.serialize_expr_to_buf(expr.handle.clauses[i].handler_body, buf);
1144→                buf.push(')');
1145→            }
1146→            buf.push(')');
1147→
1148→        case E_AND:
1149→            self.buf_append(buf, "(and ");
