1158→            buf.push(' ');
1159→            self.serialize_expr_to_buf(expr.or_expr.right, buf);
1160→            buf.push(')');
1161→
1162→        case E_BEGIN:
1163→            self.buf_append(buf, "(begin");
1164→            for (usz i = 0; i < expr.begin.expr_count; i++) {
1165→                buf.push(' ');
