1167→            }
1168→            buf.push(')');
1169→
1170→        case E_CALL:
1171→            buf.push('(');
1172→            self.serialize_expr_to_buf(expr.call.func, buf);
1173→            for (usz i = 0; i < expr.call.arg_count; i++) {
1174→                buf.push(' ');
1175→                self.serialize_expr_to_buf(expr.call.args[i], buf);
1176→            }
1177→            buf.push(')');
1178→
1179→        case E_SET:
1180→            self.buf_append(buf, "(set! ");
1181→            char[] set_name = self.interp.symbols.get_name(expr.set_expr.name);
1182→            self.buf_append(buf, set_name);
1183→            buf.push(' ');
1184→            self.serialize_expr_to_buf(expr.set_expr.value, buf);
1185→            buf.push(')');
1186→
1187→        case E_MATCH:
