615→/**
616→ * Get value for key. Returns pointer to value or null if not found.
617→ */
618→fn Value* rtmap_get(RtHashMap* m, Value key) {
619→    uint h = rt_hash_key(key) & m.mask;
620→    for (uint i = 0; i < m.capacity; i++) {
621→        uint idx = (h + i) & m.mask;
622→        RtHashEntry* entry = &m.entries[idx];
623→        if (rtmap_slot_empty(entry)) return null;
624→        if (rt_key_equal(entry.key, key)) return &entry.value;
625→    }
626→    return null;
627→}
628→
629→/**
630→ * Set key-value pair. Grows at 70% load.
631→ */
632→fn void rtmap_set(RtHashMap* m, Value key, Value value) {
633→    if (m.count * 10 >= m.capacity * 7) {
634→        rtmap_grow(m);
635→    }
636→
637→    uint h = rt_hash_key(key) & m.mask;
638→    for (uint i = 0; i < m.capacity; i++) {
639→        uint idx = (h + i) & m.mask;
640→        RtHashEntry* entry = &m.entries[idx];
641→        if (rtmap_slot_empty(entry)) {
642→            entry.key = key;
643→            entry.value = value;
644→            m.count++;
645→            return;
646→        }
647→        if (rt_key_equal(entry.key, key)) {
648→            entry.value = value;
649→            return;
650→        }
651→    }
652→}
653→
654→/**
655→ * Remove key from map using backward-shift deletion.
656→ */
657→fn bool rtmap_remove(RtHashMap* m, Value key) {
658→    uint h = rt_hash_key(key) & m.mask;
659→    for (uint i = 0; i < m.capacity; i++) {
660→        uint idx = (h + i) & m.mask;
661→        RtHashEntry* entry = &m.entries[idx];
662→        if (rtmap_slot_empty(entry)) return false;
663→        if (rt_key_equal(entry.key, key)) {
664→            // Backward shift delete
665→            uint j = idx;
666→            for (;;) {
667→                uint next = (j + 1) & m.mask;
668→                if (rtmap_slot_empty(&m.entries[next])) break;
669→                uint natural = rt_hash_key(m.entries[next].key) & m.mask;
670→                bool should_move;
671→                if (j < next) {
672→                    should_move = natural <= j || natural > next;
673→                } else {
674→                    should_move = natural <= j && natural > next;
675→                }
676→                if (!should_move) break;
677→                m.entries[j] = m.entries[next];
678→                j = next;
679→            }
680→            m.entries[j].key.tag = V_NIL;
681→            m.entries[j].value.tag = V_NIL;
682→            m.count--;
683→            return true;
684→        }
685→    }
686→    return false;
687→}
