717→/**
718→ * Push element to end of array, growing if needed.
719→ */
720→fn void rtarray_push(RtArray* a, Value val) {
721→    if (a.length >= a.capacity) {
722→        usz new_cap = a.capacity * 2;
723→        if (new_cap < 8) new_cap = 8;
724→        Value* new_items = (Value*)mem::malloc(Value.sizeof * new_cap);
725→        for (usz i = 0; i < a.length; i++) {
726→            new_items[i] = a.items[i];
727→        }
728→        mem::free(a.items);
729→        a.items = new_items;
730→        a.capacity = new_cap;
731→    }
732→    a.items[a.length] = val;
733→    a.length++;
734→}
