 973→/**
 974→ * Append two lists: (append '(a b) '(c d)) => '(a b c d).
 975→ * Copies spine of first list, shares tail with second.
 976→ */
 977→fn Value rt_list_append(Value a, Value b) {
 978→    if (a.tag == V_NIL) return b;
 979→    if (a.tag != V_CONS) return b;
 980→
 981→    // Collect elements of first list
 982→    Value[64] items;
 983→    usz count = 0;
 984→    Value cur = a;
 985→    while (cur.tag == V_CONS && count < 64) {
 986→        Value* car = main::dereference_as(Value, cur.cons_val.car);
 987→        items[count] = *car;
 988→        count++;
 989→        Value* cdr = main::dereference_as(Value, cur.cons_val.cdr);
 990→        cur = *cdr;
 991→    }
 992→
 993→    // Build result from right: b, then prepend items in reverse
 994→    Value result = b;
 995→    for (usz i = count; i > 0; i--) {
 996→        result = rt_cons(items[i - 1], result);
 997→    }
 998→    return result;
 999→}
