1055→fn Value rt_add(Value a, Value b) {
1056→    if (!rt_is_number(a) || !rt_is_number(b)) return make_nil();
1057→    if (a.tag == V_DOUBLE || b.tag == V_DOUBLE) return rt_make_double(rt_to_double(a) + rt_to_double(b));
