1061→fn Value rt_sub(Value a, Value b) {
1062→    if (!rt_is_number(a) || !rt_is_number(b)) return make_nil();
1063→    if (a.tag == V_DOUBLE || b.tag == V_DOUBLE) return rt_make_double(rt_to_double(a) - rt_to_double(b));
1064→    return make_int(a.int_val - b.int_val);
1065→}
1066→
1067→fn Value rt_mul(Value a, Value b) {
1068→    if (!rt_is_number(a) || !rt_is_number(b)) return make_nil();
1069→    if (a.tag == V_DOUBLE || b.tag == V_DOUBLE) return rt_make_double(rt_to_double(a) * rt_to_double(b));
1070→    return make_int(a.int_val * b.int_val);
1071→}
1072→
1073→fn Value rt_div(Value a, Value b) {
1074→    if (!rt_is_number(a) || !rt_is_number(b)) return make_nil();
1075→    if (a.tag == V_DOUBLE || b.tag == V_DOUBLE) {
1076→        double bd = rt_to_double(b);
1077→        if (bd == 0.0) return make_nil();
1078→        return rt_make_double(rt_to_double(a) / bd);
1079→    }
1080→    if (b.int_val == 0) return make_nil();
1081→    return make_int(a.int_val / b.int_val);
1082→}
1083→
1084→fn Value rt_mod(Value a, Value b) {
1085→    if (a.tag != V_INT || b.tag != V_INT) return make_nil();
1086→    if (b.int_val == 0) return make_nil();
1087→    return make_int(a.int_val % b.int_val);
1088→}
