454→    for (usz i = 0; i < self.type_count; i++) new_types[i] = self.types[i];
455→    mem::free(self.types);
456→    self.types = new_types;
457→    self.capacity = new_cap;
458→
459→    // Rebuild hash table at 2x new capacity
460→    usz new_hash_cap = new_cap * 2;
461→    TypeId* new_hash = (TypeId*)mem::malloc(TypeId.sizeof * new_hash_cap);
462→    for (usz i = 0; i < new_hash_cap; i++) new_hash[i] = INVALID_TYPE_ID;
463→    mem::free(self.type_hash_index);
464→    self.type_hash_index = new_hash;
465→    self.hash_capacity = new_hash_cap;
466→
467→    usz mask = new_hash_cap - 1;
468→    for (usz i = 0; i < self.type_count; i++) {
469→        char[] name_str = syms.get_name(self.types[i].name);
470→        usz h = hash_symbol(name_str);
471→        for (usz probe = 0; probe < new_hash_cap; probe++) {
472→            usz slot = (h + probe) & mask;
473→            if (new_hash[slot] == INVALID_TYPE_ID) {
474→                new_hash[slot] = (TypeId)i;
475→                break;
476→            }
477→        }
478→    }
479→}
