481→fn void TypeRegistry.destroy(TypeRegistry* self) {
482→    if (self.types != null) { mem::free(self.types); self.types = null; }
483→    if (self.type_hash_index != null) { mem::free(self.type_hash_index); self.type_hash_index = null; }
484→}
485→
486→fn TypeId TypeRegistry.register_type(TypeRegistry* self, TypeInfo info, SymbolTable* syms) {
487→    if (self.type_count >= self.capacity) {
488→        self.grow(syms);
489→    }
490→    TypeId id = (TypeId)self.type_count;
491→    self.types[self.type_count] = info;
492→    self.type_count++;
493→
494→    // Insert into hash table
495→    char[] name = syms.get_name(info.name);
496→    usz h = hash_symbol(name);
497→    usz mask = self.hash_capacity - 1;
498→    for (usz probe = 0; probe < self.hash_capacity; probe++) {
499→        usz slot = (h + probe) & mask;
500→        if (self.type_hash_index[slot] == INVALID_TYPE_ID) {
501→            self.type_hash_index[slot] = id;
502→            break;
503→        }
504→    }
505→    return id;
506→}
507→
508→fn TypeId TypeRegistry.lookup(TypeRegistry* self, SymbolId name, SymbolTable* syms) {
509→    char[] name_str = syms.get_name(name);
510→    usz h = hash_symbol(name_str);
511→    usz mask = self.hash_capacity - 1;
512→    for (usz probe = 0; probe < self.hash_capacity; probe++) {
513→        usz slot = (h + probe) & mask;
514→        TypeId tid = self.type_hash_index[slot];
515→        if (tid == INVALID_TYPE_ID) return INVALID_TYPE_ID;
516→        if (self.types[(usz)tid].name == name) return tid;
517→    }
518→    return INVALID_TYPE_ID;
519→}
520→
521→fn TypeInfo* TypeRegistry.get(TypeRegistry* self, TypeId id) {
522→    if (id == INVALID_TYPE_ID || (usz)id >= self.type_count) return null;
523→    return &self.types[(usz)id];
524→}
525→
526→fn bool TypeRegistry.is_subtype(TypeRegistry* self, TypeId child, TypeId parent) {
527→    if (child == parent) return true;
528→    // Walk parent chain (depth limit 16)
529→    TypeId current = child;
530→    for (usz depth = 0; depth < 16; depth++) {
531→        TypeInfo* info = self.get(current);
532→        if (info == null) return false;
533→        if (info.parent == INVALID_TYPE_ID) return false;
534→        if (info.parent == parent) return true;
535→        current = info.parent;
536→    }
537→    return false;
538→}
