627→// Scope destructor for Values with heap-allocated backing data.
628→// Mirrors destroy_value in eval.c3 but called from scope_region lifecycle.
629→fn void scope_dtor_value(void* ptr) {
630→    // Dtors re-enabled after fixing use-after-free (parser literals, module env)
631→    Value* v = (Value*)ptr;
632→    switch (v.tag) {
633→        case STRING:
634→        case ERROR:
635→            if (v.str_val != null) {
636→                if (v.str_val.chars != null) mem::free(v.str_val.chars);
637→                mem::free(v.str_val);
638→                v.str_val = null;
639→            }
640→        case CLOSURE:
641→            if (v.closure_val != null) {
642→                if (--v.closure_val.refcount == 0) {
643→                    // Last reference — release env_scope and free Closure
644→                    if (v.closure_val.env_scope != null) {
645→                        main::scope_release(v.closure_val.env_scope);
646→                    }
647→                    if (v.closure_val.params != null) mem::free(v.closure_val.params);
648→                    if (v.closure_val.type_sig != null) mem::free(v.closure_val.type_sig);
649→                    mem::free(v.closure_val);
650→                }
651→                v.closure_val = null;
652→            }
653→        case PRIMITIVE:
654→            if (v.prim_val != null) {
655→                mem::free(v.prim_val);
656→                v.prim_val = null;
657→            }
658→        case ARRAY:
659→            if (v.array_val != null) {
660→                if (v.array_val.items != null) mem::free(v.array_val.items);
661→                mem::free(v.array_val);
662→                v.array_val = null;
663→            }
664→        case INSTANCE:
665→            if (v.instance_val != null) {
666→                mem::free(v.instance_val);
667→                v.instance_val = null;
668→            }
669→        case METHOD_TABLE:
670→            if (v.method_table_val != null) {
671→                if (v.method_table_val.entries != null) mem::free(v.method_table_val.entries);
672→                mem::free(v.method_table_val);
673→                v.method_table_val = null;
674→            }
675→        case HASHMAP:
676→            if (v.hashmap_val != null) {
677→                if (v.hashmap_val.entries != null) mem::free(v.hashmap_val.entries);
678→                mem::free(v.hashmap_val);
679→                v.hashmap_val = null;
680→            }
681→        case FFI_HANDLE:
682→            if (v.ffi_val != null) {
683→                // Note: don't dlclose here — FFI handles are long-lived
684→                mem::free(v.ffi_val);
685→                v.ffi_val = null;
686→            }
687→        // COROUTINE and CONTINUATION dtors deferred — lifecycle managed by coroutine primitives.
688→        // See plan Phase 4c step 3 for details.
689→        default: {}
690→    }
691→}
