1297→fn void Compiler.serialize_value_to_buf(Compiler* self, Value* v, List{char}* buf) {
1298→    if (v == null || v.tag == NIL) {
1299→        self.buf_append(buf, "nil");
1300→        return;
1301→    }
1302→
1303→    switch (v.tag) {
1304→        case INT:
1305→            // Convert int to string
1306→            long n = v.int_val;
1307→            if (n < 0) {
1308→                buf.push('-');
1309→                n = -n;
1310→            }
1311→            if (n == 0) {
1312→                buf.push('0');
1313→            } else {
1314→                char[32] digits;
1315→                usz dpos = 0;
1316→                while (n > 0 && dpos < 31) {
1317→                    digits[dpos++] = (char)('0' + (n % 10));
1318→                    n /= 10;
1319→                }
1320→                for (isz di = (isz)dpos - 1; di >= 0; di--) {
1321→                    buf.push(digits[(usz)di]);
1322→                }
1323→            }
1324→
1325→        case DOUBLE:
1326→            char[64] dbuf;
1327→            char[] dslice = io::bprintf(&dbuf, "%.15g", v.double_val)!!;
1328→            self.buf_append(buf, dslice);
1329→
1330→        case STRING:
1331→            buf.push('"');
1332→            for (usz i = 0; i < v.str_val.len; i++) {
1333→                char c = v.str_val.chars[i];
1334→                if (c == '"') {
1335→                    buf.push('\\');
1336→                    buf.push('"');
1337→                } else if (c == '\\') {
1338→                    buf.push('\\');
1339→                    buf.push('\\');
1340→                } else if (c == '\n') {
1341→                    buf.push('\\');
1342→                    buf.push('n');
1343→                } else {
1344→                    buf.push(c);
1345→                }
1346→            }
1347→            buf.push('"');
1348→
1349→        case SYMBOL:
1350→            char[] sym_name = self.interp.symbols.get_name(v.sym_val);
1351→            self.buf_append(buf, sym_name);
1352→
1353→        case CONS:
1354→            buf.push('(');
1355→            self.serialize_value_to_buf(v.cons_val.car, buf);
1356→            Value* rest = v.cons_val.cdr;
1357→            while (rest != null && rest.tag == CONS) {
1358→                buf.push(' ');
1359→                self.serialize_value_to_buf(rest.cons_val.car, buf);
1360→                rest = rest.cons_val.cdr;
1361→            }
1362→            if (rest != null && rest.tag != NIL) {
1363→                self.buf_append(buf, " . ");
1364→                self.serialize_value_to_buf(rest, buf);
1365→            }
1366→            buf.push(')');
1367→
1368→        default:
1369→            self.buf_append(buf, "nil");
1370→    }
1371→}
1372→
1373→fn void Compiler.serialize_pattern_to_buf(Compiler* self, Pattern* pat, List{char}* buf) {
1374→    if (pat == null) {
1375→        buf.push('_');
1376→        return;
1377→    }
1378→
1379→    switch (pat.tag) {
1380→        case PAT_WILDCARD:
1381→            buf.push('_');
1382→
1383→        case PAT_VAR:
1384→            char[] vname = self.interp.symbols.get_name(pat.var_name);
1385→            self.buf_append(buf, vname);
1386→
1387→        case PAT_LIT:
1388→            self.serialize_value_to_buf(pat.lit_value, buf);
1389→
1390→        case PAT_QUOTE:
1391→            buf.push('\'');
1392→            self.serialize_value_to_buf(pat.quote_datum, buf);
1393→
1394→        case PAT_SEQ:
1395→            buf.push('[');
1396→            for (usz i = 0; i < pat.elem_count; i++) {
1397→                if (i > 0) buf.push(' ');
1398→                self.serialize_pattern_to_buf(pat.elements[i], buf);
1399→            }
1400→            if (pat.rest_pos == REST_MIDDLE) {
1401→                self.buf_append(buf, " .. ");
1402→                char[] rname = self.interp.symbols.get_name(pat.rest_binding);
1403→                self.buf_append(buf, rname);
1404→            }
1405→            buf.push(']');
1406→
1407→        case PAT_CONS:
1408→            buf.push('(');
1409→            self.serialize_pattern_to_buf(pat.car_pat, buf);
1410→            self.buf_append(buf, " . ");
1411→            self.serialize_pattern_to_buf(pat.cdr_pat, buf);
1412→            buf.push(')');
1413→
1414→        default:
1415→            buf.push('_');
1416→    }
1417→}
1418→
1419→fn void Compiler.buf_append(Compiler* self, List{char}* buf, char[] s) {
1420→    foreach (c : s) {
1421→        buf.push(c);
1422→    }
1423→}
