1425→/**
1426→ * Emit the serialized form of an expression as a C3 string literal
1427→ * directly into the compiler output. Escapes special characters.
1428→ */
1429→fn void Compiler.emit_serialized_expr(Compiler* self, Expr* expr) {
1430→    List{char} buf;
1431→    self.serialize_expr_to_buf(expr, &buf);
1432→
1433→    // Emit the serialized source as a C3 string literal with escaping
1434→    self.emit("\"");
1435→    for (usz i = 0; i < buf.len(); i++) {
1436→        char c = buf.entries[i];
1437→        if (c == '"') {
1438→            self.emit("\\\"");
1439→        } else if (c == '\\') {
1440→            self.emit("\\\\");
1441→        } else if (c == '\n') {
1442→            self.emit("\\n");
1443→        } else if (c == '\t') {
1444→            self.emit("\\t");
1445→        } else {
1446→            self.emit_char(c);
1447→        }
1448→    }
1449→    self.emit("\"");
1450→
1451→    buf.free();
1452→}
