1454→/**
1455→ * Collect free variables from a continuation expression (reset/shift/handle/perform).
1456→ * These are variables that need to be injected into the interpreter before evaluation.
1457→ * Returns the list of free variables (caller must free).
1458→ */
1459→fn List{SymbolId} Compiler.collect_cont_free_vars(Compiler* self, Expr* expr) {
1460→    List{SymbolId} bound;
1461→    List{SymbolId} free;
1462→    self.for_delegation = true;
1463→    self.find_free_vars(expr, &bound, &free, null);
1464→    self.for_delegation = false;
1465→    bound.free();
1466→    return free;
1467→}
