1506→/**
1507→ * Compile a complete program to C3 source code.
1508→ * Prepends stdlib definitions so HOFs are available.
1509→ */
1510→fn char[] Compiler.compile_program(Compiler* self, char[] source) {
1511→    // Prepend stdlib prelude to user source using bulk copy
1512→    usz total = STDLIB_PRELUDE.len + 1 + source.len;
1513→    char* full_buf = (char*)mem::malloc(total);
1514→    defer mem::free(full_buf);
1515→    mem::copy(full_buf, STDLIB_PRELUDE.ptr, STDLIB_PRELUDE.len);
1516→    full_buf[STDLIB_PRELUDE.len] = ' ';
1517→    mem::copy(&full_buf[STDLIB_PRELUDE.len + 1], source.ptr, source.len);
1518→    char[] full = full_buf[:total];
1519→
1520→    // Parse the program
1521→    List{Expr*} exprs = parse_program(full, self.interp);
1522→    defer exprs.free();
1523→
1524→    // First pass: collect all top-level defines (including inside module bodies)
1525→    foreach (expr : exprs) {
1526→        if (expr.tag == E_DEFINE) {
1527→            self.defined_globals.push(expr.define.name);
1528→        } else if (expr.tag == E_MODULE) {
1529→            // Module body defines become globals when compiled inline
1530→            for (usz mi = 0; mi < expr.module_expr.body_count; mi++) {
1531→                if (expr.module_expr.body[mi].tag == E_DEFINE) {
1532→                    self.defined_globals.push(expr.module_expr.body[mi].define.name);
1533→                }
1534→            }
1535→        }
1536→    }
1537→
1538→    // Prescan for mutable captures (before lambda scanning)
1539→    foreach (expr : exprs) {
1540→        self.prescan_mutable_captures(expr);
1541→    }
1542→
1543→    // Emit prelude
1544→    self.emit_prelude();
1545→
1546→    // Second pass: scan all lambdas to generate definitions
1547→    foreach (expr : exprs) {
1548→        self.scan_lambdas(expr);
1549→    }
1550→
1551→    // Emit lambda struct and function definitions
1552→    self.emit_lambda_definitions();
1553→
1554→    // Emit global variable declarations for defined globals
1555→    self.emit_global_declarations();
1556→
1557→    // Emit main function
1558→    self.emit_main_start();
1559→
1560→    // Clear declared vars for main scope
1561→    self.declared_vars.free();
1562→
1563→    // Compile each top-level expression
1564→    // Find the last non-define expression index for print_last mode
1565→    isz last_non_define = -1;
1566→    if (self.print_last) {
1567→        for (usz i = 0; i < exprs.len(); i++) {
1568→            if (exprs[i].tag != E_DEFINE) {
1569→                last_non_define = (isz)i;
1570→            }
1571→        }
1572→    }
1573→
1574→    for (usz i = 0; i < exprs.len(); i++) {
1575→        bool should_print = (self.print_all && exprs[i].tag != E_DEFINE)
1576→            || (self.print_last && (isz)i == last_non_define);
1577→        if (should_print) {
1578→            // Compile to temp, then print the result
1579→            usz r = self.compile_to_temp(exprs[i]);
1580→            self.emit_indent();
1581→            self.emit("runtime::rt_print_value(");
1582→            self.emit_temp_ref(r);
1583→            self.emit("); io::printn(\"\");\n");
1584→        } else if (exprs[i].tag == E_DEFINE) {
1585→            // Define: compile init to temp, assign to global
1586→            usz init_r = self.compile_to_temp(exprs[i].define.value);
1587→            self.emit_indent();
1588→            self.emit_symbol_name(exprs[i].define.name);
1589→            self.emit(" = ");
1590→            self.emit_temp_ref(init_r);
1591→            self.emit(";\n");
1592→        } else {
1593→            // Other statements: compile to temp (discards result)
1594→            self.compile_to_temp(exprs[i]);
1595→        }
1596→    }
1597→
1598→    self.emit_main_end();
1599→
1600→    return self.get_output();
1601→}
