1603→/**
1604→ * Scan expression tree for lambdas and register them.
1605→ */
1606→fn void Compiler.scan_lambdas(Compiler* self, Expr* expr) {
1607→    List{SymbolId} empty;
1608→    self.scan_lambdas_with_scope(expr, &empty);
1609→    empty.free();
1610→}
1611→
1612→// Returns true if any E_LAMBDA was found in the subtree (replaces body_creates_closure)
1613→fn bool Compiler.scan_lambdas_with_scope(Compiler* self, Expr* expr, List{SymbolId}* enclosing_bound) {
1614→    if (expr == null) return false;
1615→
1616→    switch (expr.tag) {
1617→        case E_LAMBDA:
1618→            List{SymbolId} own_bound;
1619→            // Add all params to bound set for free-var scanning
1620→            if (expr.lambda.param_count > 1) {
1621→                for (usz pi = 0; pi < expr.lambda.param_count; pi++) {
1622→                    own_bound.push(expr.lambda.params[pi]);
1623→                }
1624→            } else if ((uint)expr.lambda.param != 0xFFFFFFFF) {
1625→                own_bound.push(expr.lambda.param);
1626→            }
1627→            // For variadic lambdas, add all fixed params + rest param to bound set
1628→            if (expr.lambda.has_rest) {
1629→                for (usz pi = 0; pi < expr.lambda.param_count; pi++) {
1630→                    own_bound.push(expr.lambda.params[pi]);
1631→                }
1632→                if ((uint)expr.lambda.rest_param != 0) {
1633→                    own_bound.push(expr.lambda.rest_param);
1634→                }
1635→            }
1636→            List{SymbolId} free;
1637→            self.find_free_vars(expr.lambda.body, &own_bound, &free, enclosing_bound);
1638→
1639→            LambdaDef def;
1640→            def.id = self.lambda_counter++;
1641→            def.param = expr.lambda.param;
1642→            def.body = expr.lambda.body;
1643→            def.capture_count = 0;
1644→            def.capture_capacity = LAMBDA_CAPTURE_INITIAL;
1645→            def.captures = (SymbolId*)mem::malloc(SymbolId.sizeof * def.capture_capacity);
1646→            // Store variadic info
1647→            def.has_rest = expr.lambda.has_rest;
1648→            def.rest_param = expr.lambda.rest_param;
1649→            def.param_count = expr.lambda.param_count;
1650→            def.param_capacity = expr.lambda.param_count < LAMBDA_CAPTURE_INITIAL ? LAMBDA_CAPTURE_INITIAL : expr.lambda.param_count;
1651→            def.params = (SymbolId*)mem::malloc(SymbolId.sizeof * def.param_capacity);
1652→            for (usz pi = 0; pi < expr.lambda.param_count; pi++) {
1653→                def.params[pi] = expr.lambda.params[pi];
1654→            }
1655→
1656→            foreach (f : free) {
1657→                if (def.capture_count >= def.capture_capacity) {
1658→                    usz new_cap = def.capture_capacity * 2;
1659→                    SymbolId* new_caps = (SymbolId*)mem::malloc(SymbolId.sizeof * new_cap);
1660→                    for (usz ci = 0; ci < def.capture_count; ci++) new_caps[ci] = def.captures[ci];
1661→                    mem::free(def.captures);
1662→                    def.captures = new_caps;
1663→                    def.capture_capacity = new_cap;
1664→                }
1665→                def.captures[def.capture_count++] = f;
1666→            }
1667→
1668→            // Recursively scan body — the return value tells us if body has nested lambdas
1669→            List{SymbolId} new_enclosing;
1670→            foreach (b : *enclosing_bound) {
1671→                new_enclosing.push(b);
1672→            }
1673→            // Add all params to enclosing scope for nested lambda free var analysis
1674→            if (expr.lambda.param_count > 1) {
1675→                for (usz pi = 0; pi < expr.lambda.param_count; pi++) {
1676→                    new_enclosing.push(expr.lambda.params[pi]);
1677→                }
1678→            } else if ((uint)expr.lambda.param != 0xFFFFFFFF) {
1679→                new_enclosing.push(expr.lambda.param);
1680→            }
1681→            if (expr.lambda.has_rest && (uint)expr.lambda.rest_param != 0) {
1682→                new_enclosing.push(expr.lambda.rest_param);
1683→            }
1684→            bool body_has_lambda = self.scan_lambdas_with_scope(expr.lambda.body, &new_enclosing);
1685→
1686→            // Set creates_closure from recursive scan (replaces body_creates_closure)
1687→            def.creates_closure = body_has_lambda;
1688→            if (def.id < 256) {
1689→                self.lambda_creates_closure[def.id] = body_has_lambda;
1690→            }
1691→
1692→            self.lambda_defs.push(def);
1693→
1694→            new_enclosing.free();
1695→            own_bound.free();
1696→            free.free();
1697→            return true;  // This node IS a lambda
1698→
1699→        case E_APP:
1700→            bool app_f = self.scan_lambdas_with_scope(expr.app.func, enclosing_bound);
1701→            return self.scan_lambdas_with_scope(expr.app.arg, enclosing_bound) || app_f;
1702→
1703→        case E_IF:
1704→            bool if_t = self.scan_lambdas_with_scope(expr.if_expr.test, enclosing_bound);
1705→            bool if_th = self.scan_lambdas_with_scope(expr.if_expr.then_branch, enclosing_bound);
1706→            return self.scan_lambdas_with_scope(expr.if_expr.else_branch, enclosing_bound) || if_t || if_th;
1707→
1708→        case E_LET:
1709→            List{SymbolId} let_scope;
1710→            foreach (b : *enclosing_bound) {
1711→                let_scope.push(b);
1712→            }
1713→            let_scope.push(expr.let_expr.name);
1714→            bool let_found;
1715→            if (expr.let_expr.is_recursive) {
1716→                let_found = self.scan_lambdas_with_scope(expr.let_expr.init, &let_scope);
1717→            } else {
1718→                let_found = self.scan_lambdas_with_scope(expr.let_expr.init, enclosing_bound);
1719→            }
1720→            bool let_body = self.scan_lambdas_with_scope(expr.let_expr.body, &let_scope);
1721→            let_scope.free();
1722→            return let_found || let_body;
1723→
1724→        case E_DEFINE:
1725→            return self.scan_lambdas_with_scope(expr.define.value, enclosing_bound);
1726→
1727→        case E_AND:
1728→            bool and_l = self.scan_lambdas_with_scope(expr.and_expr.left, enclosing_bound);
1729→            return self.scan_lambdas_with_scope(expr.and_expr.right, enclosing_bound) || and_l;
1730→
1731→        case E_OR:
1732→            bool or_l = self.scan_lambdas_with_scope(expr.or_expr.left, enclosing_bound);
1733→            return self.scan_lambdas_with_scope(expr.or_expr.right, enclosing_bound) || or_l;
1734→
1735→        case E_MATCH:
1736→            bool m_found = self.scan_lambdas_with_scope(expr.match.scrutinee, enclosing_bound);
1737→            for (usz i = 0; i < expr.match.clause_count; i++) {
1738→                m_found |= self.scan_lambdas_with_scope(expr.match.clauses[i].result, enclosing_bound);
1739→            }
1740→            return m_found;
1741→
1742→        case E_CALL:
1743→            bool c_found = self.scan_lambdas_with_scope(expr.call.func, enclosing_bound);
1744→            for (usz i = 0; i < expr.call.arg_count; i++) {
1745→                c_found |= self.scan_lambdas_with_scope(expr.call.args[i], enclosing_bound);
1746→            }
1747→            return c_found;
1748→
1749→        case E_INDEX:
1750→            bool idx_c = self.scan_lambdas_with_scope(expr.index.collection, enclosing_bound);
1751→            return self.scan_lambdas_with_scope(expr.index.index, enclosing_bound) || idx_c;
1752→
1753→        case E_PATH:
1754→            return false;
1755→
1756→        case E_RESET: {
1757→            // Wrap body as synthetic lambda: (lambda (_eff_dummy) body)
1758→            SymbolId dummy_param = self.interp.symbols.intern("_eff_dummy");
1759→            Expr* orig_body = expr.reset.body;
1760→            Expr* wrapper = self.interp.alloc_expr();
1761→            wrapper.tag = E_LAMBDA;
1762→            wrapper.lambda = (ExprLambda*)mem::malloc(ExprLambda.sizeof);
1763→            wrapper.loc_line = expr.loc_line;
1764→            wrapper.loc_column = expr.loc_column;
1765→            wrapper.lambda.param = dummy_param;
1766→            wrapper.lambda.param_count = 1;
1767→            wrapper.lambda.params = (SymbolId*)mem::malloc(SymbolId.sizeof * 1);
1768→            wrapper.lambda.params[0] = dummy_param;
1769→            wrapper.lambda.param_annotations = null;
1770→            wrapper.lambda.has_rest = false;
1771→            wrapper.lambda.rest_param = 0;
1772→            wrapper.lambda.has_typed_params = false;
1773→            wrapper.lambda.body = orig_body;
1774→            expr.reset.body = wrapper;
1775→            return self.scan_lambdas_with_scope(wrapper, enclosing_bound);
1776→        }
1777→
1778→        case E_SHIFT: {
1779→            // Wrap body as synthetic lambda: (lambda (k_name) body)
1780→            Expr* orig_body = expr.shift.body;
1781→            Expr* wrapper = self.interp.alloc_expr();
1782→            wrapper.tag = E_LAMBDA;
1783→            wrapper.lambda = (ExprLambda*)mem::malloc(ExprLambda.sizeof);
1784→            wrapper.loc_line = expr.loc_line;
1785→            wrapper.loc_column = expr.loc_column;
1786→            wrapper.lambda.param = expr.shift.k_name;
1787→            wrapper.lambda.param_count = 1;
1788→            wrapper.lambda.params = (SymbolId*)mem::malloc(SymbolId.sizeof * 1);
1789→            wrapper.lambda.params[0] = expr.shift.k_name;
1790→            wrapper.lambda.param_annotations = null;
1791→            wrapper.lambda.has_rest = false;
1792→            wrapper.lambda.rest_param = 0;
1793→            wrapper.lambda.has_typed_params = false;
1794→            wrapper.lambda.body = orig_body;
1795→            expr.shift.body = wrapper;
1796→            return self.scan_lambdas_with_scope(wrapper, enclosing_bound);
1797→        }
1798→
1799→        case E_PERFORM:

1800→            return self.scan_lambdas_with_scope(expr.perform.arg, enclosing_bound);
1801→
1802→        case E_RESOLVE:
1803→            return self.scan_lambdas_with_scope(expr.resolve.value, enclosing_bound);
1804→
1805→        case E_HANDLE: {
1806→            // Wrap body as synthetic lambda
1807→            SymbolId dummy_param = self.interp.symbols.intern("_eff_dummy");
1808→            Expr* orig_body = expr.handle.body;
1809→            Expr* body_wrapper = self.interp.alloc_expr();
1810→            body_wrapper.tag = E_LAMBDA;
1811→            body_wrapper.lambda = (ExprLambda*)mem::malloc(ExprLambda.sizeof);
1812→            body_wrapper.loc_line = expr.loc_line;
1813→            body_wrapper.loc_column = expr.loc_column;
1814→            body_wrapper.lambda.param = dummy_param;
1815→            body_wrapper.lambda.param_count = 1;
1816→            body_wrapper.lambda.params = (SymbolId*)mem::malloc(SymbolId.sizeof * 1);
1817→            body_wrapper.lambda.params[0] = dummy_param;
1818→            body_wrapper.lambda.param_annotations = null;
1819→            body_wrapper.lambda.has_rest = false;
1820→            body_wrapper.lambda.rest_param = 0;
1821→            body_wrapper.lambda.has_typed_params = false;
1822→            body_wrapper.lambda.body = orig_body;
1823→            expr.handle.body = body_wrapper;
1824→            bool h_found = self.scan_lambdas_with_scope(body_wrapper, enclosing_bound);
1825→
1826→            // Wrap each handler clause as synthetic lambda: (lambda (_pair) (let (k (car _pair)) (let (arg (cdr _pair)) body)))
1827→            SymbolId pair_param = self.interp.symbols.intern("_eff_pair");
1828→            SymbolId sym_car = self.interp.symbols.intern("car");
1829→            SymbolId sym_cdr = self.interp.symbols.intern("cdr");
1830→            for (usz i = 0; i < expr.handle.clause_count; i++) {
1831→                Expr* orig_handler = expr.handle.clauses[i].handler_body;
1832→                SymbolId k_name = expr.handle.clauses[i].k_name;
1833→                SymbolId arg_name = expr.handle.clauses[i].arg_name;
1834→
1835→                // Build (cdr _pair) for arg extraction
1836→                Expr* pair_ref2 = self.interp.alloc_expr();
1837→                pair_ref2.tag = E_VAR;
1838→                pair_ref2.var_expr.name = pair_param;
1839→                Expr* cdr_fn = self.interp.alloc_expr();
1840→                cdr_fn.tag = E_VAR;
1841→                cdr_fn.var_expr.name = sym_cdr;
1842→                Expr* cdr_call = self.interp.alloc_expr();
1843→                cdr_call.tag = E_APP;
1844→                cdr_call.app.func = cdr_fn;
1845→                cdr_call.app.arg = pair_ref2;
1846→
1847→                // Build: (let (arg_name (cdr _pair)) orig_handler)
1848→                Expr* let_arg = self.interp.alloc_expr();
1849→                let_arg.tag = E_LET;
1850→                let_arg.let_expr.name = arg_name;
1851→                let_arg.let_expr.init = cdr_call;
1852→                let_arg.let_expr.body = orig_handler;
1853→                let_arg.let_expr.is_recursive = false;
1854→
1855→                // Build (car _pair) for k extraction
1856→                Expr* pair_ref1 = self.interp.alloc_expr();
1857→                pair_ref1.tag = E_VAR;
1858→                pair_ref1.var_expr.name = pair_param;
1859→                Expr* car_fn = self.interp.alloc_expr();
1860→                car_fn.tag = E_VAR;
1861→                car_fn.var_expr.name = sym_car;
1862→                Expr* car_call = self.interp.alloc_expr();
1863→                car_call.tag = E_APP;
1864→                car_call.app.func = car_fn;
1865→                car_call.app.arg = pair_ref1;
1866→
1867→                // Build: (let (k_name (car _pair)) (let (arg_name ...) ...))
1868→                Expr* let_k = self.interp.alloc_expr();
1869→                let_k.tag = E_LET;
1870→                let_k.let_expr.name = k_name;
1871→                let_k.let_expr.init = car_call;
1872→                let_k.let_expr.body = let_arg;
1873→                let_k.let_expr.is_recursive = false;
1874→
1875→                // Lambda wrapper: (lambda (_pair) (let (k ...) (let (arg ...) body)))
1876→                Expr* handler_wrapper = self.interp.alloc_expr();
1877→                handler_wrapper.tag = E_LAMBDA;
1878→                handler_wrapper.lambda = (ExprLambda*)mem::malloc(ExprLambda.sizeof);
1879→                handler_wrapper.loc_line = expr.loc_line;
1880→                handler_wrapper.loc_column = expr.loc_column;
1881→                handler_wrapper.lambda.param = pair_param;
1882→                handler_wrapper.lambda.param_count = 1;
1883→                handler_wrapper.lambda.params = (SymbolId*)mem::malloc(SymbolId.sizeof * 1);
1884→                handler_wrapper.lambda.params[0] = pair_param;
1885→                handler_wrapper.lambda.param_annotations = null;
1886→                handler_wrapper.lambda.has_rest = false;
1887→                handler_wrapper.lambda.rest_param = 0;
1888→                handler_wrapper.lambda.has_typed_params = false;
1889→                handler_wrapper.lambda.body = let_k;
1890→                expr.handle.clauses[i].handler_body = handler_wrapper;
1891→                h_found |= self.scan_lambdas_with_scope(handler_wrapper, enclosing_bound);
1892→            }
1893→            return h_found;
1894→        }
1895→
1896→        case E_BEGIN:
1897→            bool b_found = false;
1898→            for (usz i = 0; i < expr.begin.expr_count; i++) {
1899→                b_found |= self.scan_lambdas_with_scope(expr.begin.exprs[i], enclosing_bound);
1900→            }
1901→            return b_found;
1902→
1903→        case E_SET:
1904→            return self.scan_lambdas_with_scope(expr.set_expr.value, enclosing_bound);
1905→
1906→        case E_QUASIQUOTE:
1907→            return self.scan_lambdas_with_scope(expr.quasiquote.body, enclosing_bound);
1908→
1909→        case E_UNQUOTE:
1910→            return self.scan_lambdas_with_scope(expr.unquote.body, enclosing_bound);
1911→
1912→        case E_UNQUOTE_SPLICING:
1913→            return self.scan_lambdas_with_scope(expr.unquote_splicing.body, enclosing_bound);
1914→
1915→        case E_DEFMACRO:
1916→            return false;
1917→
1918→        case E_MODULE:
1919→            bool mod_found = false;
1920→            for (usz i = 0; i < expr.module_expr.body_count; i++) {
1921→                List{SymbolId} mod_empty;
1922→                mod_found |= self.scan_lambdas_with_scope(expr.module_expr.body[i], &mod_empty);
1923→                mod_empty.free();
1924→            }
1925→            return mod_found;
1926→
1927→        case E_IMPORT:
1928→        case E_EXPORT_FROM:
1929→            return false;
1930→
1931→        default:
1932→            return false;
1933→    }
1934→}
