1948→fn void Compiler.emit_lambda_definitions(Compiler* self) {
1949→    // Emit struct definitions for closures with captures
1950→    foreach (def : self.lambda_defs) {
1951→        if (def.capture_count > 0) {
1952→            self.emit("struct Lambda_");
1953→            self.emit_usz(def.id);
1954→            self.emit(" {\n");
1955→
1956→            // Add home_region for region tracking
1957→            self.emit("    main::RegionHandle home_region;\n");
1958→
1959→            for (usz i = 0; i < def.capture_count; i++) {
1960→                self.emit("    runtime::Value captured_");
1961→                self.emit_symbol_name(def.captures[i]);
1962→                self.emit(";\n");
1963→            }
1964→
1965→            self.emit("}\n\n");
1966→        }
1967→    }
1968→
1969→    // Emit function definitions for lambdas
1970→    foreach (def : self.lambda_defs) {
1971→        // Check if this is a zero-arg lambda (sentinel param)
1972→        bool is_zero_arg = (uint)def.param == 0xFFFFFFFF;
1973→
1974→        self.emit("fn runtime::Value invoke_lambda_");
1975→        self.emit_usz(def.id);
1976→
1977→        if (def.has_rest || (def.param_count > 1)) {
1978→            // Variadic or multi-param lambda: receives all args as a cons list
1979→            self.emit("(void* _self, runtime::Value _arg_list) {\n");
1980→        } else if (is_zero_arg) {
1981→            self.emit("(void* _self, runtime::Value _unused) {\n");
1982→        } else {
1983→            self.emit("(void* _self, runtime::Value ");
1984→            self.emit_symbol_name(def.param);
1985→            self.emit(") {\n");
1986→        }
1987→
1988→        self.indent++;
1989→
1990→        // Clear declared vars for this function scope
1991→        self.declared_vars.free();
1992→
1993→        if (def.has_rest || (def.param_count > 1 && !def.has_rest)) {
1994→            // Variadic or multi-param: unpack params from arg list
1995→            self.emit_indent();
1996→            self.emit("runtime::Value _curr = _arg_list;\n");
1997→            for (usz pi = 0; pi < def.param_count; pi++) {
1998→                self.mark_declared(def.params[pi]);
1999→                self.emit_indent();
2000→                self.emit("runtime::Value ");
2001→                self.emit_symbol_name(def.params[pi]);
2002→                self.emit(" = runtime::rt_car1(_curr);\n");
2003→                self.emit_indent();
2004→                self.emit("_curr = runtime::rt_cdr1(_curr);\n");
2005→            }
2006→            if (def.has_rest) {
2007→                // Rest param gets remaining list
2008→                self.mark_declared(def.rest_param);
2009→                self.emit_indent();
2010→                self.emit("runtime::Value ");
2011→                self.emit_symbol_name(def.rest_param);
2012→                self.emit(" = _curr;\n");
2013→            }
2014→        } else {
2015→            // Mark parameter as declared
2016→            if (!is_zero_arg) {
2017→                self.mark_declared(def.param);
2018→            }
2019→        }
2020→
2021→        // If this lambda creates closures, push a frame region
2022→        if (def.creates_closure) {
2023→            self.emit_indent();
2024→            self.emit("main::RegionHandle _frame = runtime::rt_push_frame();\n");
2025→        }
2026→
2027→        // Extract captures if any
2028→        if (def.capture_count > 0) {
2029→            self.emit_indent();
2030→            self.emit("Lambda_");
2031→            self.emit_usz(def.id);
2032→            self.emit("* self = (Lambda_");
2033→            self.emit_usz(def.id);
2034→            self.emit("*)_self;\n");
2035→
2036→            for (usz i = 0; i < def.capture_count; i++) {
2037→                self.mark_declared(def.captures[i]);
2038→                self.emit_indent();
2039→                self.emit("runtime::Value ");
2040→                self.emit_symbol_name(def.captures[i]);
2041→                self.emit(" = self.captured_");
2042→                self.emit_symbol_name(def.captures[i]);
2043→                self.emit(";\n");
2044→            }
2045→        }
2046→
2047→        // Compile body and return using statement-level compilation
2048→        if (def.body.tag == E_LAMBDA) {
2049→            self.emit_lambda_return_with_frame(def.body, def.creates_closure);
2050→        } else {
2051→            usz body_r = self.compile_to_temp_tail(def.body);
2052→            if (def.creates_closure) {
2053→                self.emit_indent();
2054→                self.emit("runtime::rt_pop_frame(_frame);\n");
2055→            }
2056→            self.emit_indent();
2057→            self.emit("return ");
2058→            self.emit_temp_ref(body_r);
2059→            self.emit(";\n");
2060→        }
2061→
2062→        self.indent--;
2063→        self.emit("}\n\n");
2064→    }
2065→}
