1319→ * Convenience function to apply write barrier when capturing a value in a closure.
1320→ *
1321→ * @param closure_region The region where the closure lives
1322→ * @param captured The Value being captured
1323→ */
1324→fn void rt_capture_value(main::RegionHandle closure_region, Value captured) {
1325→    rt_write_barrier_value(closure_region.region_id, captured);
