1332→fn Value rt_string_append(Value a, Value b) {
1333→    if (a.tag != V_STRING || b.tag != V_STRING) return make_nil();
1334→    StringData* sa = main::dereference_as(StringData, a.str_handle);
1335→    StringData* sb = main::dereference_as(StringData, b.str_handle);
1336→
1337→    StringData result;
1338→    usz total = sa.len + sb.len;
1339→    if (total > 4095) total = 4095;
1340→    usz i = 0;
1341→    for (usz j = 0; j < sa.len && i < 4095; j++) {
1342→        result.chars[i++] = sa.chars[j];
1343→    }
1344→    for (usz j = 0; j < sb.len && i < 4095; j++) {
1345→        result.chars[i++] = sb.chars[j];
1346→    }
1347→    result.chars[i] = 0;
1348→    result.len = i;
1349→
1350→    Value v;
1351→    v.tag = V_STRING;
1352→    v.str_handle = main::allocate_in(g_current_region, StringData, result);
1353→    return v;
1354→}
