1356→fn Value rt_string_join(Value sep, Value lst) {
1357→    if (sep.tag != V_STRING) return make_nil();
1358→    StringData* sep_str = main::dereference_as(StringData, sep.str_handle);
1359→
1360→    StringData result;
1361→    usz pos = 0;
1362→    bool first = true;
1363→    Value current = lst;
1364→
1365→    while (current.tag == V_CONS) {
1366→        if (!first && pos + sep_str.len < 255) {
1367→            for (usz i = 0; i < sep_str.len && pos < 4095; i++) {
1368→                result.chars[pos++] = sep_str.chars[i];
1369→            }
1370→        }
1371→        first = false;
1372→
1373→        Value* elem = main::dereference_as(Value, current.cons_val.car);
1374→        if (elem.tag == V_STRING) {
1375→            StringData* s = main::dereference_as(StringData, elem.str_handle);
1376→            for (usz i = 0; i < s.len && pos < 4095; i++) {
1377→                result.chars[pos++] = s.chars[i];
1378→            }
1379→        }
1380→
1381→        Value* next = main::dereference_as(Value, current.cons_val.cdr);
1382→        current = *next;
1383→    }
1384→
1385→    result.chars[pos] = 0;
1386→    result.len = pos;
1387→
1388→    Value v;
1389→    v.tag = V_STRING;
1390→    v.str_handle = main::allocate_in(g_current_region, StringData, result);
1391→    return v;
1392→}
