 887→/**
 888→ * raise_error — Recoverable error via algebraic effect system.
 889→ *
 890→ * If a `raise` handler is on the handler stack, sets raise_pending flag and
 891→ * returns V_ERROR for stack unwinding. If no handler, falls back to V_ERROR
 892→ * (same as make_error).
 893→ *
 894→ * Use make_error() for fatal/internal errors only (stack overflow, invariants).
 895→ */
 896→fn Value* raise_error(Interp* interp, char[] msg) {
 897→    // Fast path: no handlers at all → just return error
 898→    if (interp.handler_count == 0) {
 899→        return make_error(interp, msg);
 900→    }
 901→
 902→    // If a raise is already pending, don't overwrite it (error re-propagation)
 903→    if (interp.flags.raise_pending) {
 904→        return make_error(interp, msg);
 905→    }
 906→
 907→    SymbolId raise_sym = interp.sym_raise;
 908→
 909→    // Search handler stack from top (most recent) to bottom
 910→    for (isz i = (isz)interp.handler_count - 1; i >= 0; i--) {
 911→        EffectHandler* h = &interp.handler_stack[(usz)i];
 912→
 913→        for (usz j = 0; j < h.clause_count; j++) {
 914→            if ((uint)h.clauses[j].effect_tag == (uint)raise_sym) {
 915→                // Found a raise handler — set pending flag for jit_handle_impl to dispatch.
 916→                // We can't safely call jit_eval from within a primitive call chain,
 917→                // so we store the message and let the handle block dispatch.
 918→                interp.flags.raise_pending = true;
 919→                usz copy_len = msg.len;
 920→                if (copy_len > 255) copy_len = 255;
 921→                for (usz ci = 0; ci < copy_len; ci++) interp.raise_msg[ci] = msg[ci];
 922→                interp.raise_msg[copy_len] = 0;
 923→                interp.raise_msg_len = copy_len;
 924→                return make_error(interp, msg);
 925→            }
 926→        }
 927→
 928→        if (h.strict_mode) break;
 929→    }
 930→
 931→    // No raise handler found — fall back to V_ERROR
 932→    return make_error(interp, msg);
 933→}
