 88→/**
 89→ * EvalError - Error result from evaluation.
 90→ */
 91→struct EvalError {
 92→    bool        has_error;
 93→    char[256]   message;
 94→    usz         line;     // Source line where error occurred (0 if unknown)
 95→    usz         column;   // Source column where error occurred (0 if unknown)
 96→}
