104→}
105→
106→fn EvalResult eval_ok(Value* v) @inline {
107→    return { .value = v, .error = { .has_error = false } };
108→}
109→
110→fn EvalResult eval_error(char[] msg) {
111→    EvalResult r;
112→    r.value = null;
113→    r.error.has_error = true;
114→    r.error.line = 0;
115→    r.error.column = 0;
116→    usz len = msg.len;
117→    if (len > 255) len = 255;
118→    for (usz i = 0; i < len; i++) {
119→        r.error.message[i] = msg[i];
120→    }
121→    r.error.message[len] = 0;
122→    return r;
123→}
124→
125→/**
126→ * Create an error with source location from an expression.
127→ */
128→fn EvalResult eval_error_expr(char[] msg, Expr* expr) {
129→    EvalResult r;
130→    r.value = null;
131→    r.error.has_error = true;
132→    if (expr != null) {
133→        r.error.line = expr.loc_line;
134→        r.error.column = expr.loc_column;
135→    } else {
136→        r.error.line = 0;
137→        r.error.column = 0;
138→    }
139→    usz len = msg.len;
140→    if (len > 255) len = 255;
141→    for (usz i = 0; i < len; i++) {
142→        r.error.message[i] = msg[i];
143→    }
144→    r.error.message[len] = 0;
145→    return r;
