154→/**
155→ * Find the best matching method in a method table for the given args.
156→ * Scoring: Val match (1000) > exact type (100) > subtype (10) > any (1)
157→ */
158→fn Value* find_best_method(MethodTable* mt, Value*[] args, Interp* interp) {
159→    long best_score = -1;
160→    Value* best_method = null;
161→    usz best_count = 0;
162→
163→    // Pre-compute arg TypeIds once (avoid repeated infer_value_type calls)
164→    TypeId[8] arg_types;
165→    usz arg_count = args.len;
166→    if (arg_count > 8) { arg_count = 8; }
167→    for (usz a = 0; a < arg_count; a++) {
168→        arg_types[a] = infer_value_type(args[a], interp);
169→    }
170→
171→    for (usz i = 0; i < mt.entry_count; i++) {
172→        MethodEntry* entry = &mt.entries[i];
173→
174→        // Check arity
175→        if (entry.sig.param_count != args.len) continue;
176→
177→        long score = 0;
178→        bool matches = true;
179→
180→        for (usz j = 0; j < arg_count && j < entry.sig.param_count; j++) {
181→            TypeId expected = entry.sig.param_types[j];
182→
183→            // Check Val literal match FIRST (before any-type escape)
184→            if (entry.sig.has_val_literal[j]) {
185→                if (args[j] != null && args[j].tag == INT && args[j].int_val == entry.sig.val_literals[j]) {
186→                    score += 1000;  // Val match is strongest
187→                    continue;
188→                }
189→                matches = false;
190→                break;
191→            }
192→
193→            if (expected == INVALID_TYPE_ID) {
194→                // Any type — weak match
195→                score += 1;
196→                continue;
197→            }
198→
199→            TypeId actual = arg_types[j];
200→            if (actual == INVALID_TYPE_ID) {
201→                matches = false;
202→                break;
203→            }
204→
205→            if (actual == expected) {
206→                score += 100;  // Exact match
207→            } else if (interp.types.is_subtype(actual, expected)) {
208→                score += 10;   // Subtype match
209→            } else {
210→                matches = false;
211→                break;
212→            }
213→        }
214→
215→        // Enforce type constraints (e.g., ^{'T Number} requires arg's type <: Number)
216→        if (matches && entry.sig.constraint_count > 0) {
217→            for (usz c = 0; c < entry.sig.constraint_count; c++) {
218→                TypeId bound = entry.sig.constraints[c].bound_type;
219→                if (bound == INVALID_TYPE_ID) continue;  // unresolved bound — skip
220→
221→                // The constraint applies to the param with dict annotation.
222→                // Find which arg position has the constrained type variable.
223→                // For now: check ALL args against the bound — if any arg's type
224→                // is not a subtype of the bound, the constraint fails.
225→                // More precise: match param_sym to the annotation on a specific position.
226→                // We use a simple heuristic: scan for the arg position that has
227→                // INVALID_TYPE_ID param_type (the dict-annotated one)
228→                bool constraint_satisfied = false;
229→                for (usz p = 0; p < arg_count && p < entry.sig.param_count; p++) {
230→                    if (entry.sig.param_types[p] == INVALID_TYPE_ID && !entry.sig.has_val_literal[p]) {
231→                        TypeId actual = arg_types[p];
232→                        if (actual != INVALID_TYPE_ID &&
233→                            (interp.types.is_subtype(actual, bound))) {
234→                            constraint_satisfied = true;
235→                            break;
236→                        }
237→                    }
238→                }
239→                if (!constraint_satisfied) {
240→                    matches = false;
241→                    break;
242→                }
243→            }
244→        }
245→
246→        if (matches && score > best_score) {
247→            best_score = score;
248→            best_method = entry.implementation;
249→            best_count = 1;
250→        } else if (matches && score == best_score) {
251→            best_count++;
252→        }
253→    }
254→
255→    if (best_count > 1) {
256→        return raise_error(interp, "ambiguous method call: multiple methods match with equal specificity");
257→    }
258→
259→    return best_method;
260→}
