2272→fn void Compiler.compile_statement(Compiler* self, Expr* expr) {
2273→    if (expr == null) return;
2274→
2275→    switch (expr.tag) {
2276→        case E_DEFINE:
2277→            // (define name value) => name = <compile value>;
2278→            usz init_r = self.compile_to_temp(expr.define.value);
2279→            self.emit_indent();
2280→            self.emit_symbol_name(expr.define.name);
2281→            self.emit(" = ");
2282→            self.emit_temp_ref(init_r);
2283→            self.emit(";\n");
2284→
2285→        default:
2286→            // Other expressions: evaluate and discard result
2287→            self.compile_to_temp(expr);
2288→    }
2289→}
