2295→fn void Compiler.compile_expr(Compiler* self, Expr* expr) {
2296→    if (expr == null) {
2297→        self.emit("runtime::make_nil()");
2298→        return;
2299→    }
2300→
2301→    switch (expr.tag) {
2302→        case E_LIT:
2303→            self.compile_literal(expr.lit.value);
2304→
2305→        case E_VAR:
2306→            self.compile_var(expr);
2307→
2308→        case E_DEFINE:
2309→            // Define in expression context
2310→            self.emit("(");
2311→            self.emit_symbol_name(expr.define.name);
2312→            self.emit(" = ");
2313→            self.compile_expr(expr.define.value);
2314→            self.emit(")");
2315→
2316→        case E_QUOTE:
2317→            self.compile_quote(expr.quote.datum);
2318→
2319→        case E_PATH:
2320→            self.compile_path(expr);
2321→
2322→        default:
2323→            io::printfn("WARNING: compiler: unsupported expr tag %d", expr.tag.ordinal);
2324→            self.emit("runtime::make_nil() /* WARNING: unsupported expr type */");
