2353→/**
2354→ * Compile an expression as statements, storing result in _rN.
2355→ * Returns N. All temp declarations are emitted as proper C3 statements.
2356→ */
2357→fn usz Compiler.compile_to_temp(Compiler* self, Expr* expr) {
2358→    if (expr == null) {
2359→        usz id = self.next_result();
2360→        self.emit_temp_decl(id);
2361→        self.emit(" = runtime::make_nil();\n");
2362→        return id;
2363→    }
2364→
2365→    switch (expr.tag) {
2366→        case E_CALL:
2367→            return self.compile_call_flat(expr);
2368→
2369→        case E_LET:
2370→            return self.compile_let_flat(expr);
2371→
2372→        case E_AND:
2373→            return self.compile_and_flat(expr);
2374→
2375→        case E_OR:
2376→            return self.compile_or_flat(expr);
2377→
2378→        case E_BEGIN:
2379→            return self.compile_begin_flat(expr);
2380→
2381→        case E_SET:
2382→            return self.compile_set_flat(expr);
2383→
2384→        case E_RESET:
2385→            return self.compile_reset_flat(expr);
2386→
2387→        case E_SHIFT:
2388→            return self.compile_shift_flat(expr);
2389→
2390→        case E_PERFORM:
2391→            return self.compile_perform_flat(expr);
2392→
2393→        case E_RESOLVE: {
2394→            // Compile value, then call rt_compiled_resolve
2395→            usz val_r = self.compile_to_temp(expr.resolve.value);
2396→            usz id = self.next_result();
2397→            self.emit_temp_decl(id);
2398→            self.emit(" = runtime::rt_compiled_resolve(");
2399→            self.emit_temp_ref(val_r);

2400→            self.emit(");\n");
2401→            return id;
2402→        }
2403→
2404→        case E_HANDLE:
2405→            return self.compile_handle_flat(expr);
2406→
2407→        case E_QUASIQUOTE:
2408→            return self.compile_qq_flat(expr.quasiquote.body, 0);
2409→
2410→        case E_DEFMACRO:
2411→            // Macros expanded at compile time — no-op at runtime
2412→            usz defmacro_id = self.next_result();
2413→            self.emit_temp_decl(defmacro_id);
2414→            self.emit(" = runtime::make_nil(); // macro: expanded at compile time\n");
2415→            return defmacro_id;
2416→
2417→        case E_MODULE:
2418→            return self.compile_module_flat(expr);
2419→
2420→        case E_IMPORT:
2421→            return self.compile_import_flat(expr);
2422→
2423→        case E_EXPORT_FROM:
2424→            return self.compile_export_from_flat(expr);
2425→
2426→        case E_IF:
2427→            return self.compile_if_flat(expr);
2428→
2429→        case E_APP:
2430→            return self.compile_app_flat(expr);
2431→
2432→        case E_LAMBDA:
2433→            return self.compile_lambda_flat(expr);
2434→
2435→        case E_MATCH:
2436→            return self.compile_match_flat(expr);
2437→
2438→        case E_INDEX:
2439→            usz idx_coll_r = self.compile_to_temp(expr.index.collection);
2440→            usz idx_idx_r = self.compile_to_temp(expr.index.index);
2441→            usz idx_id = self.next_result();
2442→            self.emit_temp_decl(idx_id);
2443→            self.emit(" = runtime::rt_index(");
2444→            self.emit_temp_ref(idx_coll_r);
2445→            self.emit(", ");
2446→            self.emit_temp_ref(idx_idx_r);
2447→            self.emit(");\n");
2448→            return idx_id;
2449→
2450→        case E_DEFINE:
2451→            usz def_val_r = self.compile_to_temp(expr.define.value);
2452→            self.emit_indent();
2453→            self.emit_symbol_name(expr.define.name);
2454→            self.emit(" = ");
2455→            self.emit_temp_ref(def_val_r);
2456→            self.emit(";\n");
2457→            return def_val_r;
2458→
2459→        default:
2460→            // Leaf expressions (E_LIT, E_VAR, E_QUOTE, E_PATH):
2461→            // compile_expr produces inline code without ({ }) or recursion
2462→            usz id = self.next_result();
2463→            self.emit_temp_decl(id);
2464→            self.emit(" = ");
2465→            self.compile_expr(expr);
2466→            self.emit(";\n");
2467→            return id;
2468→    }
2469→}
