2471→/**
2472→ * compile_to_temp for tail position. For calls, emits make_thunk instead of rt_invoke.
2473→ */
2474→fn usz Compiler.compile_to_temp_tail(Compiler* self, Expr* expr) {
2475→    if (expr == null) {
2476→        usz id = self.next_result();
2477→        self.emit_temp_decl(id);
2478→        self.emit(" = runtime::make_nil();\n");
2479→        return id;
2480→    }
2481→
2482→    switch (expr.tag) {
2483→        case E_APP:
2484→            return self.compile_app_tail_flat(expr);
2485→
2486→        case E_CALL:
2487→            return self.compile_call_tail_flat(expr);
2488→
2489→        case E_IF:
2490→            // Propagate tail to branches
2491→            usz cond = self.compile_to_temp(expr.if_expr.test);
2492→            usz id = self.next_result();
2493→            self.emit_temp_decl(id);
2494→            self.emit(";\n");
2495→            self.emit_indent();
2496→            self.emit("if (runtime::rt_is_truthy(");
2497→            self.emit_temp_ref(cond);
2498→            self.emit(")) {\n");
2499→            self.indent++;
2500→            usz then_r = self.compile_to_temp_tail(expr.if_expr.then_branch);
2501→            self.emit_indent();
2502→            self.emit_temp_ref(id);
2503→            self.emit(" = ");
