2605→fn usz Compiler.compile_call_flat(Compiler* self, Expr* expr) {
2606→    usz arg_count = expr.call.arg_count;
2607→
2608→    // Special case: (dict ...) is variadic — use rt_dict_from_args directly
2609→    // Special case: (list ...) is variadic — build cons chain directly
2610→    if (expr.call.func.tag == E_VAR) {
2611→        char[] fname = self.interp.symbols.get_name(expr.call.func.var_expr.name);
2612→        if (self.str_eq(fname, "dict")) {
2613→            if (arg_count == 0) {
2614→                usz id = self.next_result();
2615→                self.emit_temp_decl(id);
2616→                self.emit(" = runtime::rt_dict_from_args(runtime::make_nil());\n");
2617→                return id;
2618→            }
2619→            // Compile args and build cons list
2620→            usz[32] arg_temps;
2621→            for (usz i = 0; i < arg_count && i < 32; i++) {
2622→                arg_temps[i] = self.compile_to_temp(expr.call.args[i]);
2623→            }
2624→            usz args_list = self.next_result();
2625→            self.emit_temp_decl(args_list);
2626→            self.emit(" = runtime::make_nil();\n");
2627→            for (isz i = (isz)arg_count - 1; i >= 0; i--) {
2628→                self.emit_indent();
2629→                self.emit_temp_ref(args_list);
2630→                self.emit(" = runtime::rt_cons(");
2631→                self.emit_temp_ref(arg_temps[(usz)i]);
2632→                self.emit(", ");
2633→                self.emit_temp_ref(args_list);
2634→                self.emit(");\n");
2635→            }
2636→            usz id = self.next_result();
2637→            self.emit_temp_decl(id);
2638→            self.emit(" = runtime::rt_dict_from_args(");
2639→            self.emit_temp_ref(args_list);
2640→            self.emit(");\n");
2641→            return id;
2642→        }
2643→        if (self.str_eq(fname, "list")) {
2644→            // list is variadic: (list a b c) → cons chain (a b c)
2645→            if (arg_count == 0) {
2646→                usz id = self.next_result();
2647→                self.emit_temp_decl(id);
2648→                self.emit(" = runtime::make_nil();\n");
2649→                return id;
2650→            }
2651→            usz[32] arg_temps;
2652→            for (usz i = 0; i < arg_count && i < 32; i++) {
2653→                arg_temps[i] = self.compile_to_temp(expr.call.args[i]);
2654→            }
2655→            usz result_r = self.next_result();
2656→            self.emit_temp_decl(result_r);
2657→            self.emit(" = runtime::make_nil();\n");
2658→            for (isz i = (isz)arg_count - 1; i >= 0; i--) {
2659→                self.emit_indent();
2660→                self.emit_temp_ref(result_r);
2661→                self.emit(" = runtime::rt_cons(");
2662→                self.emit_temp_ref(arg_temps[(usz)i]);
2663→                self.emit(", ");
2664→                self.emit_temp_ref(result_r);
2665→                self.emit(");\n");
2666→            }
2667→            return result_r;
2668→        }
2669→    }
2670→
2671→    if (arg_count == 0) {
2672→        usz func_r = self.compile_to_temp(expr.call.func);
2673→        usz id = self.next_result();
2674→        self.emit_temp_decl(id);
2675→        self.emit(" = runtime::rt_invoke(");
2676→        self.emit_temp_ref(func_r);
2677→        self.emit(", runtime::make_nil());\n");
2678→        return id;
2679→    }
2680→
2681→    // Compile each arg to a temp
2682→    usz[32] arg_temps;
2683→    for (usz i = 0; i < arg_count && i < 32; i++) {
2684→        arg_temps[i] = self.compile_to_temp(expr.call.args[i]);
2685→    }
2686→
2687→    // Compile func to temp
2688→    usz func_r = self.compile_to_temp(expr.call.func);
2689→
2690→    // Build cons list of args for rt_apply_multi (handles variadic + non-variadic)
2691→    usz args_list = self.next_result();
2692→    self.emit_temp_decl(args_list);
2693→    self.emit(" = runtime::make_nil();\n");
2694→    for (isz i = (isz)arg_count - 1; i >= 0; i--) {
2695→        self.emit_indent();
2696→        self.emit_temp_ref(args_list);
2697→        self.emit(" = runtime::rt_cons(");
2698→        self.emit_temp_ref(arg_temps[(usz)i]);
2699→        self.emit(", ");

2700→        self.emit_temp_ref(args_list);
2701→        self.emit(");\n");
2702→    }
2703→
2704→    usz id = self.next_result();
2705→    self.emit_temp_decl(id);
2706→    self.emit(" = runtime::rt_apply_multi(");
2707→    self.emit_temp_ref(func_r);
2708→    self.emit(", ");
2709→    self.emit_temp_ref(args_list);
2710→    self.emit(", ");
2711→    self.emit_usz(arg_count);
2712→    self.emit(");\n");
2713→    return id;
2714→}
