2716→fn usz Compiler.compile_call_tail_flat(Compiler* self, Expr* expr) {
2717→    usz arg_count = expr.call.arg_count;
2718→
2719→    // Special cases: list/dict build data structures, delegate to non-tail version
2720→    if (expr.call.func.tag == E_VAR) {
2721→        char[] fname = self.interp.symbols.get_name(expr.call.func.var_expr.name);
2722→        if (self.str_eq(fname, "list") || self.str_eq(fname, "dict")) {
2723→            return self.compile_call_flat(expr);
2724→        }
2725→    }
2726→
2727→    if (arg_count == 0) {
2728→        usz func_r = self.compile_to_temp(expr.call.func);
2729→        usz id = self.next_result();
2730→        self.emit_temp_decl(id);
2731→        self.emit(";\n");
2732→        self.emit_indent();
2733→        self.emit("if (");
2734→        self.emit_temp_ref(func_r);
2735→        self.emit(".tag == runtime::ValueTag.V_CLOSURE) {\n");
2736→        self.indent++;
2737→        self.emit_indent();
2738→        self.emit_temp_ref(id);
2739→        self.emit(" = runtime::make_thunk(");
2740→        self.emit_temp_ref(func_r);
2741→        self.emit(".closure_val.invoke, ");
2742→        self.emit_temp_ref(func_r);
2743→        self.emit(".closure_val.data, runtime::make_nil());\n");
2744→        self.indent--;
2745→        self.emit_indent();
2746→        self.emit("} else {\n");
2747→        self.indent++;
2748→        self.emit_indent();
2749→        self.emit_temp_ref(id);
2750→        self.emit(" = runtime::rt_invoke_once(");
2751→        self.emit_temp_ref(func_r);
2752→        self.emit(", runtime::make_nil());\n");
2753→        self.indent--;
2754→        self.emit_indent();
2755→        self.emit("}\n");
2756→        return id;
2757→    }
2758→
2759→    // Compile each arg to a temp
2760→    usz[32] arg_temps;
2761→    for (usz i = 0; i < arg_count && i < 32; i++) {
2762→        arg_temps[i] = self.compile_to_temp(expr.call.args[i]);
2763→    }
2764→
2765→    // Compile func
2766→    usz func_r = self.compile_to_temp(expr.call.func);
2767→
2768→    // Build cons list of args (needed for variadic path)
2769→    usz args_list = self.next_result();
2770→    self.emit_temp_decl(args_list);
2771→    self.emit(" = runtime::make_nil();\n");
2772→    for (isz i = (isz)arg_count - 1; i >= 0; i--) {
2773→        self.emit_indent();
2774→        self.emit_temp_ref(args_list);
2775→        self.emit(" = runtime::rt_cons(");
2776→        self.emit_temp_ref(arg_temps[(usz)i]);
2777→        self.emit(", ");
2778→        self.emit_temp_ref(args_list);
2779→        self.emit(");\n");
2780→    }
2781→
2782→    usz id = self.next_result();
2783→    self.emit_temp_decl(id);
2784→    self.emit(";\n");
2785→
2786→    // Variadic closure: make_thunk with full arg list (preserves TCO)
2787→    self.emit_indent();
2788→    self.emit("if (");
2789→    self.emit_temp_ref(func_r);
2790→    self.emit(".tag == runtime::ValueTag.V_CLOSURE && ");
2791→    self.emit_temp_ref(func_r);
2792→    self.emit(".closure_val.is_variadic) {\n");
2793→    self.indent++;
2794→    self.emit_indent();
2795→    self.emit_temp_ref(id);
2796→    self.emit(" = runtime::make_thunk(");
2797→    self.emit_temp_ref(func_r);
2798→    self.emit(".closure_val.invoke, ");
2799→    self.emit_temp_ref(func_r);
2800→    self.emit(".closure_val.data, ");
2801→    self.emit_temp_ref(args_list);
2802→    self.emit(");\n");
2803→    self.indent--;
2804→    self.emit_indent();
2805→    self.emit("} else {\n");
2806→    self.indent++;
2807→
2808→    // Non-variadic: curry one at a time; last arg is tail position (thunk)
2809→    usz tf = func_r;
2810→    for (usz i = 0; i < arg_count; i++) {
2811→        if (i == arg_count - 1) {
2812→            self.emit_indent();
2813→            self.emit("if (");
2814→            self.emit_temp_ref(tf);
2815→            self.emit(".tag == runtime::ValueTag.V_CLOSURE) {\n");
2816→            self.indent++;
2817→            self.emit_indent();
2818→            self.emit_temp_ref(id);
2819→            self.emit(" = runtime::make_thunk(");
2820→            self.emit_temp_ref(tf);
2821→            self.emit(".closure_val.invoke, ");
2822→            self.emit_temp_ref(tf);
2823→            self.emit(".closure_val.data, ");
2824→            self.emit_temp_ref(arg_temps[i]);
2825→            self.emit(");\n");
2826→            self.indent--;
2827→            self.emit_indent();
2828→            self.emit("} else {\n");
2829→            self.indent++;
2830→            self.emit_indent();
2831→            self.emit_temp_ref(id);
2832→            self.emit(" = runtime::rt_invoke_once(");
2833→            self.emit_temp_ref(tf);
2834→            self.emit(", ");
2835→            self.emit_temp_ref(arg_temps[i]);
2836→            self.emit(");\n");
2837→            self.indent--;
2838→            self.emit_indent();
2839→            self.emit("}\n");
2840→        } else {
2841→            usz next_tf = self.next_result();
2842→            self.emit_temp_decl(next_tf);
2843→            self.emit(" = runtime::rt_invoke_once(");
2844→            self.emit_temp_ref(tf);
2845→            self.emit(", ");
2846→            self.emit_temp_ref(arg_temps[i]);
2847→            self.emit(");\n");
2848→            tf = next_tf;
2849→        }
2850→    }
2851→
2852→    self.indent--;
2853→    self.emit_indent();
2854→    self.emit("}\n");
2855→    return id;
2856→}
