2955→
2956→    bool already = self.is_declared(expr.let_expr.name);
2957→
2958→    if (expr.let_expr.is_recursive) {
2959→        // Recursive let: declare first (if needed), then assign
2960→        if (!already) {
2961→            self.emit_indent();
2962→            self.emit("runtime::Value ");
2963→            self.emit_symbol_name(expr.let_expr.name);
2964→            self.emit(";\n");
2965→            self.mark_declared(expr.let_expr.name);
