2967→        usz init_r = self.compile_to_temp(expr.let_expr.init);
2968→        self.emit_indent();
2969→        self.emit_symbol_name(expr.let_expr.name);
2970→        self.emit(" = ");
2971→        self.emit_temp_ref(init_r);
2972→        self.emit(";\n");
2973→
2974→        // Patch self-reference: the closure captured an uninitialized copy of name.
2975→        // Now that name holds the closure, update the capture in the region-allocated data.
2976→        Expr* rec_init = expr.let_expr.init;
2977→        if (rec_init.tag == E_LAMBDA) {
2978→            foreach (&def : self.lambda_defs) {
2979→                if (def.body == rec_init.lambda.body && (uint)def.param == (uint)rec_init.lambda.param) {
2980→                    for (usz ci = 0; ci < def.capture_count; ci++) {
2981→                        if ((uint)def.captures[ci] == (uint)expr.let_expr.name) {
2982→                            // Patch: Lambda_N* _sp_N = (Lambda_N*)name.closure_val.data; _sp_N.captured_name = name;
2983→                            self.emit_indent();
2984→                            self.emit("Lambda_");
2985→                            self.emit_usz(def.id);
2986→                            self.emit("* _sp_");
2987→                            self.emit_usz(def.id);
2988→                            self.emit(" = (Lambda_");
2989→                            self.emit_usz(def.id);
2990→                            self.emit("*)");
2991→                            self.emit_symbol_name(expr.let_expr.name);
2992→                            self.emit(".closure_val.data;\n");
2993→                            self.emit_indent();
2994→                            self.emit("_sp_");
2995→                            self.emit_usz(def.id);
2996→                            self.emit(".captured_");
2997→                            self.emit_symbol_name(expr.let_expr.name);
2998→                            self.emit(" = ");
2999→                            self.emit_symbol_name(expr.let_expr.name);

1500→            seg_start = pos;
1501→        } else {
1502→            pos++;
1503→        }
1504→    }
1505→    // Final segment
1506→    starts[si] = seg_start;
1507→    lens[si] = s.len - seg_start;
1508→
1509→    // Build list in reverse order so cons produces correct order
1510→    for (usz i = seg_count; i > 0; i--) {
1511→        usz idx = i - 1;
1512→        usz start = starts[idx];
1513→        usz len = lens[idx];
1514→        if (len > 4095) { len = 4095; }
1515→
1516→        StringData part;
1517→        for (usz j = 0; j < len; j++) {
1518→            part.chars[j] = s.chars[start + j];
1519→        }
1520→        part.chars[len] = 0;
1521→        part.len = len;
1522→
1523→        Value part_val;
1524→        part_val.tag = V_STRING;
1525→        part_val.str_handle = main::allocate_in(g_current_region, StringData, part);
1526→        result = rt_cons(part_val, result);
1527→    }
1528→
1529→    return result;
1530→}
