1532→fn Value rt_string_length(Value a, Value _unused) {
1533→    if (a.tag != V_STRING) return make_nil();
1534→    StringData* s = main::dereference_as(StringData, a.str_handle);
1535→    usz cp_len = rt_utf8_strlen(s.chars[:s.len]);
1536→    return make_int((long)cp_len);
1537→}
1538→
1539→fn Value rt_string_to_list(Value a, Value _unused) {
1540→    if (a.tag != V_STRING) return make_nil();
1541→    StringData* s = main::dereference_as(StringData, a.str_handle);
1542→
1543→    // First pass: count codepoints
1544→    usz cp_count = 0;
1545→    usz pos = 0;
1546→    while (pos < s.len) {
1547→        usz cplen = rt_utf8_cplen(s.chars[pos]);
1548→        if (pos + cplen > s.len) cplen = s.len - pos;
1549→        pos += cplen;
1550→        cp_count++;
1551→    }
1552→
1553→    if (cp_count == 0) return make_nil();
1554→
1555→    // Allocate exact-size arrays via temp allocator
1556→    usz[] offsets = mem::temp_array(usz, cp_count);
1557→    usz[] cp_lens = mem::temp_array(usz, cp_count);
1558→
1559→    // Second pass: fill offsets and lens
1560→    pos = 0;
1561→    for (usz i = 0; i < cp_count; i++) {
1562→        offsets[i] = pos;
1563→        usz cplen = rt_utf8_cplen(s.chars[pos]);
1564→        if (pos + cplen > s.len) cplen = s.len - pos;
1565→        cp_lens[i] = cplen;
1566→        pos += cplen;
1567→    }
1568→
1569→    // Build list in reverse order
1570→    Value result = make_nil();
1571→    for (isz i = (isz)cp_count - 1; i >= 0; i--) {
1572→        usz off = offsets[(usz)i];
1573→        usz clen = cp_lens[(usz)i];
1574→        StringData ch;
1575→        for (usz j = 0; j < clen; j++) ch.chars[j] = s.chars[off + j];
1576→        ch.chars[clen] = 0;
1577→        ch.len = clen;
1578→
1579→        Value char_val;
1580→        char_val.tag = V_STRING;
1581→        char_val.str_handle = main::allocate_in(g_current_region, StringData, ch);
1582→        result = rt_cons(char_val, result);
1583→    }
1584→    return result;
1585→}
1586→
1587→fn Value rt_list_to_string(Value a, Value _unused) {
1588→    StringData result;
1589→    usz pos = 0;
1590→
1591→    Value current = a;
1592→    while (current.tag == V_CONS) {
1593→        Value* elem = main::dereference_as(Value, current.cons_val.car);
1594→        if (elem.tag == V_STRING) {
1595→            StringData* s = main::dereference_as(StringData, elem.str_handle);
1596→            for (usz i = 0; i < s.len && pos < 4095; i++) {
1597→                result.chars[pos++] = s.chars[i];
1598→            }
1599→        } else if (elem.tag == V_INT) {
1600→            if (pos < 4095) {
1601→                result.chars[pos++] = (char)elem.int_val;
1602→            }
1603→        }
1604→        Value* next = main::dereference_as(Value, current.cons_val.cdr);
1605→        current = *next;
1606→    }
1607→
1608→    result.chars[pos] = 0;
1609→    result.len = pos;
1610→
1611→    Value v;
1612→    v.tag = V_STRING;
1613→    v.str_handle = main::allocate_in(g_current_region, StringData, result);
1614→    return v;
1615→}
1616→
1617→fn Value rt_string_upcase(Value a, Value _unused) {
1618→    if (a.tag != V_STRING) return make_nil();
1619→    StringData* s = main::dereference_as(StringData, a.str_handle);
1620→
1621→    StringData result;
1622→    for (usz i = 0; i < s.len; i++) {
1623→        char c = s.chars[i];
1624→        if (c >= 'a' && c <= 'z') c = c - 'a' + 'A';
1625→        result.chars[i] = c;
1626→    }
1627→    result.chars[s.len] = 0;
1628→    result.len = s.len;
1629→
1630→    Value v;
1631→    v.tag = V_STRING;
1632→    v.str_handle = main::allocate_in(g_current_region, StringData, result);
1633→    return v;
1634→}
1635→
1636→fn Value rt_string_downcase(Value a, Value _unused) {
1637→    if (a.tag != V_STRING) return make_nil();
1638→    StringData* s = main::dereference_as(StringData, a.str_handle);
1639→
1640→    StringData result;
1641→    for (usz i = 0; i < s.len; i++) {
1642→        char c = s.chars[i];
1643→        if (c >= 'A' && c <= 'Z') c = c - 'A' + 'a';
1644→        result.chars[i] = c;
1645→    }
1646→    result.chars[s.len] = 0;
1647→    result.len = s.len;
1648→
1649→    Value v;
1650→    v.tag = V_STRING;
1651→    v.str_handle = main::allocate_in(g_current_region, StringData, result);
1652→    return v;
1653→}
1654→
1655→fn Value rt_string_trim(Value a, Value _unused) {
1656→    if (a.tag != V_STRING) return make_nil();
1657→    StringData* s = main::dereference_as(StringData, a.str_handle);
1658→
1659→    usz start = 0;
1660→    while (start < s.len && (s.chars[start] == ' ' || s.chars[start] == '\t' ||
1661→           s.chars[start] == '\n' || s.chars[start] == '\r')) {
1662→        start++;
1663→    }
1664→
1665→    usz end = s.len;
1666→    while (end > start && (s.chars[end-1] == ' ' || s.chars[end-1] == '\t' ||
1667→           s.chars[end-1] == '\n' || s.chars[end-1] == '\r')) {
1668→        end--;
1669→    }
1670→
1671→    StringData result;
1672→    usz len = end - start;
1673→    for (usz i = 0; i < len; i++) {
1674→        result.chars[i] = s.chars[start + i];
1675→    }
1676→    result.chars[len] = 0;
1677→    result.len = len;
1678→
1679→    Value v;
1680→    v.tag = V_STRING;
1681→    v.str_handle = main::allocate_in(g_current_region, StringData, result);
1682→    return v;
1683→}
