1100→// String conversion helpers (shared across primitives, eval, value printing)
1101→// =============================================================================
1102→
1103→/**
1104→ * Convert integer to string in caller-provided buffer. Returns slice of written chars.
1105→ */
1106→fn char[] int_to_string(long val, char[] buffer) {
1107→    if (val == 0) { buffer[0] = '0'; return buffer[:1]; }
1108→    usz len = 0;
1109→    bool negative = val < 0;
1110→    if (negative) val = -val;
1111→    while (val > 0 && len < buffer.len - 1) {
1112→        buffer[len++] = (char)('0' + (val % 10));
1113→        val /= 10;
1114→    }
1115→    if (negative) buffer[len++] = '-';
1116→    // Reverse in-place
1117→    for (usz j = 0; j < len / 2; j++) {
1118→        char tmp = buffer[j];
1119→        buffer[j] = buffer[len - 1 - j];
1120→        buffer[len - 1 - j] = tmp;
1121→    }
1122→    return buffer[:len];
1123→}
1124→
1125→/**
1126→ * Format double to string in caller-provided buffer, ensuring decimal point.
1127→ * Handles NaN, +inf, -inf. Buffer must be at least 64 bytes.
1128→ */
1129→fn char[] double_to_string(double val, char[] buffer) {
1130→    if (val != val) {
1131→        char[] nan = "+nan.0";
1132→        for (usz i = 0; i < nan.len; i++) buffer[i] = nan[i];
1133→        return buffer[:nan.len];
1134→    }
1135→    if (val == 1.0/0.0) {
1136→        char[] inf = "+inf.0";
1137→        for (usz i = 0; i < inf.len; i++) buffer[i] = inf[i];
1138→        return buffer[:inf.len];
1139→    }
1140→    if (val == -1.0/0.0) {
1141→        char[] ninf = "-inf.0";
1142→        for (usz i = 0; i < ninf.len; i++) buffer[i] = ninf[i];
1143→        return buffer[:ninf.len];
1144→    }
1145→    char[64] fmt_buf;
1146→    char[] s = io::bprintf(&fmt_buf, "%.15g", val)!!;
1147→    for (usz i = 0; i < s.len; i++) buffer[i] = s[i];
1148→    usz len = s.len;
1149→    bool has_dot = false;
1150→    for (usz i = 0; i < len; i++) {
1151→        if (buffer[i] == '.' || buffer[i] == 'e' || buffer[i] == 'E') { has_dot = true; break; }
1152→    }
1153→    if (!has_dot && len + 2 <= buffer.len) {
1154→        buffer[len] = '.';
1155→        buffer[len + 1] = '0';
1156→        len += 2;
1157→    }
1158→    return buffer[:len];
1159→}
