1161→// =============================================================================
1162→// SECTION 5: ENVIRONMENT
1163→// =============================================================================
1164→
1165→// Initial capacity for dynamically-sized Env binding arrays
1166→const usz ENV_INITIAL_CAPACITY = 8;
1167→
1168→// Threshold: build hash table when binding_count exceeds this
1169→const usz ENV_HASH_THRESHOLD = 16;
1170→
1171→// Sentinel for empty hash table slots
1172→const SymbolId ENV_HASH_EMPTY = 0xFFFFFFFF;
1173→
1174→/**
1175→ * Binding — Single name-value binding.
1176→ */
1177→struct Binding {
1178→    SymbolId name;
1179→    Value*   value;
1180→}
1181→
1182→/**
1183→ * EnvHashEntry — Open-addressing hash table entry for Env.
1184→ */
1185→struct EnvHashEntry {
1186→    SymbolId key;    // ENV_HASH_EMPTY = empty slot
1187→    usz      index;  // Index into bindings array
1188→}
1189→
1190→/**
1191→ * Env — Linked list of environment frames.
1192→ * Bindings array is heap-allocated and grows dynamically.
1193→ * For frames with >ENV_HASH_THRESHOLD bindings, a hash table provides O(1) lookup.
1194→ */
1195→struct Env {
1196→    Binding*              bindings;
1197→    usz                   binding_count;
1198→    usz                   capacity;
1199→    Env*                  parent;
1200→    EnvHashEntry*         hash_table;     // NULL if not using hash
1201→    usz                   hash_capacity;  // Power of 2
1202→    bool                  persistent;     // true = allocated in root_region, skip in deep_copy_env
1203→}
1204→
1205→fn Env* make_env(Interp* interp, Env* parent) {
1206→    Env* env = interp.alloc_env();
1207→    env.bindings = (Binding*)mem::malloc(Binding.sizeof * ENV_INITIAL_CAPACITY);
1208→    env.binding_count = 0;
1209→    env.capacity = ENV_INITIAL_CAPACITY;
1210→    env.parent = parent;
1211→    env.hash_table = null;
1212→    env.hash_capacity = 0;
1213→    env.persistent = false;
1214→    main::scope_register_dtor(interp.current_scope, (void*)env, &scope_dtor_env);
1215→    return env;
1216→}
1217→
1218→/**
1219→ * Build or rebuild the hash table for an Env frame.
1220→ * Hash capacity is next power of 2 >= 2 * binding_count.
1221→ */
1222→fn void Env.build_hash_table(Env* self) {
1223→    // Determine capacity (next power of 2 >= 2 * count)
1224→    usz cap = 32;
1225→    while (cap < self.binding_count * 2) cap *= 2;
1226→
1227→    // Free old hash table if exists
1228→    if (self.hash_table != null) {
1229→        mem::free(self.hash_table);
1230→    }
1231→
1232→    self.hash_capacity = cap;
1233→    self.hash_table = (EnvHashEntry*)mem::malloc(EnvHashEntry.sizeof * cap);
1234→    // Initialize all slots to empty
1235→    for (usz i = 0; i < cap; i++) {
1236→        self.hash_table[i].key = ENV_HASH_EMPTY;
1237→    }
1238→    // Insert all existing bindings
1239→    usz mask = cap - 1;
1240→    for (usz i = 0; i < self.binding_count; i++) {
1241→        usz slot = (usz)self.bindings[i].name & mask;
1242→        while (self.hash_table[slot].key != ENV_HASH_EMPTY) {
1243→            slot = (slot + 1) & mask;
1244→        }
1245→        self.hash_table[slot].key = self.bindings[i].name;
1246→        self.hash_table[slot].index = i;
1247→    }
1248→}
1249→
1250→/**
1251→ * Look up a SymbolId in the hash table. Returns index into bindings or ~(usz)0 if not found.
1252→ */
1253→<* @require self.hash_table != null : "hash_lookup called without hash table" *>
1254→fn usz Env.hash_lookup(Env* self, SymbolId name) {
1255→    usz mask = self.hash_capacity - 1;
1256→    usz slot = (usz)name & mask;
1257→    for (;;) {
1258→        SymbolId k = self.hash_table[slot].key;
1259→        if (k == name) return self.hash_table[slot].index;
1260→        if (k == ENV_HASH_EMPTY) return ~(usz)0;
1261→        slot = (slot + 1) & mask;
1262→    }
1263→}
1264→
1265→/**
1266→ * Insert into the hash table (must have space — caller ensures load factor).
1267→ */
1268→<* @require self.hash_table != null : "hash_insert called without hash table" *>
1269→fn void Env.hash_insert(Env* self, SymbolId name, usz index) {
1270→    usz mask = self.hash_capacity - 1;
1271→    usz slot = (usz)name & mask;
1272→    while (self.hash_table[slot].key != ENV_HASH_EMPTY && self.hash_table[slot].key != name) {
1273→        slot = (slot + 1) & mask;
1274→    }
1275→    self.hash_table[slot].key = name;
1276→    self.hash_table[slot].index = index;
1277→}
1278→
1279→fn void Env.define(Env* self, SymbolId name, Value* value) {
1280→    // Fast path: use hash table if available
1281→    if (self.hash_table != null) {
1282→        usz idx = self.hash_lookup(name);
1283→        if (idx != ~(usz)0) {
1284→            self.bindings[idx].value = value;
1285→            return;
1286→        }
1287→    } else {
1288→        // Linear scan for small frames
1289→        for (usz i = 0; i < self.binding_count; i++) {
1290→            if (self.bindings[i].name == name) {
1291→                self.bindings[i].value = value;
1292→                return;
1293→            }
1294→        }
1295→    }
1296→    // Grow if needed
1297→    if (self.binding_count >= self.capacity) {
1298→        usz new_cap = self.capacity * 2;
1299→        Binding* new_bindings = (Binding*)mem::malloc(Binding.sizeof * new_cap);
1300→        for (usz i = 0; i < self.binding_count; i++) {
1301→            new_bindings[i] = self.bindings[i];
1302→        }
1303→        mem::free(self.bindings);
1304→        self.bindings = new_bindings;
1305→        self.capacity = new_cap;
1306→    }
1307→    usz new_idx = self.binding_count;
1308→    self.bindings[new_idx].name = name;
1309→    self.bindings[new_idx].value = value;
1310→    self.binding_count++;
1311→
1312→    // Build hash table if we crossed the threshold
1313→    if (self.hash_table == null && self.binding_count > ENV_HASH_THRESHOLD) {
1314→        self.build_hash_table();
1315→    } else if (self.hash_table != null) {
1316→        // Check load factor: rebuild if > 70%
1317→        if (self.binding_count * 10 > self.hash_capacity * 7) {
1318→            self.build_hash_table();
1319→        } else {
1320→            self.hash_insert(name, new_idx);
1321→        }
1322→    }
1323→}
1324→
1325→fn Value* Env.lookup(Env* self, SymbolId name) {
1326→    // Fast path: use hash table if available
1327→    if (self.hash_table != null) {
1328→        usz idx = self.hash_lookup(name);
1329→        if (idx != ~(usz)0) {
1330→            return self.bindings[idx].value;
1331→        }
1332→    } else {
1333→        // Linear scan for small frames
1334→        for (usz i = 0; i < self.binding_count; i++) {
1335→            if (self.bindings[i].name == name) {
1336→                return self.bindings[i].value;
1337→            }
1338→        }
1339→    }
1340→    // Search parent
1341→    if (self.parent != null) {
1342→        return self.parent.lookup(name);
1343→    }
1344→    return null;  // Not found
1345→}
1346→
1347→fn bool Env.set(Env* self, SymbolId name, Value* value) {
1348→    if (self.hash_table != null) {
1349→        usz idx = self.hash_lookup(name);
1350→        if (idx != ~(usz)0) {
1351→            self.bindings[idx].value = value;
1352→            return true;
1353→        }
1354→    } else {
1355→        for (usz i = 0; i < self.binding_count; i++) {
1356→            if (self.bindings[i].name == name) {
1357→                self.bindings[i].value = value;
1358→                return true;
1359→            }
1360→        }
1361→    }
1362→    if (self.parent != null) return self.parent.set(name, value);
1363→    return false;
1364→}
1365→
1366→fn Env* Env.extend(Env* self, Interp* interp, SymbolId name, Value* value) {
1367→    Env* new_env = make_env(interp, self);
1368→    new_env.define(name, value);
1369→    return new_env;
1370→}
