3411→        }
3412→        case E_CALL:
3413→            return self.compile_qq_call_flat(tmpl, depth);
3414→        default: {
3415→            usz id = self.next_result();
3416→            self.emit_temp_decl(id);
3417→            self.emit(" = runtime::make_nil();\n");
3418→            return id;
3419→        }
3420→    }
3421→}
3422→
3423→/**
3424→ * compile_qq_call_flat — Flat-style compilation of E_CALL in QQ context.
3425→ * Builds cons chain from elements, handling ,@ splicing via rt_list_append.
3426→ */
3427→fn usz Compiler.compile_qq_call_flat(Compiler* self, Expr* tmpl, usz depth) {
3428→    usz total = tmpl.call.arg_count + 1;
3429→    Expr*[17] elements;
3430→    elements[0] = tmpl.call.func;
3431→    for (usz i = 0; i < tmpl.call.arg_count && i < 16; i++) {
3432→        elements[i + 1] = tmpl.call.args[i];
3433→    }
3434→
3435→    // Check for splicing
3436→    bool has_splice = false;
3437→    if (depth == 0) {
3438→        for (usz i = 0; i < total; i++) {
3439→            if (elements[i].tag == E_UNQUOTE_SPLICING) {
3440→                has_splice = true;
3441→                break;
3442→            }
3443→        }
3444→    }
3445→
3446→    if (!has_splice) {
3447→        // No splicing: build cons chain right to left
3448→        // Start with nil, then cons each element from the end
3449→        usz result_r = self.next_result();
3450→        self.emit_temp_decl(result_r);
3451→        self.emit(" = runtime::make_nil();\n");
3452→
3453→        for (usz i = total; i > 0; i--) {
3454→            usz elem_r = self.compile_qq_flat(elements[i - 1], depth);
3455→            usz new_r = self.next_result();
3456→            self.emit_temp_decl(new_r);
3457→            self.emit(" = runtime::rt_cons(");
3458→            self.emit_temp_ref(elem_r);
3459→            self.emit(", ");
3460→            self.emit_temp_ref(result_r);
3461→            self.emit(");\n");
3462→            result_r = new_r;
3463→        }
3464→        return result_r;
3465→    }
3466→
3467→    // Has splicing: process elements right to left
3468→    // For each element:
3469→    //   - if ,@ at depth 0: compile inner, append to accumulated result
3470→    //   - otherwise: compile qq, cons to accumulated result
3471→    usz result_r = self.next_result();
3472→    self.emit_temp_decl(result_r);
3473→    self.emit(" = runtime::make_nil();\n");
3474→
3475→    for (usz i = total; i > 0; i--) {
3476→        Expr* elem = elements[i - 1];
3477→        if (elem.tag == E_UNQUOTE_SPLICING && depth == 0) {
3478→            // Splice: compile the inner expression and append it before current result
3479→            usz splice_r = self.compile_to_temp(elem.unquote_splicing.body);
3480→            usz new_r = self.next_result();
3481→            self.emit_temp_decl(new_r);
3482→            self.emit(" = runtime::rt_list_append(");
3483→            self.emit_temp_ref(splice_r);
3484→            self.emit(", ");
3485→            self.emit_temp_ref(result_r);
3486→            self.emit(");\n");
3487→            result_r = new_r;
3488→        } else {
3489→            // Normal element: compile qq and cons
3490→            usz elem_r = self.compile_qq_flat(elem, depth);
3491→            usz new_r = self.next_result();
3492→            self.emit_temp_decl(new_r);
3493→            self.emit(" = runtime::rt_cons(");
3494→            self.emit_temp_ref(elem_r);
3495→            self.emit(", ");
3496→            self.emit_temp_ref(result_r);
3497→            self.emit(");\n");
3498→            result_r = new_r;
3499→        }
3500→    }
3501→    return result_r;
3502→}
