3504→// =============================================================================
3505→// SECTION: NATIVE EFFECT COMPILATION (flat style)
3506→// =============================================================================
3507→
3508→fn usz Compiler.compile_reset_flat(Compiler* self, Expr* expr) {
3509→    // Body has been wrapped as a lambda during prescan
3510→    usz body_r = self.compile_to_temp(expr.reset.body);
3511→    usz id = self.next_result();
3512→    self.emit_temp_decl(id);
3513→    self.emit(" = runtime::rt_compiled_reset(");
3514→    self.emit_temp_ref(body_r);
3515→    self.emit(");\n");
3516→    return id;
3517→}
3518→
3519→fn usz Compiler.compile_shift_flat(Compiler* self, Expr* expr) {
3520→    // Body has been wrapped as lambda (lambda (k) ...) during prescan
3521→    usz body_r = self.compile_to_temp(expr.shift.body);
3522→    usz id = self.next_result();
3523→    self.emit_temp_decl(id);
3524→    self.emit(" = runtime::rt_compiled_shift(");
3525→    self.emit_temp_ref(body_r);
3526→    self.emit(");\n");
3527→    return id;
3528→}
3529→
3530→fn usz Compiler.compile_perform_flat(Compiler* self, Expr* expr) {
3531→    // Compile the argument
3532→    usz arg_r = self.compile_to_temp(expr.perform.arg);
3533→    // Create tag symbol
3534→    usz tag_r = self.next_result();
3535→    self.emit_temp_decl(tag_r);
3536→    self.emit(" = runtime::make_symbol(\"");
3537→    char[] tag_name = self.interp.symbols.get_name(expr.perform.tag);
3538→    self.emit_escaped(tag_name);
3539→    self.emit("\");\n");
3540→
3541→    usz id = self.next_result();
3542→    self.emit_temp_decl(id);
3543→    self.emit(" = runtime::rt_compiled_perform(");
3544→    self.emit_temp_ref(tag_r);
3545→    self.emit(", ");
3546→    self.emit_temp_ref(arg_r);
3547→    self.emit(");\n");
3548→    return id;
3549→}
3550→
3551→fn usz Compiler.compile_handle_flat(Compiler* self, Expr* expr) {
3552→    usz clause_count = expr.handle.clause_count;
3553→
3554→    // Compile all handler closures and tags
3555→    usz[8] handler_rs;
3556→    usz[8] tag_rs;
3557→    for (usz i = 0; i < clause_count && i < 8; i++) {
3558→        // Tag symbol
3559→        tag_rs[i] = self.next_result();
3560→        self.emit_temp_decl(tag_rs[i]);
3561→        self.emit(" = runtime::make_symbol(\"");
3562→        char[] tag_name = self.interp.symbols.get_name(expr.handle.clauses[i].effect_tag);
3563→        self.emit_escaped(tag_name);
3564→        self.emit("\");\n");
3565→
3566→        // Handler closure (synthetic lambda from prescan)
3567→        handler_rs[i] = self.compile_to_temp(expr.handle.clauses[i].handler_body);
3568→    }
3569→
3570→    // Compile body closure (synthetic lambda from prescan)
3571→    usz body_r = self.compile_to_temp(expr.handle.body);
3572→
3573→    // Build tags and handlers arrays (C3 array syntax: Type[N] name)
3574→    usz tags_arr = self.next_result();
3575→    self.emit_indent();
3576→    self.emit("runtime::Value[");
3577→    self.emit_usz(clause_count > 0 ? clause_count : 1);
3578→    self.emit("] _eff_tags_");
3579→    self.emit_usz(tags_arr);
3580→    self.emit(";\n");
3581→
3582→    usz hdlrs_arr = self.next_result();
3583→    self.emit_indent();
3584→    self.emit("runtime::Value[");
3585→    self.emit_usz(clause_count > 0 ? clause_count : 1);
3586→    self.emit("] _eff_hdlrs_");
3587→    self.emit_usz(hdlrs_arr);
3588→    self.emit(";\n");
3589→
3590→    for (usz i = 0; i < clause_count && i < 8; i++) {
3591→        self.emit_indent();
3592→        self.emit("_eff_tags_");
3593→        self.emit_usz(tags_arr);
3594→        self.emit("[");
3595→        self.emit_usz(i);
3596→        self.emit("] = ");
3597→        self.emit_temp_ref(tag_rs[i]);
3598→        self.emit(";\n");
3599→

