1896→fn Value rt_index(Value collection, Value index) {
1897→    if (collection.tag == V_CONS && index.tag == V_INT) {
1898→        return rt_list_nth(collection, (usz)index.int_val);
1899→    }
1900→    if (collection.tag == V_STRING && index.tag == V_INT) {
1901→        StringData* s = main::dereference_as(StringData, collection.str_handle);
1902→        usz idx = (usz)index.int_val;
1903→        if (idx < s.len) {
1904→            return make_int((long)s.chars[idx]);
1905→        }
1906→        return make_nil();
1907→    }
1908→    return make_nil();
1909→}
