1911→fn Value rt_field_access(Value obj, Value field_name) {
1912→    // Field access for path notation: obj.field
1913→    // Objects are represented as association lists: ((name . value) (name . value) ...)
1914→    if (obj.tag != V_CONS || field_name.tag != V_STRING) return make_nil();
1915→
1916→    StringData* field = main::dereference_as(StringData, field_name.str_handle);
1917→
1918→    Value current = obj;
1919→    while (current.tag == V_CONS) {
1920→        Value* pair = main::dereference_as(Value, current.cons_val.car);
1921→        if (pair.tag == V_CONS) {
1922→            Value* key = main::dereference_as(Value, pair.cons_val.car);
1923→            if (key.tag == V_SYMBOL) {
1924→                SymbolData* sym = main::dereference_as(SymbolData, key.sym_handle);
1925→                if (sym.len == field.len) {
1926→                    bool match = true;
1927→                    for (usz i = 0; i < sym.len; i++) {
1928→                        if (sym.chars[i] != field.chars[i]) { match = false; break; }
1929→                    }
1930→                    if (match) {
1931→                        Value* val = main::dereference_as(Value, pair.cons_val.cdr);
1932→                        return *val;
1933→                    }
1934→                }
1935→            }
1936→        }
1937→        Value* next = main::dereference_as(Value, current.cons_val.cdr);
1938→        current = *next;
1939→    }
1940→    return make_nil();
1941→}
