1943→// =============================================================================
1944→// SECTION 15: NATIVE COMPILED EFFECTS (reset/shift/handle/perform)
1945→// =============================================================================
1946→// Self-contained effect mechanism for AOT-compiled code.
1947→// Uses replay-based continuations: body closures are re-invoked with substitution.
1948→
1949→const usz RT_MAX_HANDLERS = 64;
1950→const usz RT_MAX_CLAUSES = 64;
1951→const usz RT_MAX_PRIOR = 256;
1952→
1953→struct RtEffectClause {
1954→    Value tag;                    // V_SYMBOL tag
1955→    Value handler_closure;        // V_CLOSURE receiving (cons k arg)
1956→}
1957→
1958→struct RtEffectHandler {
1959→    RtEffectClause[RT_MAX_CLAUSES] clauses;
1960→    usz clause_count;
1961→    Value body_closure;           // Handle body closure (for continuation capture)
1962→}
1963→
1964→struct RtCapturedCont {
1965→    Value body_closure;           // Body closure to replay
1966→    bool is_effect;
1967→    Value effect_tag;             // V_SYMBOL for effect replay
1968→    RtEffectHandler handler_copy; // Handler to reinstall during effect replay
1969→    bool has_handler;
1970→    usz perform_index;
1971→    Value[RT_MAX_PRIOR] prior_results;
1972→    usz prior_count;
1973→    usz shift_index;
1974→    Value[RT_MAX_PRIOR] shift_prior_results;
1975→    usz shift_prior_count;
1976→}
1977→
1978→// Thread-local effect state
1979→tlocal usz rt_reset_depth = 0;
1980→tlocal bool rt_shift_occurred = false;
1981→tlocal usz rt_shift_target_depth = 0;
1982→tlocal Value rt_shift_result_val;
1983→
1984→tlocal bool rt_cont_sub = false;           // In replay mode?
1985→tlocal Value rt_cont_sub_val;              // Substitution value
1986→tlocal bool rt_cont_is_eff = false;        // Effect replay?
1987→tlocal Value rt_cont_eff_tag;              // Effect tag for replay
1988→
1989→tlocal RtEffectHandler[RT_MAX_HANDLERS] rt_handler_stack;
1990→tlocal usz rt_handler_count = 0;
1991→tlocal bool rt_effect_occurred = false;
1992→tlocal Value rt_effect_result_val;
1993→
1994→tlocal Value[RT_MAX_HANDLERS] rt_reset_body_stack;  // Body closures
1995→
1996→// Multi-perform/shift replay tracking
1997→tlocal usz rt_eff_perform_ctr = 0;
1998→tlocal Value[RT_MAX_PRIOR] rt_eff_prior;
1999→tlocal usz rt_cont_target_perform = 0;
2000→tlocal usz rt_eff_shift_ctr = 0;
2001→tlocal Value[RT_MAX_PRIOR] rt_shift_prior;
2002→tlocal usz rt_cont_target_shift = 0;
2003→
2004→/**
2005→ * rt_compiled_reset — Evaluate body closure within a reset delimiter.
2006→ * Body is a V_CLOSURE called with make_nil() arg.
2007→ */
2008→fn Value rt_compiled_reset(Value body_closure) {
2009→    usz saved_shift_ctr = rt_eff_shift_ctr;
2010→    rt_eff_shift_ctr = 0;
2011→
2012→    if (rt_reset_depth >= RT_MAX_HANDLERS) {
2013→        io::printfn("Error: reset stack overflow");
2014→        return make_nil();
2015→    }
2016→    rt_reset_depth++;
2017→    rt_reset_body_stack[rt_reset_depth - 1] = body_closure;
2018→
2019→    Value result = body_closure.closure_val.invoke(body_closure.closure_val.data, make_nil());
2020→    // Trampoline
2021→    while (result.tag == V_THUNK) {
2022→        Value* ta = main::dereference_as(Value, result.thunk_val.arg);
2023→        result = result.thunk_val.invoke(result.thunk_val.data, *ta);
2024→    }
2025→
2026→    rt_eff_shift_ctr = saved_shift_ctr;
2027→    rt_reset_depth--;
2028→
2029→    if (rt_shift_occurred && rt_reset_depth == rt_shift_target_depth) {
2030→        rt_shift_occurred = false;
2031→        return rt_shift_result_val;
2032→    }
2033→
2034→    return result;
2035→}
2036→
2037→/**
2038→ * rt_compiled_shift — Capture continuation and evaluate k-body.
2039→ * k_body_closure is a V_CLOSURE called with continuation as arg.
2040→ */
2041→fn Value rt_compiled_shift(Value k_body_closure) {
2042→    // REPLAY CHECK
2043→    if (rt_cont_sub && !rt_cont_is_eff) {
2044→        usz current = rt_eff_shift_ctr;
2045→        rt_eff_shift_ctr++;
2046→        if (current < rt_cont_target_shift) {
2047→            return rt_shift_prior[current];
2048→        }
2049→        if (current == rt_cont_target_shift) {
2050→            rt_cont_sub = false;
2051→            if (current < RT_MAX_PRIOR) {
2052→                rt_shift_prior[current] = rt_cont_sub_val;
2053→            }
2054→            return rt_cont_sub_val;
2055→        }
2056→    }
2057→
2058→    if (rt_reset_depth == 0) {
2059→        io::printfn("Error: shift outside of reset");
2060→        return make_nil();
2061→    }
2062→
2063→    // Capture continuation
2064→    RtCapturedCont* cc = (RtCapturedCont*)mem::malloc(RtCapturedCont.sizeof);
2065→    cc.body_closure = rt_reset_body_stack[rt_reset_depth - 1];
2066→    cc.is_effect = false;
2067→    cc.has_handler = false;
2068→    cc.shift_index = rt_eff_shift_ctr;
2069→    cc.shift_prior_count = rt_eff_shift_ctr;
2070→    for (usz i = 0; i < cc.shift_prior_count && i < RT_MAX_PRIOR; i++) {
2071→        cc.shift_prior_results[i] = rt_shift_prior[i];
2072→    }
2073→    rt_eff_shift_ctr++;
2074→
2075→    // Create continuation closure
2076→    Value k_val = make_closure((void*)cc, &invoke_compiled_continuation);
2077→
2078→    // Call k-body with continuation
2079→    Value body_result = k_body_closure.closure_val.invoke(k_body_closure.closure_val.data, k_val);
2080→    while (body_result.tag == V_THUNK) {
2081→        Value* ta = main::dereference_as(Value, body_result.thunk_val.arg);
2082→        body_result = body_result.thunk_val.invoke(body_result.thunk_val.data, *ta);
2083→    }
2084→
2085→    rt_shift_occurred = true;
2086→    rt_shift_target_depth = rt_reset_depth - 1;
2087→    rt_shift_result_val = body_result;
2088→
2089→    return body_result;
2090→}
2091→
2092→/**
2093→ * rt_compiled_handle — Evaluate body with effect handlers installed.
2094→ * tags[i] is V_SYMBOL, handlers[i] is V_CLOSURE receiving (cons k arg).
2095→ */
2096→fn Value rt_compiled_handle(Value* tags, Value* handlers, usz clause_count, Value body_closure) {
2097→    if (rt_handler_count >= RT_MAX_HANDLERS) {
2098→        io::printfn("Error: handler stack overflow");
2099→        return make_nil();

2100→    }
2101→
2102→    RtEffectHandler* h = &rt_handler_stack[rt_handler_count];
2103→    h.clause_count = clause_count;
2104→    h.body_closure = body_closure;
2105→    for (usz i = 0; i < clause_count && i < RT_MAX_CLAUSES; i++) {
2106→        h.clauses[i].tag = tags[i];
2107→        h.clauses[i].handler_closure = handlers[i];
2108→    }
2109→
2110→    usz saved_perform_ctr = rt_eff_perform_ctr;
2111→    rt_eff_perform_ctr = 0;
2112→    rt_handler_count++;
2113→
2114→    Value result = body_closure.closure_val.invoke(body_closure.closure_val.data, make_nil());
2115→    while (result.tag == V_THUNK) {
2116→        Value* ta = main::dereference_as(Value, result.thunk_val.arg);
2117→        result = result.thunk_val.invoke(result.thunk_val.data, *ta);
2118→    }
2119→
2120→    rt_eff_perform_ctr = saved_perform_ctr;
2121→
2122→    if (rt_effect_occurred) {
2123→        rt_effect_occurred = false;
2124→        return rt_effect_result_val;
2125→    }
2126→
2127→    rt_handler_count--;
2128→    return result;
2129→}
2130→
2131→/**
2132→ * rt_compiled_perform — Dispatch an effect.
2133→ * Searches handler stack, captures continuation, calls handler.
2134→ * I/O fast path when no handler installed.
2135→ */
2136→fn Value rt_compiled_perform(Value tag, Value arg) {
2137→    // REPLAY CHECK
2138→    if (rt_cont_sub && rt_cont_is_eff) {
2139→        // Check if tags match
2140→        if (tag.tag == V_SYMBOL && rt_cont_eff_tag.tag == V_SYMBOL) {
2141→            SymbolData* t1 = main::dereference_as(SymbolData, tag.sym_handle);
2142→            SymbolData* t2 = main::dereference_as(SymbolData, rt_cont_eff_tag.sym_handle);
2143→            bool match = (t1.len == t2.len);
2144→            if (match) {
