2339→
2340→    // Use C3's file::load_temp to read entire file
2341→    if (try content = io::file::load_temp((String)path_slice)) {
2342→        usz len = content.len;
2343→        if (len > 4095) len = 4095;
2344→
2345→        StringData result;
2346→        for (usz i = 0; i < len; i++) {
2347→            result.chars[i] = content[i];
