1073→fn Value* copy_to_parent(Value* v, Interp* interp) {
1074→    if (v == null) return null;
1075→
1076→    Value* result;
1077→    switch (v.tag) {
1078→        case NIL:
1079→            result = make_nil(interp);
1080→        case INT:
1081→            result = make_int(interp, v.int_val);
1082→        case DOUBLE:
1083→            result = make_double(interp, v.double_val);
1084→        case STRING:
1085→            result = make_string(interp, v.str_val.chars[:v.str_val.len]);
1086→        case SYMBOL:
1087→            result = make_symbol(interp, v.sym_val);
1088→        case CONS: {
1089→            Value* new_car = copy_to_parent(v.cons_val.car, interp);
1090→            Value* new_cdr = copy_to_parent(v.cons_val.cdr, interp);
1091→            result = make_cons(interp, new_car, new_cdr);
1092→        }
1093→        case CLOSURE: {
1094→            // Shared Closure: new Value wrapper in target scope, bump refcount
1095→            result = interp.alloc_value();
1096→            result.tag = CLOSURE;
1097→            result.closure_val = v.closure_val;
1098→            result.closure_val.refcount++;
1099→            main::scope_register_dtor(interp.current_scope, (void*)result, &scope_dtor_value);
1100→        }
1101→        case PRIMITIVE:
1102→            result = v;
1103→        case PARTIAL_PRIM: {
1104→            // Deep copy: Value wrapper may be in child scope, and first_arg/second_arg may too
1105→            result = interp.alloc_value();
1106→            result.tag = PARTIAL_PRIM;
1107→            result.partial_val.func = v.partial_val.func;
1108→            result.partial_val.remaining = v.partial_val.remaining;
1109→            result.partial_val.first_arg = copy_to_parent(v.partial_val.first_arg, interp);
1110→            result.partial_val.second_arg = copy_to_parent(v.partial_val.second_arg, interp);
1111→        }
1112→        case CONTINUATION:
1113→            // Shallow copy: Value wrapper may be in child scope, cont_val itself is in root_region
1114→            result = interp.alloc_value();
1115→            result.tag = CONTINUATION;
1116→            result.cont_val = v.cont_val;
1117→        case HASHMAP:
1118→        case ARRAY:
1119→        case INSTANCE:
1120→        case METHOD_TABLE:
1121→            result = v;  // Value allocated in root_scope; backing data is malloc'd with registered destructors
1122→        case FFI_HANDLE:
1123→            result = v;  // FfiHandle is inline in Value; Value allocated in root_scope
1124→        case TYPE_INFO:
1125→            result = v;  // type info lives in registry
1126→        case ITERATOR: {
1127→            // Phase 4b: iterator_val is a Value* to a CLOSURE that may be in a child scope.
1128→            // Promote the underlying closure too so it outlives the ITERATOR.
1129→            Value* promoted_thunk = copy_to_parent(v.iterator_val, interp);
1130→            result = interp.alloc_value();
1131→            result.tag = ITERATOR;
1132→            result.iterator_val = promoted_thunk;
1133→        }
1134→        case COROUTINE:
1135→            // Shallow copy: Value wrapper may be in child scope, coroutine_val (Coro*) managed by stack pool
1136→            result = interp.alloc_value();
1137→            result.tag = COROUTINE;
1138→            result.coroutine_val = v.coroutine_val;
1139→        case MODULE:
1140→            result = v;  // Module lives in interp.modules array
1141→        case ERROR:
1142→            result = make_error(interp, v.str_val.chars[:v.str_val.len]);
1143→        default:
1144→            result = v;
1145→    }
1146→    return result;
1147→}
