1149→/**
1150→ * Promote a value to root_scope so it survives child scope release.
1151→ * No-op when already in root_scope (fast path for stdlib loading, etc.).
1152→ * Used when storing values into root-scope data structures (hashmap, array).
1153→ */
1154→fn Value* promote_to_root(Value* v, Interp* interp) {
1155→    if (v == null || interp.current_scope == interp.root_scope) return v;
1156→    main::ScopeRegion* saved_scope = interp.current_scope;
1157→    interp.current_scope = interp.root_scope;
