1163→/**
1164→ * Copy an env chain into interp.current_scope (caller must set this to the target scope,
1165→ * typically a closure's env_scope). Uses copy_to_parent for each binding value.
1166→ * Stops at global_env (already in root_region). Skips persistent env nodes (mutable boxes).
1167→ * Replaces deep_copy_env — allocates into any scope, not just root_scope.
1168→ */
1169→fn Env* copy_env_to_scope(Env* env, Interp* interp, usz depth = 0) {
1170→    if (env == null || env == interp.global_env) return env;
1171→    if (depth >= 256) return null;
1172→
1173→    // Persistent env nodes (mutable boxes allocated in root_region) are kept
1174→    // as-is to preserve sharing between JIT stack slots and closure captures.
1175→    // Their parent chain still needs fixing up since it may point to child-scope envs.
1176→    if (env.persistent) {
1177→        env.parent = copy_env_to_scope(env.parent, interp, depth + 1);
1178→        return env;
1179→    }
1180→
1181→    Env* new_env = interp.alloc_env();
1182→    // Allocate bindings to match source
1183→    new_env.bindings = (Binding*)mem::malloc(Binding.sizeof * env.binding_count);
1184→    new_env.capacity = env.binding_count;
1185→    new_env.binding_count = env.binding_count;
1186→    for (usz i = 0; i < env.binding_count; i++) {
1187→        new_env.bindings[i].name = env.bindings[i].name;
1188→        new_env.bindings[i].value = copy_to_parent(
1189→            env.bindings[i].value, interp);
1190→    }
1191→    new_env.parent = copy_env_to_scope(env.parent, interp, depth + 1);
1192→    // Rebuild hash table if source had one
1193→    if (env.hash_table != null) {
1194→        new_env.build_hash_table();
1195→    }
1196→    // Register destructor for the newly malloc'd bindings
1197→    main::scope_register_dtor(interp.current_scope, (void*)new_env, &scope_dtor_env);
1198→
1199→    return new_env;
1200→}
