1204→/**
1205→ * Look up a key in an association list.
1206→ * An alist is a list of pairs: ((key1 . val1) (key2 . val2) ...)
1207→ * Returns the value associated with the key, or null if not found.
1208→ */
1209→fn Value* alist_lookup(Value* alist, SymbolId key, Interp* interp) {
1210→    // Iterate through the alist
1211→    while (is_cons(alist)) {
1212→        Value* pair = car(alist);
1213→
1214→        // Each element should be a cons cell (key . value)
1215→        if (is_cons(pair)) {
1216→            Value* pair_key = car(pair);
1217→
1218→            // Check if the key matches (compare as symbols)
1219→            if (is_symbol(pair_key) && (uint)pair_key.sym_val == (uint)key) {
1220→                return cdr(pair);
1221→            }
1222→        }
1223→
1224→        alist = cdr(alist);
1225→    }
1226→
1227→    return null;  // Key not found
1228→}
