3705→fn usz Compiler.compile_match_flat(Compiler* self, Expr* expr) {
3706→    // Compile scrutinee to temp
3707→    usz scrutinee_r = self.compile_to_temp(expr.match.scrutinee);
3708→
3709→    // Declare result temp
3710→    usz id = self.next_result();
3711→    self.emit_temp_decl(id);
3712→    self.emit(" = runtime::make_nil();\n");
3713→
3714→    for (usz i = 0; i < expr.match.clause_count; i++) {
3715→        self.emit_indent();
3716→        if (i > 0) {
3717→            self.emit("else ");
3718→        }
3719→        self.emit("if (");
3720→        // Use temp ref name for pattern checks
3721→        char[16] ref_name;
3722→        usz ref_len = io::bprintf(&ref_name, "_r%d", (int)scrutinee_r)!!.len;
3723→        self.compile_pattern_check(expr.match.clauses[i].pattern, ref_name[:ref_len]);
3724→        self.emit(") {\n");
3725→        self.indent++;
3726→
3727→        // Bind pattern variables
3728→        self.emit_indent();
3729→        self.compile_pattern_bindings(expr.match.clauses[i].pattern, ref_name[:ref_len]);
3730→
3731→        // Compile result
3732→        usz clause_r = self.compile_to_temp(expr.match.clauses[i].result);
3733→        self.emit_indent();
3734→        self.emit_temp_ref(id);
3735→        self.emit(" = ");
3736→        self.emit_temp_ref(clause_r);
3737→        self.emit(";\n");
3738→        self.indent--;
3739→        self.emit_indent();
3740→        self.emit("} ");
3741→    }
3742→
3743→    self.emit("\n");
3744→    return id;
3745→}
