3747→fn void Compiler.compile_literal(Compiler* self, Value* v) {
3748→    if (v == null || v.tag == NIL) {
3749→        self.emit("runtime::make_nil()");
3750→        return;
3751→    }
3752→
3753→    switch (v.tag) {
3754→        case INT:
3755→            self.emit("runtime::make_int(");
3756→            self.emit_int(v.int_val);
3757→            self.emit(")");
3758→
3759→        case DOUBLE:
3760→            self.emit("runtime::rt_make_double(");
3761→            char[64] dbuf;
3762→            char[] dslice = io::bprintf(&dbuf, "%.17g", v.double_val)!!;
3763→            self.emit(dslice);
3764→            self.emit(")");
3765→
3766→        case STRING:
3767→            self.emit("runtime::make_string(\"");
3768→            // Emit string with escaping
3769→            for (usz i = 0; i < v.str_val.len; i++) {
3770→                char c = v.str_val.chars[i];
3771→                if (c == '"') {
3772→                    self.emit("\\\"");
3773→                } else if (c == '\\') {
3774→                    self.emit("\\\\");
3775→                } else if (c == '\n') {
3776→                    self.emit("\\n");
3777→                } else if (c == '\t') {
3778→                    self.emit("\\t");
3779→                } else {
3780→                    self.emit_char(c);
3781→                }
3782→            }
3783→            self.emit("\")");
3784→
3785→        case SYMBOL:
3786→            self.emit("runtime::make_symbol(\"");
3787→            char[] name = self.interp.symbols.get_name(v.sym_val);
3788→            self.emit_escaped(name);
3789→            self.emit("\")");
3790→
3791→        case CONS:
3792→            self.emit("runtime::rt_cons(");
3793→            self.compile_literal(v.cons_val.car);
3794→            self.emit(", ");
3795→            self.compile_literal(v.cons_val.cdr);
3796→            self.emit(")");
3797→
3798→        default:
3799→            self.emit("runtime::make_nil()");
3800→    }
3801→}
