3831→fn void Compiler.compile_pattern_check(Compiler* self, Pattern* pat, char[] val_name) {
3832→    if (pat == null) {
3833→        self.emit("true");
3834→        return;
3835→    }
3836→
3837→    switch (pat.tag) {
3838→        case PAT_WILDCARD:
3839→            self.emit("true");
3840→
3841→        case PAT_VAR:
3842→            self.emit("true");
3843→
3844→        case PAT_LIT:
3845→            self.emit("runtime::rt_values_equal(");
3846→            self.emit(val_name);
3847→            self.emit(", ");
3848→            self.compile_literal(pat.lit_value);
3849→            self.emit(")");
3850→
3851→        case PAT_QUOTE:
3852→            self.emit("runtime::rt_values_equal(");
3853→            self.emit(val_name);
3854→            self.emit(", ");
3855→            self.compile_literal(pat.quote_datum);
3856→            self.emit(")");
3857→
3858→        case PAT_SEQ:
3859→            // Check list length and elements
3860→            self.emit("runtime::rt_is_list(");
3861→            self.emit(val_name);
3862→            self.emit(")");
3863→
3864→            if (pat.rest_pos == REST_NONE) {
3865→                // Exact length match
3866→                self.emit(" && runtime::rt_list_length(");
3867→                self.emit(val_name);
3868→                self.emit(") == ");
3869→                self.emit_usz(pat.elem_count);
3870→            } else if (pat.rest_pos == REST_START || pat.rest_pos == REST_MIDDLE || pat.rest_pos == REST_END) {
3871→                // At least N elements
3872→                self.emit(" && runtime::rt_list_length(");
3873→                self.emit(val_name);
3874→                self.emit(") >= ");
3875→                self.emit_usz(pat.elem_count);
3876→            }
3877→
3878→        case PAT_GUARD:
3879→            // Guard patterns: delegate to true for now (guard check at runtime)
3880→            self.emit("true");
3881→
3882→        default:
3883→            self.emit("true");
3884→    }
3885→}
