2433→const usz RT_VAR_TABLE_SIZE = 512;
2434→
2435→struct RtVarEntry {
2436→    char[64] name;
2437→    usz      name_len;
2438→    Value    val;
2439→    bool     used;
2440→}
2441→
2442→RtVarEntry[RT_VAR_TABLE_SIZE] g_rt_vars;
2443→
2444→fn usz rt_var_hash(char[] name) {
2445→    usz h = 5381;
2446→    for (usz i = 0; i < name.len; i++) {
2447→        h = ((h << 5) + h) + (usz)name[i];
2448→    }
2449→    return h & (RT_VAR_TABLE_SIZE - 1);
2450→}
2451→
2452→/**
2453→ * Define/update a variable in the standalone var table.
2454→ * Used for mutable-captured variables.
2455→ */
2456→fn void rt_define_var(char[] name, Value val) {
2457→    usz idx = rt_var_hash(name);
2458→    for (usz i = 0; i < RT_VAR_TABLE_SIZE; i++) {
2459→        usz slot = (idx + i) & (RT_VAR_TABLE_SIZE - 1);
2460→        if (g_rt_vars[slot].used && g_rt_vars[slot].name_len == name.len) {
2461→            bool match = true;
2462→            for (usz j = 0; j < name.len; j++) {
2463→                if (g_rt_vars[slot].name[j] != name[j]) { match = false; break; }
2464→            }
2465→            if (match) {
2466→                g_rt_vars[slot].val = val;
2467→                return;
2468→            }
2469→        }
2470→        if (!g_rt_vars[slot].used) {
2471→            usz len = name.len;
2472→            if (len > 63) len = 63;
2473→            for (usz j = 0; j < len; j++) {
2474→                g_rt_vars[slot].name[j] = name[j];
2475→            }
2476→            g_rt_vars[slot].name[len] = 0;
2477→            g_rt_vars[slot].name_len = len;
2478→            g_rt_vars[slot].val = val;
2479→            g_rt_vars[slot].used = true;
2480→            return;
2481→        }
2482→    }
2483→}
2484→
2485→/**
2486→ * Look up a variable in the standalone var table.
2487→ * Used for mutable-captured variables.
2488→ */
2489→fn Value rt_lookup_var(char[] name) {
2490→    usz idx = rt_var_hash(name);
2491→    for (usz i = 0; i < RT_VAR_TABLE_SIZE; i++) {
2492→        usz slot = (idx + i) & (RT_VAR_TABLE_SIZE - 1);
2493→        if (!g_rt_vars[slot].used) return make_nil();
2494→        if (g_rt_vars[slot].name_len == name.len) {
2495→            bool match = true;
2496→            for (usz j = 0; j < name.len; j++) {
2497→                if (g_rt_vars[slot].name[j] != name[j]) { match = false; break; }
2498→            }
2499→            if (match) return g_rt_vars[slot].val;
2500→        }
2501→    }
2502→    return make_nil();
2503→}
