2531→/**
2532→ * (string->number str) => int or nil
2533→ */
2534→fn Value rt_string_to_number(Value a, Value _unused) {
2535→    if (a.tag != V_STRING) return make_nil();
2536→    StringData* s = main::dereference_as(StringData, a.str_handle);
2537→    if (s.len == 0) return make_nil();
2538→
2539→    // Check if it contains a decimal point or exponent → parse as double
2540→    bool is_float = false;
2541→    for (usz i = 0; i < s.len; i++) {
2542→        if (s.chars[i] == '.' || s.chars[i] == 'e' || s.chars[i] == 'E') {
2543→            is_float = true;
2544→            break;
2545→        }
2546→    }
2547→
2548→    if (is_float) {
2549→        // Parse as double manually
2550→        double result = 0.0;
2551→        bool negative = false;
2552→        usz pos = 0;
2553→        if (s.chars[0] == '-') { negative = true; pos = 1; }
2554→        else if (s.chars[0] == '+') { pos = 1; }
2555→        // Integer part
2556→        while (pos < s.len && s.chars[pos] >= '0' && s.chars[pos] <= '9') {
2557→            result = result * 10.0 + (double)(s.chars[pos] - '0');
2558→            pos++;
2559→        }
2560→        // Fractional part
2561→        if (pos < s.len && s.chars[pos] == '.') {
2562→            pos++;
2563→            double frac = 0.1;
2564→            while (pos < s.len && s.chars[pos] >= '0' && s.chars[pos] <= '9') {
2565→                result += (double)(s.chars[pos] - '0') * frac;
2566→                frac *= 0.1;
2567→                pos++;
2568→            }
2569→        }
2570→        // Exponent part
2571→        if (pos < s.len && (s.chars[pos] == 'e' || s.chars[pos] == 'E')) {
2572→            pos++;
2573→            bool exp_neg = false;
2574→            if (pos < s.len && s.chars[pos] == '-') { exp_neg = true; pos++; }
2575→            else if (pos < s.len && s.chars[pos] == '+') { pos++; }
2576→            long exp_val = 0;
2577→            while (pos < s.len && s.chars[pos] >= '0' && s.chars[pos] <= '9') {
2578→                exp_val = exp_val * 10 + (long)(s.chars[pos] - '0');
2579→                pos++;
2580→            }
2581→            double multiplier = 1.0;
2582→            for (long e = 0; e < exp_val; e++) multiplier *= 10.0;
2583→            if (exp_neg) { result /= multiplier; }
2584→            else { result *= multiplier; }
2585→        }
2586→        if (pos != s.len) return make_nil();  // Unparsed characters
2587→        return rt_make_double(negative ? -result : result);
2588→    }
2589→
2590→    // Parse as integer
2591→    long result = 0;
2592→    bool negative = false;
2593→    usz start = 0;
2594→
2595→    if (s.chars[0] == '-') {
2596→        negative = true;
2597→        start = 1;
2598→        if (s.len == 1) return make_nil();
2599→    }
2600→
2601→    for (usz i = start; i < s.len; i++) {
2602→        char c = s.chars[i];
2603→        if (c < '0' || c > '9') return make_nil();
2604→        result = result * 10 + (long)(c - '0');
2605→    }
2606→
2607→    return make_int(negative ? -result : result);
2608→}
