2610→/**
2611→ * (number->string n) => string
2612→ */
2613→fn Value rt_number_to_string(Value a, Value _unused) {
2614→    if (a.tag == V_DOUBLE) {
2615→        char[64] dbuf;
2616→        char[] dslice = io::bprintf(&dbuf, "%.15g", a.double_val)!!;
2617→        return make_string(dslice);
2618→    }
2619→    if (a.tag != V_INT) return make_nil();
2620→    long n = a.int_val;
2621→
2622→    // Handle long.min specially to avoid -long.min overflow
2623→    if (n == long.min) {
2624→        char[] min_str = "-9223372036854775808";
2625→        return make_string(min_str);
2626→    }
2627→
2628→    char[32] buf;
2629→    usz pos = 0;
2630→    bool negative = n < 0;
2631→    if (negative) { n = -n; }
2632→
2633→    if (n == 0) {
2634→        buf[0] = '0';
2635→        pos = 1;
2636→    } else {
2637→        while (n > 0 && pos < 31) {
2638→            buf[pos++] = (char)('0' + (n % 10));
2639→            n /= 10;
2640→        }
2641→        // Reverse
2642→        for (usz i = 0; i < pos / 2; i++) {
2643→            char tmp = buf[i];
2644→            buf[i] = buf[pos - 1 - i];
2645→            buf[pos - 1 - i] = tmp;
2646→        }
2647→    }
2648→
2649→    if (negative) {
2650→        // Shift right and prepend '-'
2651→        for (isz i = (isz)pos; i > 0; i--) {
2652→            buf[(usz)i] = buf[(usz)i - 1];
2653→        }
2654→        buf[0] = '-';
2655→        pos++;
2656→    }
2657→
2658→    return make_string(buf[:pos]);
2659→}
