2661→/**
2662→ * (gensym) => unique symbol via interpreter delegation
2663→ */
2664→tlocal long g_gensym_counter = 0;
2665→
2666→fn Value rt_gensym(Value _a, Value _unused) {
2667→    long n = g_gensym_counter++;
2668→    char[32] buf;
2669→    // Format as "g#N"
2670→    buf[0] = 'g';
2671→    buf[1] = '#';
2672→    usz pos = 2;
2673→    if (n == 0) {
2674→        buf[pos++] = '0';
2675→    } else {
2676→        // Write digits reversed, then reverse
2677→        usz start = pos;
2678→        long tmp = n;
2679→        while (tmp > 0 && pos < 31) {
2680→            buf[pos++] = (char)('0' + (tmp % 10));
2681→            tmp /= 10;
2682→        }
2683→        for (usz i = 0; i < (pos - start) / 2; i++) {
2684→            char c = buf[start + i];
2685→            buf[start + i] = buf[pos - 1 - i];
2686→            buf[pos - 1 - i] = c;
2687→        }
2688→    }
2689→    return make_symbol(buf[:pos]);
2690→}
