2734→/**
2735→ * Create a dict from a cons list of interleaved key-value pairs.
2736→ * (dict k1 v1 k2 v2 ...) compiles to rt_dict_from_args(args_cons_list)
2737→ */
2738→fn Value rt_dict_from_args(Value arg_list) {
2739→    // Count args first
2740→    Value current = arg_list;
2741→    long count = 0;
2742→    while (current.tag == V_CONS) {
2743→        count++;
2744→        Value* cdr = main::dereference_as(Value, current.cons_val.cdr);
2745→        current = *cdr;
2746→    }
2747→
2748→    // Create hashmap with appropriate capacity (min 16, 2x pairs)
2749→    uint cap = 16;
2750→    if (count > 8) cap = (uint)count * 2;
2751→    Value d = make_dict(cap);
2752→
2753→    // Insert key-value pairs
2754→    current = arg_list;
2755→    while (current.tag == V_CONS) {
2756→        Value* car = main::dereference_as(Value, current.cons_val.car);
2757→        Value key = *car;
2758→        Value* cdr_ptr = main::dereference_as(Value, current.cons_val.cdr);
2759→        current = *cdr_ptr;
2760→        if (current.tag != V_CONS) break;
2761→        Value* val_car = main::dereference_as(Value, current.cons_val.car);
