3965→fn void Compiler.compile_path(Compiler* self, Expr* expr) {
3966→    if (expr.path.segment_count == 0) {
3967→        self.emit("runtime::make_nil()");
3968→        return;
3969→    }
3970→
3971→    // First segment is a variable, remaining segments are field lookups
3972→    for (usz i = 1; i < expr.path.segment_count; i++) {
3973→        self.emit("runtime::rt_field_access(");
