3975→
3976→    // Emit first segment as variable reference
3977→    self.emit_symbol_name(expr.path.segments[0]);
3978→
3979→    // Emit remaining segments as string field names (wrapped in make_string for Value type)
3980→    for (usz i = 1; i < expr.path.segment_count; i++) {
3981→        self.emit(", runtime::make_string(\"");
3982→        char[] name = self.interp.symbols.get_name(expr.path.segments[i]);
3983→        self.emit_escaped(name);
3984→        self.emit("\"))");
3985→    }
3986→}
