3992→/**
3993→ * compile_module_flat — Flat-style module compilation.
3994→ * Compiles module body expressions inline, registers module in table.
3995→ */
3996→fn usz Compiler.compile_module_flat(Compiler* self, Expr* expr) {
3997→    // Register the module in compiled_modules table
3998→    if (self.compiled_module_count >= self.compiled_module_capacity) {
3999→        usz new_cap = self.compiled_module_capacity * 2;
4000→        CompiledModule* new_mods = (CompiledModule*)mem::malloc(CompiledModule.sizeof * new_cap);
4001→        for (usz i = 0; i < self.compiled_module_count; i++) new_mods[i] = self.compiled_modules[i];
4002→        mem::free(self.compiled_modules);
4003→        self.compiled_modules = new_mods;
4004→        self.compiled_module_capacity = new_cap;
4005→    }
4006→    {
4007→        CompiledModule* mod = &self.compiled_modules[self.compiled_module_count];
4008→        mod.name = expr.module_expr.name;
4009→        usz cap = expr.module_expr.export_count < 16 ? 16 : expr.module_expr.export_count;
4010→        mod.exports = (SymbolId*)mem::malloc(SymbolId.sizeof * cap);
4011→        mod.export_capacity = cap;
4012→        mod.export_count = expr.module_expr.export_count;
4013→        for (usz i = 0; i < expr.module_expr.export_count; i++) {
4014→            mod.exports[i] = expr.module_expr.exports[i];
4015→        }
4016→        mod.loaded = true;
4017→        self.compiled_module_count++;
4018→    }
4019→
4020→    // Compile body expressions inline
4021→    usz last_id = 0;
4022→    for (usz i = 0; i < expr.module_expr.body_count; i++) {
4023→        Expr* body_expr = expr.module_expr.body[i];
4024→        if (body_expr.tag == E_DEFINE) {
4025→            // Define: compile init, assign to global
4026→            usz init_r = self.compile_to_temp(body_expr.define.value);
4027→            self.emit_indent();
4028→            self.emit_symbol_name(body_expr.define.name);
4029→            self.emit(" = ");
4030→            self.emit_temp_ref(init_r);
4031→            self.emit(";\n");
4032→            last_id = init_r;
4033→        } else {
4034→            // Non-define: compile inline
4035→            last_id = self.compile_to_temp(body_expr);
4036→        }
4037→    }
4038→
4039→    // Module evaluates to nil
4040→    usz id = self.next_result();
4041→    self.emit_temp_decl(id);
4042→    self.emit(" = runtime::make_nil();\n");
4043→    return id;
4044→}
