1958→    p.init(&lex, interp);
1959→
1960→    List{Expr*} exprs;
1961→    while (!lex.at_end() && !p.has_error) {
1962→        exprs.push(p.parse_expr());
1963→    }
1964→
1965→    if (p.has_error) {
1966→        exprs.free();
1967→        EvalResult r;
1968→        r.value = null;
1969→        r.error.has_error = true;
1970→        r.error.line = p.error_line;
1971→        r.error.column = p.error_col;
1972→        usz len = p.error_msg_len;
1973→        if (len > 255) len = 255;
1974→        for (usz i = 0; i < len; i++) {
1975→            r.error.message[i] = p.error_msg[i];
1976→        }
1977→        r.error.message[len] = 0;
1978→        return r;
1979→    }
1980→
1981→    EvalResult result = eval_ok(make_nil(interp));
1982→
1983→    foreach (expr : exprs) {
1984→        // GC JIT states between top-level expressions (safe: no JIT code on stack)
1985→        jit_gc();
1986→
1987→        // Expand macros before JIT compilation
1988→        expr = expand_macros_in_expr(expr, interp);
1989→        JitFn f = jit_compile(expr, interp);
1990→        if (f != null) {
1991→            Value* jit_result = jit_exec(f, interp);
1992→            if (jit_result != null && jit_result.tag == ERROR) {
1993→                result = eval_error_expr(jit_result.str_val.chars[:jit_result.str_val.len], expr);
1994→            } else {
1995→                result = eval_ok(jit_result);
1996→            }
1997→            if (result.error.has_error) break;
1998→            continue;
1999→        }
2000→        result = eval_error_expr("JIT compilation failed", expr);
2001→        break;
2002→    }
2003→
2004→    exprs.free();
2005→    return result;
2006→}
