2008→/**
2009→ * Run a single expression.
2010→ */
2011→fn EvalResult run(char[] source, Interp* interp) {
2012→    Lexer lex;
2013→    lex.init(source);
2014→    Parser p;
2015→    p.init(&lex, interp);
2016→
2017→    Expr* expr = p.parse_expr();
2018→
2019→    if (p.has_error) {
2020→        EvalResult r;
2021→        r.value = null;
2022→        r.error.has_error = true;
2023→        r.error.line = p.error_line;
2024→        r.error.column = p.error_col;
2025→        usz len = p.error_msg_len;
2026→        if (len > 255) len = 255;
2027→        for (usz i = 0; i < len; i++) {
2028→            r.error.message[i] = p.error_msg[i];
2029→        }
2030→        r.error.message[len] = 0;
2031→        return r;
2032→    }
2033→
2034→    // JIT path: compile + execute in child region + child scope
2035→    expr = expand_macros_in_expr(expr, interp);
2036→
2037→    // Push child scope — temporaries freed after eval
2038→    main::ScopeRegion* saved_scope = interp.current_scope;
2039→    main::ScopeRegion* child_scope = main::scope_create(saved_scope);
2040→    interp.current_scope = child_scope;
2041→
2042→    JitFn f = jit_compile(expr, interp);
2043→    EvalResult result;
2044→    if (f != null) {
2045→        Value* jit_result = jit_exec(f, interp);
2046→        if (jit_result != null && jit_result.tag == ERROR) {
2047→            result = eval_error_expr(jit_result.str_val.chars[:jit_result.str_val.len], expr);
2048→        } else {
2049→            if (jit_result != null) {
2050→                // Promote result to parent scope before releasing child
2051→                interp.current_scope = saved_scope;
2052→                jit_result = copy_to_parent(jit_result, interp);
2053→            }
2054→            result = eval_ok(jit_result);
2055→        }
2056→    } else {
2057→        result = eval_error_expr("JIT compilation failed", expr);
2058→    }
2059→
2060→    // Pop child scope — frees all temporaries from this eval
2061→    interp.current_scope = saved_scope;
2062→    main::scope_release(child_scope);
2063→
2064→    return result;
2065→}
