2116→// Check if a symbol name is a keyword (special form)
2117→fn bool is_keyword(char[] name) {
2118→    // Special forms
2119→    char[][] keywords = {
2120→        "lambda", "define", "let", "if", "begin", "set!", "quote",
2121→        "and", "or", "match", "reset", "shift", "signal", "handle",
2122→        "resolve", "module", "import", "export", "with-continuation"
2123→    };
2124→    foreach (kw : keywords) {
