2151→// Helper: classify a symbol name and apply color to the range [start, end) in colors array
2152→fn void flush_symbol(char* input, CInt* colors, isz start, CInt end_pos) {
2153→    if (start < 0 || start >= (isz)end_pos) return;
2154→    usz slen = (usz)end_pos - (usz)start;
