2156→    if (slen > 127) slen = 127;
2157→    for (usz k = 0; k < slen; k++) sbuf[k] = input[(usz)start + k];
2158→    char[] sym = sbuf[:slen];
2159→
2160→    CInt col = RXCOLOR_DEFAULT;
2161→    if (is_keyword(sym)) {
2162→        col = RXCOLOR_BRIGHTCYAN | RXCOLOR_BOLD;
2163→    } else if (is_builtin_const(sym)) {
2164→        col = RXCOLOR_BRIGHTMAGENTA;
2165→    }
2166→    for (isz j = start; j < (isz)end_pos; j++) {
2167→        colors[(CInt)j] = col;
2168→    }
2169→}
