2171→// Syntax highlighter callback for replxx — colors individual code points
2172→fn void lisp_highlighter(char* input, CInt* colors, CInt size, void* ud) {
2173→    if (input == null || size <= 0) return;
2174→
2175→    bool in_string = false;
2176→    bool in_comment = false;
2177→    bool escape_next = false;
2178→    int paren_depth = 0;
2179→    CInt[6] paren_colors = { RXCOLOR_BRIGHTCYAN, RXCOLOR_BRIGHTMAGENTA, RXCOLOR_YELLOW, RXCOLOR_BRIGHTGREEN, RXCOLOR_BRIGHTBLUE, RXCOLOR_BRIGHTRED };
2180→    isz sym_start = -1;
2181→
2182→    for (CInt i = 0; i < size; i++) {
2183→        char c = input[i];
2184→
2185→        if (in_comment) {
2186→            colors[i] = RXCOLOR_GRAY;
2187→            if (c == '\n') { in_comment = false; }
2188→            continue;
2189→        }
2190→
2191→        if (in_string) {
2192→            colors[i] = RXCOLOR_GREEN;
2193→            if (escape_next) { escape_next = false; continue; }
2194→            if (c == '\\') { escape_next = true; continue; }
2195→            if (c == '"') { in_string = false; }
2196→            continue;
2197→        }
2198→
2199→        // Normal mode
2200→        if (c == ';') {
2201→            flush_symbol(input, colors, sym_start, i); sym_start = -1;
2202→            in_comment = true;
2203→            colors[i] = RXCOLOR_GRAY;
2204→        } else if (c == '"') {
2205→            flush_symbol(input, colors, sym_start, i); sym_start = -1;
2206→            in_string = true;
2207→            colors[i] = RXCOLOR_GREEN;
2208→        } else if (c == '(' || c == ')') {
2209→            flush_symbol(input, colors, sym_start, i); sym_start = -1;
2210→            if (c == '(') {
2211→                colors[i] = paren_colors[paren_depth % 6];
2212→                paren_depth++;
2213→            } else {
2214→                paren_depth--;
2215→                if (paren_depth < 0) { paren_depth = 0; }
2216→                colors[i] = paren_colors[paren_depth % 6];
2217→            }
2218→        } else if (c == '[' || c == ']') {
2219→            flush_symbol(input, colors, sym_start, i); sym_start = -1;
2220→            colors[i] = RXCOLOR_YELLOW;
2221→        } else if (c == '{' || c == '}') {
2222→            flush_symbol(input, colors, sym_start, i); sym_start = -1;
2223→            colors[i] = RXCOLOR_BROWN;
2224→        } else if (c == '\'' && (i == 0 || input[i-1] == '(' || input[i-1] == ' ' || input[i-1] == '\t')) {
2225→            colors[i] = RXCOLOR_CYAN;
2226→        } else if (c >= '0' && c <= '9' && sym_start < 0) {
2227→            colors[i] = RXCOLOR_BRIGHTMAGENTA;
2228→        } else if (c == ' ' || c == '\t' || c == '\n' || c == '\r') {
2229→            flush_symbol(input, colors, sym_start, i); sym_start = -1;
2230→        } else {
2231→            if (sym_start < 0) { sym_start = (isz)i; }
2232→        }
2233→    }
2234→
2235→    // Flush trailing symbol
2236→    flush_symbol(input, colors, sym_start, size);
2237→}
