115→fn usz format_arity_error(char[] buf, usz expected, usz got) {
116→    char[] prefix = "arity mismatch: expected ";
117→    usz pos = 0;
118→    for (usz i = 0; i < prefix.len && pos < buf.len - 1; i++) buf[pos++] = prefix[i];
119→    // Write expected count
120→    char[20] num_buf;
121→    char[] num_str = int_to_string((long)expected, &num_buf);
122→    for (usz i = 0; i < num_str.len && pos < buf.len - 1; i++) buf[pos++] = num_str[i];
123→    char[] mid = " argument(s), got ";
124→    for (usz i = 0; i < mid.len && pos < buf.len - 1; i++) buf[pos++] = mid[i];
125→    num_str = int_to_string((long)got, &num_buf);
126→    for (usz i = 0; i < num_str.len && pos < buf.len - 1; i++) buf[pos++] = num_str[i];
127→    buf[pos] = 0;
128→    return pos;
129→}
