131→fn Value* jit_apply_value_impl(Value* func, Value* arg, Interp* interp) {
132→    if (func == null) {
133→        if ((uint)interp.last_call_name != 0) {
134→            char[256] ebuf;
135→            char[] msg = io::bprintf(&ebuf, "'%s' is not defined\n  hint: did you (load ...) or (import ...) it?",
136→                (ZString)interp.symbols.get_name(interp.last_call_name))!!;
137→            return raise_error(interp, msg);
138→        }
139→        return raise_error(interp, "called value is nil — not a function");
140→    }
141→
142→    // Propagate errors from function evaluation (e.g. unbound variable)
143→    if (func.tag == ERROR) return func;
144→
145→    switch (func.tag) {
146→        case CLOSURE: {
147→            if (!func.closure_val.has_param && !func.closure_val.has_rest) {
148→                return jit_eval_in_call_scope(func.closure_val.body, func.closure_val.env, interp);
149→            }
150→            if (func.closure_val.has_rest) {
151→                usz pc = func.closure_val.param_count;
152→                if (pc == 0) {
153→                    Env* new_env = func.closure_val.env;
154→                    Value* rest_list = make_cons(interp, arg, make_nil(interp));
155→                    new_env = new_env.extend(interp, func.closure_val.rest_param, rest_list);
156→                    return jit_eval_in_call_scope(func.closure_val.body, new_env, interp);
157→                } else if (pc == 1) {
158→                    Env* new_env = func.closure_val.env;
159→                    new_env = new_env.extend(interp, func.closure_val.params[0], arg);
160→                    new_env = new_env.extend(interp, func.closure_val.rest_param, make_nil(interp));
161→                    return jit_eval_in_call_scope(func.closure_val.body, new_env, interp);
162→                } else {
163→                    return raise_error(interp, "too few arguments for variadic lambda");
164→                }
165→            }
166→            // Arity check: non-variadic multi-param closure called with 1 arg
167→            if (func.closure_val.param_count > 1) {
168→                char[128] buf;
169→                usz len = format_arity_error(&buf, func.closure_val.param_count, 1);
170→                return raise_error(interp, buf[:len]);
171→            }
172→            Env* new_env = func.closure_val.env.extend(interp, func.closure_val.param, arg);
173→            return jit_eval_in_call_scope(func.closure_val.body, new_env, interp);
174→        }
175→
176→        case PRIMITIVE: {
177→            // Set constructor type_id (needed for type constructor primitives)
178→            interp.constructor_type_id = func.prim_val.tag;
179→            EvalResult r = apply_primitive(func, arg, interp);
180→            if (r.error.has_error) return make_error(interp, r.error.message[:256]);
181→            return r.value;
182→        }
183→
184→        case PARTIAL_PRIM: {
185→            EvalResult r = apply_partial(func, arg, interp);
186→            if (r.error.has_error) return make_error(interp, r.error.message[:256]);
187→            return r.value;
188→        }
189→
190→        case CONTINUATION: {
191→            EvalResult r = jit_apply_continuation(func, arg, interp);
192→            if (r.error.has_error) return make_error(interp, r.error.message[:256]);
193→            return r.value;
194→        }
195→
196→        case METHOD_TABLE: {
197→            Value*[1] args = { arg };
198→            MethodTable* mt = func.method_table_val;
199→            Value* resolved = find_best_method(mt, args[:1], interp);
200→            if (resolved != null && resolved.tag == ERROR) return resolved;
201→            if (resolved == null && mt.fallback != null) {
202→                resolved = mt.fallback;
203→            }
204→            if (resolved == null) {
205→                return format_dispatch_error(mt, args[:1], interp);
206→            }
207→            return jit_apply_value(resolved, arg, interp);
208→        }
209→
210→        default:
211→            char[256] ebuf2;
212→            char[] type_name = interp.symbols.get_name(value_type_name(func, interp));
213→            if ((uint)interp.last_call_name != 0) {
214→                char[] msg2 = io::bprintf(&ebuf2, "'%s' is %s, not a function",
215→                    (ZString)interp.symbols.get_name(interp.last_call_name),
216→                    (ZString)type_name)!!;
217→                return raise_error(interp, msg2);
218→            }
219→            char[] msg2 = io::bprintf(&ebuf2, "called value is %s, not a function",
220→                (ZString)type_name)!!;
221→            return raise_error(interp, msg2);
222→    }
223→}
