225→<* @require func != null : "jit_apply_value called with null func" *>
226→fn Value* jit_apply_value(Value* func, Value* arg, Interp* interp) {
227→    interp.eval_depth++;
228→    if (interp.eval_depth > interp.max_eval_depth) {
229→        $if DEBUG_BUILD:
230→            io::eprintfn("[debug] Stack overflow at depth %d (max %d)", interp.eval_depth, interp.max_eval_depth);
231→        $endif
232→        interp.eval_depth--;
233→        return make_error(interp, "stack overflow: maximum eval depth exceeded");
234→    }
235→    Value* result = jit_apply_value_impl(func, arg, interp);
236→    interp.eval_depth--;
237→    return result;
238→}
