240→// Tail-call variant: sets TCO bounce fields for CLOSURE instead of recursing.
241→// ONLY called when the result goes directly to R0 as the function return value.
242→fn Value* jit_apply_value_tail(Value* func, Value* arg, Interp* interp) {
243→    if (func == null) {
244→        if ((uint)interp.last_call_name != 0) {
245→            char[256] ebuf;
246→            char[] msg = io::bprintf(&ebuf, "'%s' is not defined\n  hint: did you (load ...) or (import ...) it?",
247→                (ZString)interp.symbols.get_name(interp.last_call_name))!!;
248→            return raise_error(interp, msg);
249→        }
250→        return raise_error(interp, "called value is nil — not a function");
251→    }
252→
253→    // Propagate errors from function evaluation (e.g. unbound variable)
254→    if (func.tag == ERROR) return func;
255→
256→    if (func.tag == CLOSURE) {
257→        Env* new_env;
258→        if (!func.closure_val.has_param && !func.closure_val.has_rest) {
259→            new_env = func.closure_val.env;
260→        } else if (func.closure_val.has_rest) {
261→            usz pc = func.closure_val.param_count;
262→            if (pc == 0) {
263→                new_env = func.closure_val.env;
264→                Value* rest_list = make_cons(interp, arg, make_nil(interp));
265→                new_env = new_env.extend(interp, func.closure_val.rest_param, rest_list);
266→            } else if (pc == 1) {
267→                new_env = func.closure_val.env;
268→                new_env = new_env.extend(interp, func.closure_val.params[0], arg);
269→                new_env = new_env.extend(interp, func.closure_val.rest_param, make_nil(interp));
270→            } else {
271→                return raise_error(interp, "too few arguments for variadic lambda");
272→            }
273→        } else if (func.closure_val.param_count > 1) {
274→            // Arity check: non-variadic multi-param closure called with 1 arg
275→            char[128] buf;
276→            usz len = format_arity_error(&buf, func.closure_val.param_count, 1);
277→            return raise_error(interp, buf[:len]);
278→        } else {
279→            new_env = func.closure_val.env.extend(interp, func.closure_val.param, arg);
280→        }
281→        interp.jit_tco_expr = func.closure_val.body;
282→        interp.jit_tco_env = new_env;
283→        interp.flags.jit_tco_bounce = true;
284→        return jit_tco_sentinel();
285→    }
286→
287→    // Non-closure: normal apply (no TCO needed for primitives/continuations)
288→    return jit_apply_value(func, arg, interp);
289→}
