295→// JIT-aware eval replacement with trampoline TCO.
296→// Compiles sub-expressions with cache, executes with env context.
297→// When a tail-call helper sets jit_tco_bounce, loops instead of recursing.
298→<* @require interp != null : "jit_eval: null interp" *>
299→fn Value* jit_eval(Expr* expr, Env* env, Interp* interp) {
300→    Env* saved_env = interp.jit_env;

299→fn Value* jit_eval(Expr* expr, Env* env, Interp* interp) {
300→    Env* saved_env = interp.jit_env;
301→
302→    for (;;) {
303→        if (expr == null) {
304→            interp.jit_env = saved_env;
305→            return make_nil(interp);
306→        }
307→
308→        // 1. Check cache
309→        JitFn cached = jit_cache_lookup(expr);
310→        if (cached == null) {
311→            // 2. Compile
312→            cached = jit_compile(expr, interp);
313→            if (cached == null) {
314→                // JIT can't compile this expression
315→                interp.jit_env = saved_env;
316→                return raise_error(interp, "JIT compilation failed");
317→            }
318→            jit_cache_store(expr, cached);
319→        }
320→
321→        // 3. Execute with env context
322→        interp.jit_env = env;
323→        interp.flags.jit_tco_bounce = false;
324→        Value* result = cached(interp);
325→
326→        // 4. Check for TCO bounce
327→        if (interp.flags.jit_tco_bounce) {
328→            // Tail call — loop with new expr/env instead of recursing
329→            expr = interp.jit_tco_expr;
330→            env = interp.jit_tco_env;
331→            interp.flags.jit_tco_bounce = false;
332→
333→            // TCO scope recycling: only when current_scope is the scope created by
334→            // jit_eval_in_call_scope (not a scope from handle clause or other context).
335→            // Guards: scope is marked recyclable, nothing escaped (RC=1).
336→            // Phase 4b: copy_tco_env_chain copies the FULL chain to global_env so the
337→            // fresh scope is independent of any env_scope freed during scope_release.
338→            main::ScopeRegion* cs = interp.current_scope;
339→            if (cs == interp.tco_recycle_scope && cs.refcount == 1) {
340→                main::ScopeRegion* fresh = main::scope_create(cs.parent);
341→                interp.current_scope = fresh;
342→                interp.tco_recycle_scope = fresh;  // Update: fresh is now the recyclable scope
343→                env = copy_tco_env_chain(env, interp);
344→                main::scope_release(cs);
345→            }
346→
347→            continue;
348→        }
349→
350→        interp.jit_env = saved_env;
351→        return result;
352→    }
353→}
