388→/// Copy env frames from `src` up to (but not including) `stop_at` into current_scope.
389→/// Copy env frames from `src` up to (but not including) `global_env` into current_scope.
390→/// Used at TCO bounce to preserve the next iteration's env while releasing old scope.
391→/// Phase 4b: copies the FULL chain (including env_scope frames from closures) so the
392→/// fresh scope is independent of any env_scope that might be freed during scope_release.
393→fn Env* copy_tco_env_chain(Env* src, Interp* interp) {
394→    if (src == null || src == interp.global_env) return src;
395→
396→    // Persistent env nodes (mutable boxes in root_region) are kept as-is.
397→    // Their parent chain still needs fixing up since it may point to env_scope frames.
398→    if (src.persistent) {
399→        src.parent = copy_tco_env_chain(src.parent, interp);
400→        return src;
401→    }
402→
403→    // Recursive: copy parent chain first (bottom-up)
404→    Env* parent_copy = copy_tco_env_chain(src.parent, interp);
405→
406→    // Create new env frame in current_scope (already switched to fresh scope)
407→    Env* dst = make_env(interp, parent_copy);
408→    for (usz i = 0; i < src.binding_count; i++) {
409→        Value* v = copy_to_parent(src.bindings[i].value, interp);
410→        dst.define(src.bindings[i].name, v);
411→    }
412→    // Rebuild hash table if source had one
413→    if (src.hash_table != null) {
414→        dst.build_hash_table();
415→    }
416→    return dst;
417→}
