482→// Lambda/closure creation helper — called from JIT-compiled code.
483→// Mirrors eval_lambda from eval.c3: creates a closure value from an E_LAMBDA Expr*.
484→// Phase 4b: Closures allocated in current_scope (not root_scope). Env copied to a
485→// standalone env_scope (refcounted). Temporary closures freed when scope releases.
486→fn Value* jit_make_closure_from_expr(Interp* interp, Expr* expr, Env* env) {
487→    main::ScopeRegion* creation_scope = interp.current_scope;
488→    bool need_env_copy = (creation_scope != interp.root_scope);
489→
490→    // Check for zero-arg lambda (sentinel param)
491→    if ((uint)expr.lambda.param == 0xFFFFFFFF && !expr.lambda.has_rest) {
492→        Value* closure = make_closure_no_param(interp, expr.lambda.body, env);
493→        if (need_env_copy) {
494→            main::ScopeRegion* env_scope = main::scope_create(null);
495→            interp.current_scope = env_scope;
496→            closure.closure_val.env = copy_env_to_scope(env, interp);
497→            closure.closure_val.env_scope = env_scope;
498→            interp.current_scope = creation_scope;
499→        }
500→        return closure;
501→    }
502→
503→    // Create closure in current_scope
504→    Value* closure = make_closure(interp, expr.lambda.param, expr.lambda.body, env);
505→
506→    // Copy variadic info from ExprLambda to Closure
507→    closure.closure_val.param_count = expr.lambda.param_count;
508→    if (expr.lambda.param_count > 0) {
509→        mem::free(closure.closure_val.params);
510→        closure.closure_val.params = (SymbolId*)mem::malloc(SymbolId.sizeof * expr.lambda.param_count);
511→        for (usz i = 0; i < expr.lambda.param_count; i++) {
512→            closure.closure_val.params[i] = expr.lambda.params[i];
513→        }
514→    }
515→    closure.closure_val.has_rest = expr.lambda.has_rest;
516→    closure.closure_val.rest_param = expr.lambda.rest_param;
517→
518→    // For variadic with zero fixed params: (lambda (.. args) body)
519→    if (expr.lambda.has_rest && expr.lambda.param_count == 0) {
520→        closure.closure_val.has_param = false;
521→        closure.closure_val.param = 0;
522→    }
523→
524→    // Build type signature if lambda has typed params
525→    closure.closure_val.has_typed_params = expr.lambda.has_typed_params;
526→    closure.closure_val.type_sig = null;
527→    if (expr.lambda.has_typed_params) {
528→        MethodSignature* sig = (MethodSignature*)mem::malloc(MethodSignature.sizeof);
529→        sig.param_count = expr.lambda.param_count;
530→        sig.constraint_count = 0;
531→        usz ann_count = expr.lambda.param_count;
532→        if (ann_count > 8) ann_count = 8;
533→        for (usz i = 0; i < ann_count; i++) {
534→            TypeAnnotation* ann = &expr.lambda.param_annotations[i];
535→            if (ann.has_annotation) {
536→                if (ann.has_val_literal) {
537→                    sig.param_types[i] = INVALID_TYPE_ID;
538→                    sig.val_literals[i] = ann.val_literal;
539→                    sig.has_val_literal[i] = true;
540→                } else if (ann.is_dict) {
541→                    sig.param_types[i] = INVALID_TYPE_ID;
542→                    sig.has_val_literal[i] = false;
543→                    for (usz m = 0; m < ann.meta_count && sig.constraint_count < MAX_TYPE_PARAMS; m++) {
544→                        if (!ann.meta[m].is_int) {
545→                            sig.constraints[sig.constraint_count].param_sym = ann.meta[m].key;
546→                            sig.constraints[sig.constraint_count].bound_type =
547→                                interp.types.lookup(ann.meta[m].sym_value, &interp.symbols);
548→                            sig.constraint_count++;
549→                        }
550→                    }
551→                } else {
552→                    sig.param_types[i] = interp.types.lookup(ann.base_type, &interp.symbols);
553→                    sig.has_val_literal[i] = false;
554→                }
555→            } else {
556→                sig.param_types[i] = INVALID_TYPE_ID;
557→                sig.has_val_literal[i] = false;
558→            }
559→        }
560→        closure.closure_val.type_sig = sig;
561→    }
562→
