2843→fn bool jit_compile_lit(void* s, Expr* expr, Interp* interp) {
2844→    Value* lit = expr.lit.value;
2845→    if (lit == null || lit.tag == NIL) {
2846→        emit_call_1(s, (void*)&jit_make_nil);
2847→        return true;
2848→    }
2849→    if (lit.tag == INT) {
2850→        emit_call_2i(s, (void*)&jit_make_int, JIT_V0, lit.int_val);
2851→        return true;
2852→    }
2853→    // For other literal types, use the literal value directly
2854→    // (it's a pointer to a pre-existing Value in the expr pool)
2855→    _jit_new_node_ww(s, CODE_MOVI, JIT_R0, (long)lit);
2856→    return true;
2857→}
2858→
2859→fn bool jit_compile_var(void* s, Expr* expr, Interp* interp, JitLocals* locals) {
2860→    uint sym_id = (uint)expr.var_expr.name;
2861→
2862→    // Check JIT locals first (reverse order for proper scoping of shadowed names)
2863→    for (usz i = locals.locals.len(); i > 0; i--) {
2864→        if ((uint)locals.locals[i - 1].name == sym_id) {
2865→            if (locals.locals[i - 1].is_mutable) {
2866→                // Mutable local: stack slot holds Env* (the box). Lookup value in it.
2867→                _jit_new_node_www(s, CODE_LDXI_L, (long)JIT_V1, (long)JIT_FP, (long)locals.locals[i - 1].stack_offset);
2868→                emit_call_2i(s, (void*)&jit_env_lookup_local, JIT_V1, (long)sym_id);
2869→                return true;
2870→            }
2871→            // Non-mutable: load value directly from stack slot
2872→            _jit_new_node_www(s, CODE_LDXI_L, (long)JIT_R0, (long)JIT_FP, (long)locals.locals[i - 1].stack_offset);
2873→            return true;
2874→        }
2875→    }
2876→
2877→    // Fall back to jit_lookup_var: checks jit_env (for sub-expression local bindings), then global
2878→    emit_call_2i(s, (void*)&jit_lookup_var, JIT_V0, (long)sym_id);
2879→    return true;
2880→}
