2882→fn bool jit_compile_if(void* s, Expr* expr, Interp* interp, JitLocals* locals, bool is_tail) {
2883→    // Compile test expression -> R0 (test is never in tail position)
2884→    if (!jit_compile_expr(s, expr.if_expr.test, interp, locals)) return false;
2885→
2886→    // Save test result to V1, call is_falsy(V1, interp)
2887→    _jit_new_node_ww(s, CODE_MOVR, JIT_V1, JIT_R0);  // V1 = test result
2888→    emit_call_2(s, (void*)&jit_is_falsy, JIT_V1, JIT_V0);
2889→
2890→    // If is_falsy returned true (non-zero), jump to else branch
2891→    void* jump_else = _jit_new_node_pww(s, CODE_BNEI, null, (long)JIT_R0, 0);
2892→
2893→    // Then branch — inherits tail position
2894→    if (!jit_compile_expr(s, expr.if_expr.then_branch, interp, locals, is_tail)) return false;
2895→    void* jump_end = _jit_new_node_p(s, CODE_JMPI, null);
2896→
2897→    // Else branch — inherits tail position
2898→    _jit_patch(s, jump_else);
2899→    if (!jit_compile_expr(s, expr.if_expr.else_branch, interp, locals, is_tail)) return false;
2900→
2901→    // End
2902→    _jit_patch(s, jump_end);
2903→    return true;
2904→}
