1075→    main::StackCtx* ctx = main::stack_ctx_create(&interp.stack_ctx_pool);
1076→    if (ctx == null) return eval_error("stack engine: failed to create context for reset");
1077→
1078→    ResetState state;
1079→    state.body = expr.reset.body;
1080→    state.env = env;
1081→    state.interp = interp;
1082→    state.shifted = false;
1083→    state.shift_body = null;
1084→    state.shift_env = null;
1085→
1086→    main::stack_ctx_init(ctx, &reset_entry, &state);
1087→
1088→    // Save/restore the reset state pointer for nesting
1089→    void* saved_state = interp.current_reset_state;
1090→    interp.current_reset_state = &state;
1091→
1092→    // Save interp state before entering context. The context shares the same Interp
1093→    // and its jit_eval calls modify these fields (eval_depth, jit_env, etc.).
1094→    // When the context suspends (shift) or completes, these are left in the context's
1095→    // state. We must restore the parent's values.
1096→    Env*        saved_jit_env       = interp.jit_env;
1097→    Env*        saved_match_env     = interp.match_env;
1098→    usz         saved_eval_depth    = interp.eval_depth;
1099→    InterpFlags saved_flags         = interp.flags;
1100→    Expr*       saved_tco_expr      = interp.jit_tco_expr;
1101→    Env*        saved_tco_env       = interp.jit_tco_env;
1102→    main::ScopeRegion* saved_tco_recycle = interp.tco_recycle_scope;
1103→    usz         saved_reset_depth   = interp.reset_depth;
1104→    usz         saved_handler_count = interp.handler_count;
1105→    main::ScopeRegion* saved_scope = interp.current_scope;
1106→
1107→    // Run the body context
1108→    main::StackContext parent_ctx;
1109→    main::stack_ctx_switch_to(ctx, &parent_ctx);
1110→
1111→    // Restore interp state after context suspends/completes
1112→    interp.current_reset_state = saved_state;
1113→    interp.jit_env        = saved_jit_env;
1114→    interp.match_env      = saved_match_env;
1115→    interp.eval_depth     = saved_eval_depth;
1116→    interp.flags          = saved_flags;
1117→    interp.jit_tco_expr   = saved_tco_expr;
1118→    interp.jit_tco_env    = saved_tco_env;
1119→    interp.tco_recycle_scope = saved_tco_recycle;
1120→    interp.reset_depth    = saved_reset_depth;
1121→    interp.handler_count  = saved_handler_count;
1122→    interp.current_scope  = saved_scope;
1123→
1124→    // Stack overflow — context hit guard page
1125→    if (ctx.status == main::StackCtxStatus.CTX_DEAD) {
1126→        main::stack_ctx_destroy(ctx, &interp.stack_ctx_pool);
1127→        return eval_error("stack overflow in reset body");
1128→    }
1129→
1130→    if (state.shifted) {
1131→        // Shift occurred — evaluate shift body in parent context
1132→        Value* shift_result = jit_eval(state.shift_body, state.shift_env, interp);
1133→        if (shift_result != null && shift_result.tag == ERROR) {
1134→            return eval_error(shift_result.str_val.chars[:shift_result.str_val.len]);
1135→        }
1136→        return eval_ok(shift_result);
1137→    }
1138→
1139→    // Normal completion (no shift)
1140→    Value* v = (Value*)ctx.result;
1141→    main::stack_ctx_destroy(ctx, &interp.stack_ctx_pool);
1142→    if (v != null && v.tag == ERROR) {
1143→        return eval_error(v.str_val.chars[:v.str_val.len]);
1144→    }
1145→    return eval_ok(v);
1146→}
