1158→    // EvalResult is >16 bytes, triggering the System V ABI hidden return pointer.
1159→    // After stack_ctx_clone that pointer is stale, causing writes to the wrong stack.
1160→    main::StackCtx* current = main::g_current_stack_ctx;
1161→    if (current == null) {
1162→        return make_error(interp, "shift outside of reset");
1163→    }
1164→
1165→    ResetState* rstate = (ResetState*)interp.current_reset_state;
1166→    if (rstate == null) {
1167→        return make_error(interp, "shift outside of reset (no reset state)");
1168→    }
1169→
1170→    // Create continuation wrapping the current context
1171→    Continuation* k = interp.alloc_lisp_continuation();
1172→    k.ctx = current;
1173→    k.is_coroutine_based = true;

